-- Poems batch 253
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d5a4e951-1848-4e5c-9a2d-0429adc7fa39','題蕭照山水  其二','舒岳祥','宋','宋诗','song-poetry','','[]','林窮磵絕石崖傾，臨水幽朋更欲登。',32,'全唐诗/poet.song.228000.json','["林窮磵絕石崖傾，臨水幽朋更欲登。", "擬共前峯成小隠，曉來雲盡見高棱。"]'),
('c30e2c49-46cc-48b5-88b8-6d57281fd1fc','題蕭照山水  其三','舒岳祥','宋','宋诗','song-poetry','','[]','何人一舸下清溪，列壑攢峯想舊棲。',32,'全唐诗/poet.song.228000.json','["何人一舸下清溪，列壑攢峯想舊棲。", "不雨石林元自濕，無雲山路只長迷。"]'),
('f087945b-e56b-4f53-a6cd-a4ce38f09684','題蕭照山水  其四','舒岳祥','宋','宋诗','song-poetry','','[]','翩翩凉樹小茅堂，揖客柴門去棧長。',32,'全唐诗/poet.song.228000.json','["翩翩凉樹小茅堂，揖客柴門去棧長。", "山外橫舟篷不啟，誰知世有送迎忙。"]'),
('369cf5ba-3824-4fcb-9637-0aee941c4ee7','次韻答戴帥初送麴二絕  其一','舒岳祥','宋','宋诗','song-poetry','','[]','亂離無酒何以活，最愛涓涓淺酌時。',32,'全唐诗/poet.song.228000.json','["亂離無酒何以活，最愛涓涓淺酌時。", "理到何須辨清濁，興來誰解問醇醨。"]'),
('94435bf6-dd9a-4de3-8f2c-f7a9756b3f12','次韻答戴帥初送麴二絕  其二','舒岳祥','宋','宋诗','song-poetry','','[]','子雲嗜飲苦不給，時有問字人能來。',32,'全唐诗/poet.song.228000.json','["子雲嗜飲苦不給，時有問字人能來。", "使我得裂醉鄉土，爲爾特築黄金臺。"]'),
('38ea37c3-eae0-462b-b730-fa8ea0264549','桐','舒岳祥','宋','宋诗','song-poetry','','[]','嶧陽渾璞凱風心，此是姚虞膝上琴。',32,'全唐诗/poet.song.228000.json','["嶧陽渾璞凱風心，此是姚虞膝上琴。", "我有全琴元不斲，時携枕簟卧清陰。"]'),
('447fa665-b2bd-403a-b43f-e02952bd15c8','山扉','舒岳祥','宋','宋诗','song-poetry','','[]','未要携家入遠山，閉門謝俗自安閒。',32,'全唐诗/poet.song.228000.json','["未要携家入遠山，閉門謝俗自安閒。", "簷低還許歸雲度，牆短仍將疊嶂環。"]'),
('1b1be6df-6479-4c66-8069-a1104ac9820f','楊柳筏','舒岳祥','宋','宋诗','song-poetry','','[]','作此橫舟古柳間，八風不動只如山。',32,'全唐诗/poet.song.228000.json','["作此橫舟古柳間，八風不動只如山。", "夜來雨漲牂牁沒，却道舟移過別灣。"]'),
('233326e1-3a8e-4c6c-bddf-0ed55e08bdc5','十一夜月色凄淡數酌竟醉華胥國似可避世也','舒岳祥','宋','宋诗','song-poetry','','[]','冬暖熙熙作午晴，紅梅花下一壺傾。',32,'全唐诗/poet.song.228000.json','["冬暖熙熙作午晴，紅梅花下一壺傾。", "衰年未夜先思睡，深閉柴門却月明。"]'),
('6e56990d-8569-4c98-aa0f-9d1cdcb8cf8e','平泉佳景  其一','舒岳祥','宋','宋诗','song-poetry','','[]','清風截斷排簷雨，返景燒成冠嶺霞。',32,'全唐诗/poet.song.228000.json','["清風截斷排簷雨，返景燒成冠嶺霞。", "定是來朝好春色，海棠須作小桃花。"]'),
('7df2e277-11ed-40e0-bcd2-746b2c081660','平泉佳景  其二','舒岳祥','宋','宋诗','song-poetry','','[]','山狖暗穿黄葉響，沙烏遠叫白烟昏。',32,'全唐诗/poet.song.228000.json','["山狖暗穿黄葉響，沙烏遠叫白烟昏。", "採蘭童子歸來晚，一道香風先到門。"]'),
('3c2ace8c-4f94-4e6e-9ed5-b8863f40f03e','九月二十七日曉起書夢','舒岳祥','宋','宋诗','song-poetry','','[]','老去無營百念寬，只餘故紙未忘鑽。',32,'全唐诗/poet.song.228000.json','["老去無營百念寬，只餘故紙未忘鑽。", "小窗坐寐含幽夢，夢涉寒波賦楚蘭。"]'),
('86a9f991-7c9b-417b-bc74-a06ab8b1c854','紀夢','舒岳祥','宋','宋诗','song-poetry','','[]','款段徐行穩不危，迢迢溪路見疎梅。',32,'全唐诗/poet.song.228000.json','["款段徐行穩不危，迢迢溪路見疎梅。", "青枝欲挽憐香雪，喚取芳尊樹下來。"]'),
('23e8ab5b-2b19-40ee-af00-3c53b7edfb7c','夢歸','舒岳祥','宋','宋诗','song-poetry','','[]','獨行東阪茅茨屋，回望西牆竹樹坡。',32,'全唐诗/poet.song.228000.json','["獨行東阪茅茨屋，回望西牆竹樹坡。", "愁殺曛黄歸路遠，兵殘人少髑髏多。"]'),
('d6f76539-555f-4b45-9266-dde4646a6870','夢中作','舒岳祥','宋','宋诗','song-poetry','','[]','桃李成蹊春不言，有人扶瘦倚欄干。',32,'全唐诗/poet.song.228000.json','["桃李成蹊春不言，有人扶瘦倚欄干。", "柔柔軟軟愁如困，燕子初歸带薄寒。"]'),
('fbf901af-8e47-42d9-a06e-9ab1ec1a9182','夢成','舒岳祥','宋','宋诗','song-poetry','','[]','山棠紅白間青林，上有和鳴百囀禽。',32,'全唐诗/poet.song.228000.json','["山棠紅白間青林，上有和鳴百囀禽。", "一陣晚風吹曀去，又尋桃杏說春心。"]'),
('02840a2d-678d-43ba-a6c6-5e2ae0d90c86','二十五日晚西窗坐睡夢美人出紈扇索題爲題一絕既覺則童子已明燭矣忘其上三句足成此篇','舒岳祥','宋','宋诗','song-poetry','','[]','皎皎瓊華了不疑，綠窗團扇索題詩。',32,'全唐诗/poet.song.228000.json','["皎皎瓊華了不疑，綠窗團扇索題詩。", "風流自是天生句，燕子梨花恰並時。"]'),
('3b4eef4d-65e3-4a91-bc43-141d50f0df5b','紀夢','舒岳祥','宋','宋诗','song-poetry','','[]','纚纚桃花萬樹紅，徑回無復辨西東。',32,'全唐诗/poet.song.228000.json','["纚纚桃花萬樹紅，徑回無復辨西東。", "人間何處春風好，若欲逃秦入夢中。"]'),
('437590d2-cceb-4f32-9f35-cbe756c1e682','伯夷','舒岳祥','宋','宋诗','song-poetry','','[]','四海歸周莫不臣，首陽山下餓夫身。',32,'全唐诗/poet.song.228000.json','["四海歸周莫不臣，首陽山下餓夫身。", "清風萬古何曾死，愧死當時食粟人。"]'),
('a75f2153-9f94-4bac-9b63-922659df2fa8','春晚還致庵','舒岳祥','宋','宋诗','song-poetry','','[]','亂後還山喜復哀，舊書亡失等秦灰。',32,'全唐诗/poet.song.228000.json','["亂後還山喜復哀，舊書亡失等秦灰。", "翛然山徑花吹盡，蠶豆青梅薦一杯。"]'),
('d21de61e-2fe8-46d2-9731-4fd2008c4b32','蕉逕小立','舒岳祥','宋','宋诗','song-poetry','','[]','晝夜中分凉燠平，裁新熨故體輕清。',32,'全唐诗/poet.song.228000.json','["晝夜中分凉燠平，裁新熨故體輕清。", "無端撓亂成多事，剛種芭蕉作雨聲。"]'),
('3dfaad2c-601f-480d-8d7c-7cf7f7a5e4a3','二月初三日曝睡','舒岳祥','宋','宋诗','song-poetry','','[]','山茶花白野棠紅，誶語紛紛雀閙叢。',32,'全唐诗/poet.song.228000.json','["山茶花白野棠紅，誶語紛紛雀閙叢。", "眼暗耳聾牆角睡，真成老退一田翁。"]'),
('720b77a6-b84b-42e1-a510-0970740dfa30','去春達善分碧桃移植篆畦今春已作蕊達善前有見過之約偶立花下口占寄之  其一','舒岳祥','宋','宋诗','song-poetry','','[]','春衫露染玉肌寒，來自于闐植小園。',32,'全唐诗/poet.song.228000.json','["春衫露染玉肌寒，來自于闐植小園。", "欲寄平安無好句，不如來此共憑欄。"]'),
('b03cd205-1fc0-4cd1-b569-528980ea47af','去春達善分碧桃移植篆畦今春已作蕊達善前有見過之約偶立花下口占寄之  其二','舒岳祥','宋','宋诗','song-poetry','','[]','前年花在玉堂日，偶和成編競出奇。',32,'全唐诗/poet.song.228000.json','["前年花在玉堂日，偶和成編競出奇。", "今日篆畦同寂寞，碧桃無語我無詩。"]'),
('93493814-d536-4f69-8c52-173411b87426','老獵','舒岳祥','宋','宋诗','song-poetry','','[]','少壯登山脚似飛，張弓安肯擬狐狸。',32,'全唐诗/poet.song.228000.json','["少壯登山脚似飛，張弓安肯擬狐狸。", "老來猶向兒孫話，話著南山射虎時。"]'),
('f288ddd7-eb80-4ac5-aaa7-a89672822d2d','即事','舒岳祥','宋','宋诗','song-poetry','','[]','漁翁一葉舞波瀾，不及牛童自在眠。',32,'全唐诗/poet.song.228000.json','["漁翁一葉舞波瀾，不及牛童自在眠。", "短笛數聲烟草晚，柴門疎柳小星懸。"]'),
('aec8441f-6936-44c1-b2ab-af8b3a003c60','牡丹','舒岳祥','宋','宋诗','song-poetry','','[]','九枝初拆御袍紅，艷質煌煌日正中。',32,'全唐诗/poet.song.228000.json','["九枝初拆御袍紅，艷質煌煌日正中。", "曾對集英瞻衮冕，孤臣灑？立東風。"]'),
('fb35c1e2-cbdd-4bfa-8206-68bb73cd028e','老椶','舒岳祥','宋','宋诗','song-poetry','','[]','馬鬉頻剪新心吐，鳳翅初開勁葉森。',32,'全唐诗/poet.song.228000.json','["馬鬉頻剪新心吐，鳳翅初開勁葉森。", "更有木魚三百尾，山僧鍋裏煮黄金。"]'),
('639dedeb-971b-4fb7-b0bc-7f64c66c2d7d','芰荷洲','舒岳祥','宋','宋诗','song-poetry','','[]','綠垤霞川濯錦香，何人著屐上溪航。',32,'全唐诗/poet.song.228000.json','["綠垤霞川濯錦香，何人著屐上溪航。", "數聲疎雨鳴荷葉，兩岸清蛙報水凉。"]'),
('36a40a47-e195-44a2-9f66-8649031c80af','啼烏詞','舒岳祥','宋','宋诗','song-poetry','','[]','月明雙影带霜栖，長憶青梧玉井西。',32,'全唐诗/poet.song.228000.json','["月明雙影带霜栖，長憶青梧玉井西。", "前度碧窗驚曉夢，女奴驅遣莫教啼。"]'),
('173c4a30-76ff-416c-8cf9-0dad78243254','十五日雨後微月遺安堂前有梔花一枝適開折爲佛供此夜清寒','舒岳祥','宋','宋诗','song-poetry','','[]','雨足清寒月色微，風將幽磬落柴扉。',32,'全唐诗/poet.song.228000.json','["雨足清寒月色微，風將幽磬落柴扉。", "一瓶薝蔔修清供，童子巖腰取水歸。"]'),
('f635a28b-baf9-4acb-a2c8-4c131461a54f','西洞宿雲','舒岳祥','宋','宋诗','song-poetry','','[]','悠然岸幘看雲歸，出處無心也太奇。',32,'全唐诗/poet.song.228000.json','["悠然岸幘看雲歸，出處無心也太奇。", "未是爲霖蘇旱日，出山不似宿巖時。"]'),
('ec62714a-b444-4b9f-acff-4284465dd0eb','十一月初三日插梅花古罍洗中因成四絕  其一','舒岳祥','宋','宋诗','song-poetry','','[]','半映寒溪半映山，不妨朱戶借清閒。',32,'全唐诗/poet.song.228000.json','["半映寒溪半映山，不妨朱戶借清閒。", "詩人带得渠風味，也有香名滿世間。"]'),
('e64b38cc-7049-4152-be00-9849eac0f8ed','十一月初三日插梅花古罍洗中因成四絕  其二','舒岳祥','宋','宋诗','song-poetry','','[]','正是江村欲雪時，柴門修竹見橫枝。',32,'全唐诗/poet.song.228000.json','["正是江村欲雪時，柴門修竹見橫枝。", "誰知句裏生香處，只許疎簾半面窺。"]'),
('b412f03f-cfcc-4d02-86d7-f36337dc8986','十一月初三日插梅花古罍洗中因成四絕  其三','舒岳祥','宋','宋诗','song-poetry','','[]','雪中點綴精神好，月下橫陳骨格真。',32,'全唐诗/poet.song.228000.json','["雪中點綴精神好，月下橫陳骨格真。", "更有風烟生別恨，隔簾遥望李夫人。"]'),
('1ffb3760-50f6-40b0-bb37-edd98bb90613','十一月初三日插梅花古罍洗中因成四絕  其四','舒岳祥','宋','宋诗','song-poetry','','[]','洛水湘娥剪曉冰，枝頭五出幻飛霙。',32,'全唐诗/poet.song.228000.json','["洛水湘娥剪曉冰，枝頭五出幻飛霙。", "夜來鶴踏高枝折，撒下階前碎月明。"]'),
('5b39adc2-971e-4a74-bd33-3c921985fa89','和劉仙尉咏梅','舒岳祥','宋','宋诗','song-poetry','','[]','垂垂一樹壓疎籬，最愛崚嶒鶴膝枝。',32,'全唐诗/poet.song.228000.json','["垂垂一樹壓疎籬，最愛崚嶒鶴膝枝。", "只占歲寒花盡後，不爭開早與開遲。"]'),
('7143c52d-0134-4623-b36a-8764f7302ef6','古銅爐','舒岳祥','宋','宋诗','song-poetry','','[]','殷彝周鼎幾千年，土蝕苔封洗滌全。',32,'全唐诗/poet.song.228000.json','["殷彝周鼎幾千年，土蝕苔封洗滌全。", "且與道人燒柏子，不須公子爇龍涎。"]'),
('4eee2db1-595c-4179-9f1c-1eedcb7e9aa0','即目','舒岳祥','宋','宋诗','song-poetry','','[]','藕梢菱蔓織橫塘，屬玉鵁鶄度渺茫。',32,'全唐诗/poet.song.228000.json','["藕梢菱蔓織橫塘，屬玉鵁鶄度渺茫。", "可怪插秧青雨裏，暮寒清切水梔香。"]'),
('7a807403-039c-4138-ba6d-15f37d39970d','櫧樹','舒岳祥','宋','宋诗','song-poetry','','[]','凌轢風霜四十圍，白猿不上最高枝。',32,'全唐诗/poet.song.228000.json','["凌轢風霜四十圍，白猿不上最高枝。", "明堂未構材何用，拋擲玄珠滿地皮。"]'),
('119be86f-6006-4d7b-9363-aebb9fc8168e','咏龍','舒岳祥','宋','宋诗','song-poetry','','[]','曾見老人潭上坐，忽然不見石泓深。',32,'全唐诗/poet.song.228000.json','["曾見老人潭上坐，忽然不見石泓深。", "至今月白風清夜，潭底時聞似笛吟。"]'),
('53000e18-1045-4648-9b1a-5aa2eabfea6a','戲咏玉簪花金線草二物','舒岳祥','宋','宋诗','song-poetry','','[]','金線草頭蜂展翅，玉簪花頷鷺生兒。',32,'全唐诗/poet.song.228000.json','["金線草頭蜂展翅，玉簪花頷鷺生兒。", "窗前野草皆天巧，也有閒人爲賦詩。"]'),
('ceb50920-e9ac-456a-a2aa-e0046c24312d','即事','舒岳祥','宋','宋诗','song-poetry','','[]','二月東風始見梅，山童折得數枝來。',32,'全唐诗/poet.song.228000.json','["二月東風始見梅，山童折得數枝來。", "銅瓶棐几修清供，香鼎中間易卷開。"]'),
('1cbd3856-5b44-4f09-ad81-c7c9d8a811c1','小春聞提壺鳥戲成','舒岳祥','宋','宋诗','song-poetry','','[]','越鳥憂兄行不得，蜀禽勸客不如歸。',32,'全唐诗/poet.song.228000.json','["越鳥憂兄行不得，蜀禽勸客不如歸。", "何如聽此提壺語，美酒沽來總息機。"]'),
('542357a6-997c-4bc3-b672-b2449031996a','谷口','舒岳祥','宋','宋诗','song-poetry','','[]','萬朵千枝滿谷中，含成谷口是牆東。',32,'全唐诗/poet.song.228000.json','["萬朵千枝滿谷中，含成谷口是牆東。", "先生老向花中坐，莫放東風落晚紅。"]'),
