('7fe0897a-f99b-4e31-957d-650c52f8ed60','無題  其八','舒岳祥','宋','宋诗','song-poetry','','[]','春風萬里虞姬草，夜月千村蜀帝花。',32,'全唐诗/poet.song.228000.json','["春風萬里虞姬草，夜月千村蜀帝花。", "已矣莫論如許事，菜畦黄蝶繞田家。"]'),
('77212895-fd02-44f4-9561-86d8914732b5','雪村聞鵑','舒岳祥','宋','宋诗','song-poetry','','[]','故國亡來身已非，千年猶訴不如歸。',32,'全唐诗/poet.song.228000.json','["故國亡來身已非，千年猶訴不如歸。", "參天古木魂迷路，誰與黎侯賦式微。"]'),
('20ba494e-589b-43c4-906f-6a9c230c887e','十五日月明悽然無况因憶方泳道挽拙齋詩有人哭台明界天昏水石村之句故用其語以敘傷感','舒岳祥','宋','宋诗','song-poetry','','[]','月色清寒早閉門，秋蟲依舊語黄昏。',32,'全唐诗/poet.song.228000.json','["月色清寒早閉門，秋蟲依舊語黄昏。", "老人心事渾如此，舊住薌巖水石村。"]'),
('5c7de02a-e35f-4cfb-b32e-7496045e048c','雁','舒岳祥','宋','宋诗','song-poetry','','[]','老鴈移屯百萬回，黄埃極目磧沙飛。',32,'全唐诗/poet.song.228000.json','["老鴈移屯百萬回，黄埃極目磧沙飛。", "春風萬里梅花路，淼淼江南人未歸。"]'),
('82e92999-815f-4bb0-8ed7-52397da45164','五月二十八日四絕  其一','舒岳祥','宋','宋诗','song-poetry','','[]','鳥獨沉啼意，螢低照去蹤。',24,'全唐诗/poet.song.228000.json','["鳥獨沉啼意，螢低照去蹤。", "艱危吾輩老，寂寞此心同。"]'),
('1da81da3-940b-4182-8e53-d0203bea5c89','五月二十八日四絕  其二','舒岳祥','宋','宋诗','song-poetry','','[]','蜂影過窗急，雛聲出樹繁。',24,'全唐诗/poet.song.228000.json','["蜂影過窗急，雛聲出樹繁。", "經時不吐句，此日獨窺園。"]'),
('c8a465bc-ad6d-46cc-bdcc-c92a6562b715','五月二十八日四絕  其三','舒岳祥','宋','宋诗','song-poetry','','[]','雨來元有路，風過本無痕。',24,'全唐诗/poet.song.228000.json','["雨來元有路，風過本無痕。", "小立清溪曲，欹眠白石根。"]'),
('bea33b0c-4188-4601-8bb7-7e54f64eacec','口號','舒岳祥','宋','宋诗','song-poetry','','[]','敏求善釀能好客，喜與老潘相往還。',32,'全唐诗/poet.song.228000.json','["敏求善釀能好客，喜與老潘相往還。", "今日敏求泉下卧，老潘無酒客薑山。"]'),
('596334bd-8710-4704-be25-fc0865d49f27','無題  其一','舒岳祥','宋','宋诗','song-poetry','','[]','江山有恨非吾土，花鳥相逢故惱翁。',32,'全唐诗/poet.song.228000.json','["江山有恨非吾土，花鳥相逢故惱翁。", "百歲唯餘二十五，一春强半又成空。"]'),
('358adbb3-9693-484e-8f90-d55847035362','無題  其二','舒岳祥','宋','宋诗','song-poetry','','[]','宇宙千年更帝霸，春秋萬世正乾坤。',32,'全唐诗/poet.song.228000.json','["宇宙千年更帝霸，春秋萬世正乾坤。", "陰陽定位綱常立，於此推尋見本原。"]'),
('8ead77a7-bb10-4c7f-a0ac-77930fcfef10','無題  其三','舒岳祥','宋','宋诗','song-poetry','','[]','杏花寒氣退三舍，柳絮春光減二分。',32,'全唐诗/poet.song.228000.json','["杏花寒氣退三舍，柳絮春光減二分。", "簾外遊絲飛冉冉，窗間野馬走紛紛。"]'),
('d0e74418-f7c0-48dc-a068-37d73fdc1c6e','無題  其四','舒岳祥','宋','宋诗','song-poetry','','[]','欲問醉鄉過睡鄉，兩鄉相接兩相忘。',32,'全唐诗/poet.song.228000.json','["欲問醉鄉過睡鄉，兩鄉相接兩相忘。", "海棠應是此鄉物，醉暈深如午睡長。"]'),
('01ee6b15-fbbf-4ca1-810c-029dcacb983e','清絕','舒岳祥','宋','宋诗','song-poetry','','[]','道人清絕在中宵，清絕因何生寂寥。',32,'全唐诗/poet.song.228000.json','["道人清絕在中宵，清絕因何生寂寥。", "最愛讀書窗外雨，數聲殘剩過芭蕉。"]'),
('6caff24b-0fdb-4693-9ed5-9f7eb7c93fdc','老銅壺','舒岳祥','宋','宋诗','song-poetry','','[]','孫孫子子永享用，下有銘文誰所爲。',32,'全唐诗/poet.song.228000.json','["孫孫子子永享用，下有銘文誰所爲。", "有色無聲形制具，不得隨俗插花枝。"]'),
('1e79ced2-3110-40ff-80e5-a816f8595214','三月二十九日立夏喜晴稍有自適意有自舊京來者問錢湖景物又復悵然','舒岳祥','宋','宋诗','song-poetry','','[]','黄梅青李夏方初，新綠池塘浴小鳬。',64,'全唐诗/poet.song.228000.json','["黄梅青李夏方初，新綠池塘浴小鳬。", "此日貓頭削寒玉，他時鴻喙煮明珠。", "白頭偷果從渠樂，繡眼穿花不我虞。", "更有長愁無遣處，只今細柳映新蒲。"]'),
('700bd04f-d59e-4e31-a5b8-0a3b8a2840e8','題正仲瓠齋','舒岳祥','宋','宋诗','song-poetry','','[]','大瓠秋成實，垂垂掛舊林。',48,'全唐诗/poet.song.228000.json','["大瓠秋成實，垂垂掛舊林。", "剖堅容五石，濟急直千金。", "瓢飲希賢樂，匏尊共客斟。", "許由嫌汝聒，擲去是何心。"]'),
('54ea5636-679f-47c0-b205-9bf01264ae68','新成小齋曰剡雪舟以此興有所思也','舒岳祥','宋','宋诗','song-poetry','','[]','銀河枕上客星來，殘夢西窗水鳥啼。',32,'全唐诗/poet.song.228000.json','["銀河枕上客星來，殘夢西窗水鳥啼。", "身入布衾如卧雪，當年曾泛戴公溪。"]'),
('ba06890f-efe9-4426-98e3-0eb9c99c18d9','桂臺','舒岳祥','宋','宋诗','song-poetry','','[]','蒼苔踏碎吟初就，綠蔭看成老又來。',32,'全唐诗/poet.song.228000.json','["蒼苔踏碎吟初就，綠蔭看成老又來。", "世事悠悠吾已矣，人生擾擾亦何鍘。"]'),
('0840f877-b757-4a60-925a-f21a825a92b5','和俟其按察詠縣學古梅  其一','舒岳祥','宋','宋诗','song-poetry','','[]','前身自是傅岩梅，持斧江南得得來。',64,'全唐诗/poet.song.228000.json','["前身自是傅岩梅，持斧江南得得來。", "一笑見花同臭味，百妖潛影入莓苔。", "只將冷淡全超俗，肯向繁穠浪占魁。", "愛惜耆儒如此樹，二天雨露好培栽。"]'),
('59960dc4-12ea-477b-a10e-d57101b3309c','和俟其按察詠縣學古梅  其二','舒岳祥','宋','宋诗','song-poetry','','[]','四教堂前百歲梅，北方豪傑爲渠來。',64,'全唐诗/poet.song.228000.json','["四教堂前百歲梅，北方豪傑爲渠來。", "清癯自許根封雪，勁峭何妨骨鎖苔。", "影裏青衿飽絃誦，花前玉節照杓魁。", "林逋只向孤山種，不及文宣廟裏栽。"]'),
('7c3e1504-708f-4199-a04d-cc33ec303bdd','問信紅梅二章  其一','舒岳祥','宋','宋诗','song-poetry','','[]','花到紅梅真有韻，人生白髮未宜愁。',32,'全唐诗/poet.song.228000.json','["花到紅梅真有韻，人生白髮未宜愁。", "只須竟就花前醉，如此風流不外求。"]'),
('84d863b8-df0d-4f3b-abdb-2dad576f4fa9','問信紅梅二章  其二','舒岳祥','宋','宋诗','song-poetry','','[]','凍白千林須雪重，暖紅一點著春多。',32,'全唐诗/poet.song.228000.json','["凍白千林須雪重，暖紅一點著春多。", "啞馿瘦策平臯去，如此風流奈老何。"]'),
('7200ecfb-3674-4e88-b541-989186e1ac0d','對紅香梅','舒岳祥','宋','宋诗','song-poetry','','[]','雪裏紅梅樹，尊前白髮翁。',24,'全唐诗/poet.song.228000.json','["雪裏紅梅樹，尊前白髮翁。", "莫求顔色似，風致許渠同。"]'),
('0f15361f-1e29-4b35-88c9-2f8bb85adfec','紅梅','舒岳祥','宋','宋诗','song-poetry','','[]','掃盡西風萬葉紅，梅花一色照青空。',32,'全唐诗/poet.song.228000.json','["掃盡西風萬葉紅，梅花一色照青空。", "天公又恐太枯淡，故著紅藍染雪叢。"]'),
('49c6beb3-32e9-4db2-8af8-ee0ffecf6703','三月十七日食梅子有感','舒岳祥','宋','宋诗','song-poetry','','[]','春事已隨花事殘，東風急處省憑欄。',32,'全唐诗/poet.song.228000.json','["春事已隨花事殘，東風急處省憑欄。", "枝頭青子生來苦，守得黄時也自酸。"]'),
('02526db7-b521-4592-82a7-80cf17f6186d','高人','舒岳祥','宋','宋诗','song-poetry','','[]','雲日弄輕霠，前溪給緩尋。',48,'全唐诗/poet.song.228000.json','["雲日弄輕霠，前溪給緩尋。", "燕翻紅雨亂，鶑出翠微深。", "迥矣蘇門嘯，懷哉梁父吟。", "高人不可見，誰見此時心。"]'),
('b8fddd14-5537-4d8e-a52e-5dd80007793c','老人村','舒岳祥','宋','宋诗','song-poetry','','[]','綠樹合來無路入，青煙起處有人居。',32,'全唐诗/poet.song.228000.json','["綠樹合來無路入，青煙起處有人居。", "衣冠從俗語言樸，禮樂相忘機巧疏。"]'),
('25645bb3-0c49-47ec-8b65-88280a345ea6','丙子九月陳村避地三絕  其一','舒岳祥','宋','宋诗','song-poetry','','[]','黑光磨蕩掩陽精，兵火成霞照夜明。',32,'全唐诗/poet.song.228000.json','["黑光磨蕩掩陽精，兵火成霞照夜明。", "誰信天台山脚下，如今無佛救蒼生。"]'),
