('e17707c2-ef27-4a69-95a9-428bc5a59834','丙子九月陳村避地三絕  其三','舒岳祥','宋','宋诗','song-poetry','','[]','盤盤幽谷造雲峯，應有逃秦隠此中。',32,'全唐诗/poet.song.228000.json','["盤盤幽谷造雲峯，應有逃秦隠此中。", "行到半山奇絕事，白鷳如練掛青松。"]'),
('0e7cd8d8-e89b-4e20-b236-f41a26ef0a3a','行海村','舒岳祥','宋','宋诗','song-poetry','','[]','天遠鳴榔雙槳浦，夜凉吹笛十家村。',32,'全唐诗/poet.song.228000.json','["天遠鳴榔雙槳浦，夜凉吹笛十家村。", "如今鬼出無人過，深閉柴門自斷魂。"]'),
('5a765b4b-50f3-4e91-bebe-e16a12c29ff6','十村絕句  其一','舒岳祥','宋','宋诗','song-poetry','','[]','鵁鶄屬玉亂橫斜，石步柴門下白沙。',32,'全唐诗/poet.song.228000.json','["鵁鶄屬玉亂橫斜，石步柴門下白沙。", "長笛一聲人不見，小舟風緊入蒹葭。"]'),
('2ae812ba-c15f-4d03-8b3c-c96f7f6793c2','十村絕句  其二','舒岳祥','宋','宋诗','song-poetry','','[]','深谷元無鄒子律，牧童携角上牛吹。',32,'全唐诗/poet.song.228000.json','["深谷元無鄒子律，牧童携角上牛吹。", "一聲吹下柴門近，先報渠孃煮菜糜。"]'),
('02eff02a-832f-470e-a170-c2a2662a4106','十村絕句  其三','舒岳祥','宋','宋诗','song-poetry','','[]','朝朝腰斧採荆榛，博米求鹽到海村。',32,'全唐诗/poet.song.228000.json','["朝朝腰斧採荆榛，博米求鹽到海村。", "白虎當溪儂不畏，祗愁暴吏打人門。"]'),
('3698a200-a5e2-4517-b374-77d1046274e1','十村絕句  其四','舒岳祥','宋','宋诗','song-poetry','','[]','麥鬚剪剪吹成浪，花口吟吟笑作東。',32,'全唐诗/poet.song.228000.json','["麥鬚剪剪吹成浪，花口吟吟笑作東。", "莫道太平無處覓，便於此處見天真。"]'),
('0679b860-cfe8-462e-b1de-169b809ec0db','十村絕句  其五','舒岳祥','宋','宋诗','song-poetry','','[]','清晨扶杖百花源，風摺烏紗半幅翻。',32,'全唐诗/poet.song.228000.json','["清晨扶杖百花源，風摺烏紗半幅翻。", "三十年前風月好，青樓白面碗如盆。"]'),
('50b99a85-60ba-4812-9f86-a8c2b2c052e4','十村絕句  其六','舒岳祥','宋','宋诗','song-poetry','','[]','青帘懸椀誰誇大，小閤留人更放饒。',32,'全唐诗/poet.song.228000.json','["青帘懸椀誰誇大，小閤留人更放饒。", "我有布袍堪典否，如今無客解金貂。"]'),
('0628db03-0896-4c2a-b0af-e9d9026706f6','十村絕句  其七','舒岳祥','宋','宋诗','song-poetry','','[]','桐花開處青鳩醉，桑椹甜時紫鴿忙。',32,'全唐诗/poet.song.228000.json','["桐花開處青鳩醉，桑椹甜時紫鴿忙。", "正是三眠三起日，送蠶小婦出烘房。"]'),
('aecf816d-ddfa-4efe-a919-72f878be9ece','十村絕句  其八','舒岳祥','宋','宋诗','song-poetry','','[]','煮來藤竹如輕霧，漉就槽簾不怕冰。',32,'全唐诗/poet.song.228000.json','["煮來藤竹如輕霧，漉就槽簾不怕冰。", "辛苦饑寒緣底事，夜深甓屋尚懸燈。"]'),
('4bcaa078-f5c9-447f-94a7-9f0fdb463bee','十村絕句  其九','舒岳祥','宋','宋诗','song-poetry','','[]','翰林子墨青氈稿，毛穎陶泓白髮交。',32,'全唐诗/poet.song.228000.json','["翰林子墨青氈稿，毛穎陶泓白髮交。", "寄語諸郎須祓滌，一牀書卷共衡茅。"]'),
('55304bd4-b95d-4023-a40d-4fb843f296d5','十村絕句  其一○','舒岳祥','宋','宋诗','song-poetry','','[]','春風淰淰欺駝褐，客思翛翛著柳黄。',32,'全唐诗/poet.song.228000.json','["春風淰淰欺駝褐，客思翛翛著柳黄。", "不是蘭舟共漂泊，清明何事不還鄉。"]'),
('294b55cf-97f5-405d-8485-5dd2c1b2771b','讀方元善落花詩有感  其一','舒岳祥','宋','宋诗','song-poetry','','[]','爲渠銷瘦爲渠愁，減却風流剩却羞。',64,'全唐诗/poet.song.228000.json','["爲渠銷瘦爲渠愁，減却風流剩却羞。", "得雨如投碧玉井，隨風似墮綠珠樓。", "醫頰髓空無處覓，返魂香斷爲誰留。", "此詩吟罷難消得，八十翁翁一笑休。"]'),
('6a50a368-19c9-43d2-a693-9a76db41b29f','讀方元善落花詩有感  其二','舒岳祥','宋','宋诗','song-poetry','','[]','次第花開次第飛，總堪飲酒與吟詩。',32,'全唐诗/poet.song.228000.json','["次第花開次第飛，總堪飲酒與吟詩。", "絕憐新綠光如沃，何必繁英儘在枝。"]'),
('869a5e22-db8c-479b-be85-f90387ded933','歲莫送正仲還鴈蒼','舒岳祥','宋','宋诗','song-poetry','','[]','歲窮終有別，人老得無愁。',48,'全唐诗/poet.song.228000.json','["歲窮終有別，人老得無愁。", "眼看書先廢，材衰句懶酬。", "計年知晚易，論學愧東丘。", "欲就寧川志，開春與子謀。"]'),
('2f6e306c-06fb-4d3d-a9fd-fc409481c59e','和正仲賦重修篆畦亭館韻','舒岳祥','宋','宋诗','song-poetry','','[]','亭館成來三十年，主人頭白與扶顛。',64,'全唐诗/poet.song.228000.json','["亭館成來三十年，主人頭白與扶顛。", "已誅薦莽開瓜圃，更剪茭蘆浚藕田。", "竹下鳴琴長憶鶴，花邊釀酒擬留仙。", "今知煩惱都無用，脩短隨緣一任天。"]'),
('882dfc2a-c2d4-4cb9-a727-a3dec7fae6f6','戒僮僕種蕉葦','舒岳祥','宋','宋诗','song-poetry','','[]','莫把閒愁向客談，且看晴雪映疏簾。',32,'全唐诗/poet.song.228000.json','["莫把閒愁向客談，且看晴雪映疏簾。", "欲聽夜雨無篷艇，更種紅蕉碧葦添。"]'),
('819f1b1c-6746-4489-8bfc-cc1edadc7952','寄趙敏求','舒岳祥','宋','宋诗','song-poetry','','[]','趙子貧愈好，吟詩送此生。',48,'全唐诗/poet.song.228000.json','["趙子貧愈好，吟詩送此生。", "焚巢同旅鳥，泛宅老書檠。", "八座清門戶，王塘好弟兄。", "杉棚先辱和，欲報怨無瓊。"]'),
('038e8724-2f4a-466d-befd-bd0a8f2a3a88','臘月二十五日偶憶孟浩然白髮催年老青陽逼歲除之句因次和此篇奉寄達善','舒岳祥','宋','宋诗','song-poetry','','[]','歸夢涉遠道，青山非故廬。',48,'全唐诗/poet.song.228000.json','["歸夢涉遠道，青山非故廬。", "歲時筋力減，日夜鬢毛疎。", "且免編民役，休論邸報除。", "百年餘二老，莫遣寸陰虛。"]'),
('bbb37241-30a6-43fd-aa2b-65df5c6897da','寄達善','舒岳祥','宋','宋诗','song-poetry','','[]','渺渺思君處，悠悠古道旁。',48,'全唐诗/poet.song.228000.json','["渺渺思君處，悠悠古道旁。", "柴荆人獨自，櫸柳月昏黄。", "渴鼠尋松溜，饑烏背夕陽。", "王塘在吾目，空費九回腸。"]'),
('8202e1cd-78a5-47cf-8888-8290e58ebcd6','寄二林','舒岳祥','宋','宋诗','song-poetry','','[]','久客誰爲主，無歸莫問家。',48,'全唐诗/poet.song.228000.json','["久客誰爲主，無歸莫問家。", "古書澆茗椀，凍酒嚥梅花。", "巖靜松拋子，沙虛筍養芽。", "二林誰遠近，佇立日西斜。"]'),
('ab61f2c7-ba69-4b3a-b2f5-67ddf568f333','寄袁季源','舒岳祥','宋','宋诗','song-poetry','','[]','當世佳公子，枝吾雅道多。',48,'全唐诗/poet.song.228000.json','["當世佳公子，枝吾雅道多。", "江南有文獻，魯國自强歌。", "火後歸新第，兵餘喜止戈。", "公車行有召，毋久戀松蘿。"]'),
('2b9a5706-7ad9-496f-a3b2-70fd19bfe3d9','寄帥初','舒岳祥','宋','宋诗','song-poetry','','[]','寄語榆林戴，年來書不靈。',48,'全唐诗/poet.song.228000.json','["寄語榆林戴，年來書不靈。", "翠微雙鬢白，茅舍一燈青。", "醉後窮豪在，吟成老健能。", "楊梅時節近，吾欲理行縢。"]'),
('b648cb89-82c5-404c-9a87-a1f064b53e9b','病起寄二林','舒岳祥','宋','宋诗','song-poetry','','[]','心地緬然平，喬林夏氣清。',48,'全唐诗/poet.song.228000.json','["心地緬然平，喬林夏氣清。", "炎風疏鳥毳，凉雨滴蟬聲。", "輸翟專攻守，弓函誓死生。", "吟成與誰寄，二子在鄞城。"]'),
('29a95b3d-b344-45d0-9030-57918d21c96e','寄子堂  其一','舒岳祥','宋','宋诗','song-poetry','','[]','來往畏炎熱，杉篁取逕微。',48,'全唐诗/poet.song.228000.json','["來往畏炎熱，杉篁取逕微。", "蝶飛逢草住，燕出認簷歸。", "雲卧從衣冷，風梳愛髮稀。", "清談能解慍，松麈爲君揮。"]'),
('859a6eb6-115f-4242-8de1-38c799c933f3','寄子堂  其二','舒岳祥','宋','宋诗','song-poetry','','[]','不踐山中約，時時夢見之。',48,'全唐诗/poet.song.228000.json','["不踐山中約，時時夢見之。", "況當春雨夜，正作韭虀思。", "種菊秋堪擷，誅茅冬未遲。", "人生難自料，身後要名垂。"]'),
('33f4b063-5573-4026-a12d-fa75480c7f79','寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','雲峰雙鳥破，雪逕一僧分。',48,'全唐诗/poet.song.228000.json','["雲峰雙鳥破，雪逕一僧分。", "紅酒回丹渥，青編笑白紛。", "風昏生月暈，水落織冰文。", "歲莫無來客，開門獨候君。"]'),
('c2ba86c2-7218-424a-a44d-c054b71adc76','寄袁中素季原','舒岳祥','宋','宋诗','song-poetry','','[]','清談疏世慮，知髮度年華。',48,'全唐诗/poet.song.228000.json','["清談疏世慮，知髮度年華。", "雀飲盆中水，蜂尋案上花。", "郊原新射雉，陂蕩早開蛙。", "得句何人贈，棠溪有竹家。"]'),
('c1c42eb7-b7a9-45b4-8b23-de25464e4848','亂後寄正仲因諗恕齋樞相朔漠音耗','舒岳祥','宋','宋诗','song-poetry','','[]','山人水南北，別業瀼東西。',48,'全唐诗/poet.song.228000.json','["山人水南北，別業瀼東西。", "落葉屏風石，斜陽水碓溪。", "門荒翟公雀，野迥孟嘗鷄。", "樞相徂沙漠，酸風萬里迷。"]'),
('bd80af89-b9ef-4d1f-a8ce-bb67eb633599','帥初屢書有相訪之約且求予文集知予有藏山之志也近因彌大過我知其有來日矣作此寄之','舒岳祥','宋','宋诗','song-poetry','','[]','流水不還剡，落花終到鄞。',48,'全唐诗/poet.song.228000.json','["流水不還剡，落花終到鄞。", "偶逢歸峽客，乃是寄書人。", "古剎藏山志，他生結願因。", "煩君同校正，字字莫留塵。"]'),
('f6b763d8-4eee-4ef4-a418-88ea2081140f','寄子堂','舒岳祥','宋','宋诗','song-poetry','','[]','欲出一雨隔，相違十日强。',48,'全唐诗/poet.song.228000.json','["欲出一雨隔，相違十日强。", "鼠過松落粉，雉步麥摇芒。", "酒盡夜難過，書清日自長。", "羊求三逕約，來往莫相忘。"]'),
('0bdef281-bfcf-4fc8-8c6d-bd28eb83f62d','寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','相對石屏風，相邀石老翁。',48,'全唐诗/poet.song.228000.json','["相對石屏風，相邀石老翁。", "魚遊山影裏，鳥睡水聲中。", "詩卷行未了，書囊倒不空。", "笭箵君莫忘，猶約待秋風。"]'),
('72f0f31e-ad99-4bc4-8424-27f72f67412c','五月一日寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','住處村非遠，別時山更多。',48,'全唐诗/poet.song.228000.json','["住處村非遠，別時山更多。", "花風起晴浪，草露落明河。", "世事老休問，故人今幾何。", "朝來新酒禁，煮餠卧岩阿。"]'),
('16864d42-e749-434c-a364-25050445178c','和韻寄胡山甫','舒岳祥','宋','宋诗','song-poetry','','[]','鄉心趨老重，見說買山成。',72,'全唐诗/poet.song.228000.json','["鄉心趨老重，見說買山成。", "靜坐性情淡，孤眠滋味清。", "樵人時識面，禪客共知名。", "山色元無垢，溪聲自不平。", "池荷應足製，山蕷想堪羹。", "九日如今近，思君出峽行。"]'),
('c06c15e4-de2f-4f83-ba46-f86077a91cc4','五月間與正仲立耕養堂前見石榴一花吐初因以荆公詩并俗語作對云萬綠一紅十風五雨好作尺牘中時令語正仲云只作詩語亦佳別後因補成章以寄之','舒岳祥','宋','宋诗','song-poetry','','[]','石屏溪上晚風柔，深念沉思註易樓。',64,'全唐诗/poet.song.228000.json','["石屏溪上晚風柔，深念沉思註易樓。", "好酒自能和性氣，閑愁何必上眉頭。", "十風五雨天常順，萬綠一紅春更留。", "竈婢解炊新麥飯，提魚仍就篆畦遊。"]'),
('3842716d-04f5-49cc-bbe1-d14842b77b19','寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','淰淰清愁變暮寒，賓鴻去後燕來還。',64,'全唐诗/poet.song.228000.json','["淰淰清愁變暮寒，賓鴻去後燕來還。", "流紅似雨人千里，總翠如山屋萬間。", "竹杖行藏觀動靜，柴門開闔見忙閑。", "何如上傳多髯客，白飯魚羹養好顔。"]'),
('d42dac05-5e20-476b-a015-df44f4d8d713','用韻寄胡元魯因梅所袖達','舒岳祥','宋','宋诗','song-poetry','','[]','賓鴻風逆斷來縢，魚腹書沉未上罾。',64,'全唐诗/poet.song.228000.json','["賓鴻風逆斷來縢，魚腹書沉未上罾。", "鑷白秋風鍊藥院，研朱仙露讀書燈。", "青峰極目先榆景，黄鳥收聲有木冰。", "欲問都城初破事，願君秉筆直無朋。"]'),
('a28ee835-5728-44ba-8498-cb043422220c','寄二林','舒岳祥','宋','宋诗','song-poetry','','[]','等閑詩句無題目，憶著二林新意生。',64,'全唐诗/poet.song.228000.json','["等閑詩句無題目，憶著二林新意生。", "月皎皎時猿一箇，風泠泠處竹千莖。", "春花不及寒花耐，山鳥何如水鳥清。", "欲放詩瓢滄海渺，不如飛鴈入鄞城。"]'),
('e473dab2-236e-4d44-9ab6-285d0dcd17e6','寄帥初','舒岳祥','宋','宋诗','song-poetry','','[]','西家女兒長日愁，白頭鼻息撼林丘。',64,'全唐诗/poet.song.228000.json','["西家女兒長日愁，白頭鼻息撼林丘。", "老去聲名惜雞肋，世間富貴爛羊頭。", "青山白鷺水天遠，綠葉黄鸝風日柔。", "欲往榆林忘南北，幾回吹笛上高樓。"]'),
('a8b31c0a-04c4-4f9e-9558-c4d94c126d9d','寄少白詩後因問訊小潘','舒岳祥','宋','宋诗','song-poetry','','[]','詩翁山膊鬢颼颼，只向岩幽了白頭。',32,'全唐诗/poet.song.228000.json','["詩翁山膊鬢颼颼，只向岩幽了白頭。", "欲共君家阿戎語，蟬聯書笥吐難收。"]'),
('c17f102b-7348-4382-ab3c-e9a71f94a10d','再寄正仲','舒岳祥','宋','宋诗','song-poetry','','[]','澗碧山紅錦步障，晚菘早韭五侯鯖。',32,'全唐诗/poet.song.228000.json','["澗碧山紅錦步障，晚菘早韭五侯鯖。", "莫道亂來無樂事，牀頭流水作琴聽。"]'),
('2d2276b3-1abd-4e59-97e1-f472769739b5','寄胡山甫','舒岳祥','宋','宋诗','song-poetry','','[]','梅梢殘雨知頭數，溪上無風麥自青。',32,'全唐诗/poet.song.228000.json','["梅梢殘雨知頭數，溪上無風麥自青。", "遲子不來還獨卧，踏簷啼鳥喚人醒。"]'),
('e9cefc61-6561-463d-97fb-99c72d7ba987','免役未幾四月二十九日總府復有倉官之命五月初二日入城告愬作一絕貽如山王監簿如山前與予別謂此別不復有相見之日矣予言得十年住山不出吾事畢矣今未兩月已復會面更成慘愴也','舒岳祥','宋','宋诗','song-poetry','','[]','前時臨別語堪哀，後會無期首重回。',32,'全唐诗/poet.song.228000.json','["前時臨別語堪哀，後會無期首重回。", "我有巾山緣未繼，半年兩度入城來。"]'),
('12688ec0-39ce-4e1c-ba43-90b27be18fea','再題巾山二絕貽王如山監簿  其一','舒岳祥','宋','宋诗','song-poetry','','[]','北山自負任翻句，多少詩人閣筆休。',32,'全唐诗/poet.song.228000.json','["北山自負任翻句，多少詩人閣筆休。", "戎挾兩峰懷袖去，併它句子一時收。"]'),
('1370842e-2e39-4a0c-bcfe-2519cf73caba','再題巾山二絕貽王如山監簿  其二','舒岳祥','宋','宋诗','song-poetry','','[]','天將秋露沐雲鬟，故遣松巔鶴勢盤。',32,'全唐诗/poet.song.228000.json','["天將秋露沐雲鬟，故遣松巔鶴勢盤。", "詩客惟看半江月，不知一半在闌干。"]'),
('31813e52-aea8-4d0f-a92c-a69c8b64f2cd','巾山行同王監簿作','舒岳祥','宋','宋诗','song-poetry','','[]','皇華真人遊海東，雲行急疾去若風。',176,'全唐诗/poet.song.228000.json','["皇華真人遊海東，雲行急疾去若風。", "蜺旌羽節追不及，飄颻雙幘墮碧空。", "六丁六甲不得取，化作兩峰撐青紅。", "至今八面各變態，隠見有無橫復縱。", "或說蒼龍從海度，潮落江乾不能去。", "兩角崢嶸雲護之，身伏泥沙惟脊露。", "雷鳴電作定騰霄，鐵鎖橫江截歸路。", "老胡說法欲降龍，又恐鉢盂藏不住。", "故將兩塔壓其巔，擊鼓撞鐘警朝暮。", "有時風雨響空巖，僧坐堂中生畏怖。", "惟有江平月照時，付與詩人題好句。"]'),
('ae09dcaa-f385-4327-943c-cae54d847c32','一春四十日天氣未佳花事行復已矣太息成吟','舒岳祥','宋','宋诗','song-poetry','','[]','積翠林塘十畝陰，雨中不覺變流音。',64,'全唐诗/poet.song.228000.json','["積翠林塘十畝陰，雨中不覺變流音。", "江山萬里登樓眼，宇宙千年隠几心。", "有客不來還日暮，掩書無語自春深。", "倚闌欲數排簷竹，故故飛花點袖襟。"]'),
('fc76a69e-a40c-4f8a-88a5-b80c4173616b','谿魚','舒岳祥','宋','宋诗','song-poetry','','[]','紅白谿魚也可憐，夜凉沙靜枕流眠。',32,'全唐诗/poet.song.228000.json','["紅白谿魚也可憐，夜凉沙靜枕流眠。", "澄潭百尺無機事，自古何人作釣船。"]'),
('9b6e9074-d003-4bcd-bc27-d4110c5f88b4','懷舊','舒岳祥','宋','宋诗','song-poetry','','[]','蔌蔌藤花滿石床，道人端坐受生香。',32,'全唐诗/poet.song.228000.json','["蔌蔌藤花滿石床，道人端坐受生香。", "海棠枝上鶑啼處，二十年前事未忘。"]'),
('d76d2916-cdae-483d-bdf3-34830adb015c','天門山','舒岳祥','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','烟樹連天遠，漁樵兩地分。',48,'全唐诗/poet.song.228000.json','["烟樹連天遠，漁樵兩地分。", "仙舟滄海路，僧錫石橋雲。", "落日人行少，空村犬吠聞。", "誰知隠淪者，絕迹在人羣。"]'),
('2679e869-e78a-4f8f-9b8f-d320812ccb50','天門雜詠','舒岳祥','宋','宋诗','song-poetry','','[]','棋尋五老智識長，茶煮八公肌骨仙。',32,'全唐诗/poet.song.228000.json','["棋尋五老智識長，茶煮八公肌骨仙。", "應是青牛遺舊迹，不知白鹿去何年。"]'),
('ed27a740-4477-4df2-a350-80493fc16a08','新脫船場提調之役柳堤閒步','舒岳祥','宋','宋诗','song-poetry','','[]','兩兩三三溪上童，口吹麥葉送迎翁。',64,'全唐诗/poet.song.228000.json','["兩兩三三溪上童，口吹麥葉送迎翁。", "花間緩步陰陰日，柳畔閒行款款風。", "山鳥何愁頭也白，野棠無愧面能紅。", "太平五十年前過，煩惱今知萬境空。"]'),
('eb7eec94-1c1b-4b3c-8c66-8b1dcfb57d39','留正仲篆畦','舒岳祥','宋','宋诗','song-poetry','','[]','子欲尋安道，吾方夢惠連。',48,'全唐诗/poet.song.228000.json','["子欲尋安道，吾方夢惠連。", "雪花成小雨，春草傍殘年。", "悄悄論詩夜，陰陰駐客天。", "自慚私釀薄，一酌醉誰先。"]'),
('d14bca3b-8295-48a3-9d11-2186eb45df22','聞禽獻詠','舒岳祥','宋','宋诗','song-poetry','','[]','郭公莓熟郭公語，謝豹花開謝豹啼。',32,'全唐诗/poet.song.228000.json','["郭公莓熟郭公語，謝豹花開謝豹啼。", "萬斛愁消一樽酒，莊生物理底須齊。"]'),
('bb95df17-c8e5-4249-af6b-602d2b4d7a97','句','舒岳祥','宋','宋诗','song-poetry','','[]','從來明月無古今。',8,'全唐诗/poet.song.228000.json','["從來明月無古今。"]'),
('7f82bf78-cc43-432e-8087-9933844b3830','句','袁仲素','宋','宋诗','song-poetry','','[]','一松五鳳雛。',6,'全唐诗/poet.song.228000.json','["一松五鳳雛。"]'),
('911a4996-7b13-4fbf-a56e-84779491cc62','句','胡山甫','宋','宋诗','song-poetry','','[]','病起百花開。',6,'全唐诗/poet.song.228000.json','["病起百花開。"]'),
('418f14b4-fc40-4797-a4fa-bb068e45d484','湘中二首書縣齋冰壺  其一','張埴','宋','宋诗','song-poetry','','[]','湘水平淼淼，魚意活潑潑。',24,'全唐诗/poet.song.228000.json','["湘水平淼淼，魚意活潑潑。", "綠楊蓋江頭，春晚陰正闊。"]'),
('10a9c849-2132-4a6a-87ac-8c8fa8022f67','湘中二首書縣齋冰壺  其二','張埴','宋','宋诗','song-poetry','','[]','晴壟麥過花，暖泥秧出水。',24,'全唐诗/poet.song.228000.json','["晴壟麥過花，暖泥秧出水。", "寬得一寸心，人行更千里。"]'),
('252957b4-e805-4914-a134-9e33717706d8','和漢東先生韻六首  其一','張埴','宋','宋诗','song-poetry','','[]','青瓢歸自滄海頭，眇然天地飛一鷗。',32,'全唐诗/poet.song.228000.json','["青瓢歸自滄海頭，眇然天地飛一鷗。", "今人來來古人去，我自認我山中樓。"]'),
('bd878cea-421c-4e44-a580-dd999229ed5d','和漢東先生韻六首  其二','張埴','宋','宋诗','song-poetry','','[]','行行采芝復采芝，相期萬世同一時。',32,'全唐诗/poet.song.228000.json','["行行采芝復采芝，相期萬世同一時。", "可憐群動相啖食，利害悱然爭朵頤。"]'),
('081fb5ff-3589-4f5e-83a5-17cc2d695153','和漢東先生韻六首  其三','張埴','宋','宋诗','song-poetry','','[]','𥬒來黄鶴問故里，養得白鴉在玄田。',32,'全唐诗/poet.song.228000.json','["𥬒來黄鶴問故里，養得白鴉在玄田。", "人生擘劃千古歲，碧桃開向母樓前。"]'),
('211ab473-fcf6-45bf-afdb-897ff3226d26','和漢東先生韻六首  其四','張埴','宋','宋诗','song-poetry','','[]','凌明放龍去飲泉，何事此牧不在天。',32,'全唐诗/poet.song.228000.json','["凌明放龍去飲泉，何事此牧不在天。", "山中鋤芝亦不惡，未入一班輸群仙。"]'),
('16d24c6e-7f62-4ad1-bf9f-fa4a4aec3b6e','和漢東先生韻六首  其五','張埴','宋','宋诗','song-poetry','','[]','一枰勝負何有心，往往局外多堪吟。',32,'全唐诗/poet.song.228000.json','["一枰勝負何有心，往往局外多堪吟。", "今人未晤爛柯意，祗道歲月青山深。"]'),
('1b59c01b-acdf-4a1c-8199-5dcc0dbf23a3','和漢東先生韻六首  其六','張埴','宋','宋诗','song-poetry','','[]','舉矢欲向天狼時，草木零落美人遲。',32,'全唐诗/poet.song.228000.json','["舉矢欲向天狼時，草木零落美人遲。", "中年新知舊別意，悲樂相忘荃獨宜。"]'),
('dbb6a713-1275-4425-8b06-a755a0dac2e1','過洞庭書所見','張埴','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','濕烟吹起岸東西，漁子藏舟竹四圍。',32,'全唐诗/poet.song.228000.json','["濕烟吹起岸東西，漁子藏舟竹四圍。", "脫下簑衣揚去雪，不教人道釣魚歸。"]'),
('c14b840f-255d-4833-b1e1-7a6e8a86de86','東湖湯餠後進翁展墓飲嵩山踏雨泳歸在行相繼屬和蘭亭集獻之噤無半語果人情耶  其一','張埴','宋','宋诗','song-poetry','','[]','諸老襟期三十年，看花杖屨又棲禪。',32,'全唐诗/poet.song.228000.json','["諸老襟期三十年，看花杖屨又棲禪。", "春風不斷斯文意，噓拂衣冠著一邊。"]'),
('693439c6-a74c-4f81-a2e8-68852ac82322','東湖湯餠後進翁展墓飲嵩山踏雨泳歸在行相繼屬和蘭亭集獻之噤無半語果人情耶  其二','張埴','宋','宋诗','song-poetry','','[]','溪橋三日雨輕過，歸影蒼凉雨奈何。',32,'全唐诗/poet.song.228000.json','["溪橋三日雨輕過，歸影蒼凉雨奈何。", "詩落邙山松柏後，相看有媿少陵多。"]'),
('3d5a7b0b-88e4-4ce0-ac0c-e72e219b1df0','西州訪舊諸公皆沿檄去偕江一父過郎官湖賦此','張埴','宋','宋诗','song-poetry','','[]','一池漢水秀可餐，十年借我江南看。',80,'全唐诗/poet.song.228000.json','["一池漢水秀可餐，十年借我江南看。", "陰山夜半黑風起，此水與我心都寒。", "可惜野狐不革面，當來棲鳳俱生翰。", "湖亭謝荷著句穩，霜月記憶浮杯寬。", "端期歲晚同不朽，報答地主老郎官。"]'),
('483026f8-0f96-45de-8377-6956c110d067','杜園九日紅梅主人以爲瑞彭潜心索賦','張埴','宋','宋诗','song-poetry','','[]','鞠後西風醉飲醇，醖香釀影奪初春。',64,'全唐诗/poet.song.228000.json','["鞠後西風醉飲醇，醖香釀影奪初春。", "幾年江縣依緣舊，一笑孫枝造化新。", "鈿翠半偏如意悞，鑰魚曉放守宮人。", "是誰不識花爲瑞，分寸躋攀及太真。"]'),
('570ebea4-5686-444d-be60-0f7870329d0f','春日瓶花','張埴','宋','宋诗','song-poetry','','[]','鳥鳴木陰深，魚動陂水漫。',108,'全唐诗/poet.song.228000.json','["鳥鳴木陰深，魚動陂水漫。", "燕坐南窗下，欣然得幽伴。", "盈盈菩薩面，一莞生几案。", "恍如空中墮，著我丈室看。", "地偏風日隔，香艷不耗散。", "無土種一根，他鄉得把玩。", "嬌嬈目接熟，老醜面失半。", "物忌停涵久，無嫌汲新換。", "不懷妙色身，長作如是觀。"]'),
('97cf4c88-d01c-409a-a262-6469bdffbb2c','是日歸館中作','張埴','宋','宋诗','song-poetry','','[]','一聲湖外笑掀天，誰挽楊枝艤酒船。',64,'全唐诗/poet.song.228000.json','["一聲湖外笑掀天，誰挽楊枝艤酒船。", "倚柱宛然聞鶴語，買花却不要犀錢。", "山陰擬去重爲客，路滑歸來亦悟禪。", "還訝春風無勾事，綠林吹血化杜鵑。"]'),
('98036050-1985-4da1-82d0-9aacfcc7905e','送衣還石泓弟  其一','張埴','宋','宋诗','song-poetry','','[]','十指本非捫蝨具，半生何有結鶉時。',32,'全唐诗/poet.song.228000.json','["十指本非捫蝨具，半生何有結鶉時。", "道安一矢不相及，管領歲寒吟此詩。"]'),
('4b15ebcd-8b2e-4264-bc90-435bdd075eb7','送衣還石泓弟  其二','張埴','宋','宋诗','song-poetry','','[]','所不貸人惟世道，最無窮處是天機。',32,'全唐诗/poet.song.228000.json','["所不貸人惟世道，最無窮處是天機。", "昂藏池上霜楓樹，寒冷年年著錦衣。"]'),
('ed078800-d5c1-41d3-b398-cd96affaad99','食新','張埴','宋','宋诗','song-poetry','','[]','此腹有天幸，已及新穀升。',72,'全唐诗/poet.song.228000.json','["此腹有天幸，已及新穀升。", "青瑶出爨玉，几席生光明。", "執匕不求飽，人起雞未鳴。", "六月不再雨，不裨去年耕。", "可愛善卷山，木影如水清。", "老人好擊壤，老矣擊不成。"]'),
('e69cb1d2-72c2-4015-9321-28d029930746','風雨後有懷','張埴','宋','宋诗','song-poetry','','[]','淒淒如此雨，僕僕是何人。',48,'全唐诗/poet.song.228000.json','["淒淒如此雨，僕僕是何人。", "野飯徒炊濕，泥行亦浹旬。", "斯文從古有，我輩及今貧。", "歲晚歸南郭，爲靴不用銀。"]'),
('7d904951-c2cd-499b-9773-0651852bea34','奇山在繁步二十八字迎之','張埴','宋','宋诗','song-poetry','','[]','聞有翛然一角巾，湖山雨亦動吟聲。',32,'全唐诗/poet.song.228000.json','["聞有翛然一角巾，湖山雨亦動吟聲。", "如何十里繁江路，猶待詩筒一笑迎。"]'),
('c65881e9-cebc-43f8-8e43-ab78c81fa602','贈雲留道人  其一','張埴','宋','宋诗','song-poetry','','[]','咸池沐髮扶桑晞，隻手橫捉鄧林枝。',32,'全唐诗/poet.song.228000.json','["咸池沐髮扶桑晞，隻手橫捉鄧林枝。", "楚人六月請時雨，呼喚雷公似嬰兒。"]'),
('eac06ce1-bb13-4381-9e0a-b54501708f6c','贈雲留道人  其二','張埴','宋','宋诗','song-poetry','','[]','往往諸公眼亦青，尚疑崔浩是前生。',32,'全唐诗/poet.song.228000.json','["往往諸公眼亦青，尚疑崔浩是前生。", "蚩尤墮地已爲石，且道何時見景星。"]'),
('c94ae422-632f-4345-aa88-b62e36e159f7','贈神目劉正卿','張埴','宋','宋诗','song-poetry','','[]','手撚花鬚送去春，綠陰溪曲喜逢君。',64,'全唐诗/poet.song.228000.json','["手撚花鬚送去春，綠陰溪曲喜逢君。", "相看時日愁千種，試說今年老幾分。", "馬喙信於人罕見，豺聲顧不世多聞。", "長吟莫謝寥寥意，飛過南山自看雲。"]'),
('5bba9fdc-9102-4b3d-97c7-75c1dadc5188','曾希曾見示近作賦此贈之','張埴','宋','宋诗','song-poetry','','[]','孔門言志二三子，當初獨取點而已。',256,'全唐诗/poet.song.228000.json','["孔門言志二三子，當初獨取點而已。", "聖人非棄由與求，樂在春風詠沂水。", "此意簡短幾千年，誰歟鼓瑟聲其傳。", "彼其人斯掉冷語，雖在南豐猶不然。", "乾坤清氣寧有已，一日蒼山生浪翠。", "玉局仙人喜又悲，雲妍月秀無停髓，瓣香在天老英靈。", "爲公少吐氣，雲來此山青。", "西山百年白樵戶，郵筒剝剝溪扉午。", "其發何從六一鄉，彼美人兮時十五。", "更二十五又外堂，小美不識西江路。", "何當刻日牢爲期，青葱華裾短褐衣。", "顛倒底裏入推激，蜜柱見跋更遲遲。", "吟魄隔泉應破碎，本色終然是家世。", "明日採風聞九陛，身曳錦袍長到地，此時南豐大吐氣。", "吾將擬之三語曰，後蒼山，無事莫與俗人言。"]'),
('da5c6904-def9-4621-b2e3-e160bea3e492','寄樊上友人','張埴','宋','宋诗','song-poetry','','[]','鳳凰覽德輝，鷾鴯戀庭宇。',144,'全唐诗/poet.song.228000.json','["鳳凰覽德輝，鷾鴯戀庭宇。", "吟詩已戴白，未能參此語。", "百川谷口翁，一笑輞川路。", "桃紅楊柳綠，鶑歌蝴蝶舞。", "春風吹野水，飲客如渴虎。", "夜來作老夢，鳥啼掌中僂。", "白駒千五百，樂固不償苦。", "當來漁父湄，慷慨解力處。", "賓餞十牛鳴，分寸屐齒土。", "何如歸霜崖，夜取白石煮。", "長孫汲澗水，拾薪三四五。", "日出如羊胛，家人皆可飫。"]'),
('e9099f91-c8c9-422f-b79c-bed913e8a873','寄馬竹岡','張埴','宋','宋诗','song-poetry','','[]','竹岡先生一世賢，如何斷我百十弦。',160,'全唐诗/poet.song.228000.json','["竹岡先生一世賢，如何斷我百十弦。", "苦哉幾枕黄鶴夢，天風吹到吳江邊。", "先生手提綠玉鞭，跨馿與我說去年。", "夢中記得去年別，縛雞提酒送上船。", "明年奇章觀前泊，捩手烹雞持酒酌。", "飽歌醉舞插梅花，幾夜月中記說著。", "誰知相逢劉太史，拭目雲烟新落紙。", "便從太史使之年，恁時祗謂黄河底。", "書生歡喜斯文壽，囑下楚雲樓上酒。", "菊花九日是明朝，遥望長眉三稽首。"]'),
('170eded2-ed36-4b92-894e-23aaf0bc108e','寄黄秀峰','張埴','宋','宋诗','song-poetry','','[]','春風兩眼合看花，今年却不在黄家。',200,'全唐诗/poet.song.228000.json','["春風兩眼合看花，今年却不在黄家。", "世間豈無魚羹飯，不似黄家能頓頓。", "未應南樓復南樓，江湖添個新白頭。", "午夜橫眠看星斗，玉柄摇摇似招手。", "崖公失顧第四星，使我不逢渠大明。", "忽思叔度久不見，林梢飛來果一片。", "露蟲啾唧四壁鳴，小蟲喉中亦作聲。", "太息去年十二月，秀峰先生臨去說。", "明年八月九月凉，更來樊川享秋光。", "菊花不住梅花去，去借一間茅屋住。", "霜清月冷人行街，起來教我讀簡齋。", "紅字壽安坊里路，且倩西風一傳語，木枕拳拳五更鼓。"]'),
('caf7f3fa-1c5f-46a8-bd64-00830985e4c1','寄賢齋','張埴','宋','宋诗','song-poetry','','[]','自從一摻去三千，尺宅拋來喜中年。',64,'全唐诗/poet.song.228000.json','["自從一摻去三千，尺宅拋來喜中年。", "每歎聖賢風泯矣，可憐母子日蕭然。", "悠悠蘭老離騷國，渺渺花開陽艷川。", "九月不能應十月，挂書一束放翁船。"]'),
('6f9505ab-f3ba-40bf-b986-0722d569d098','寄樊口鄭石谷','張埴','宋','宋诗','song-poetry','','[]','春日曾交問，炎天不欲書。',72,'全唐诗/poet.song.228000.json','["春日曾交問，炎天不欲書。", "亦慚吾事謬，豈願後人疏。", "古有嗤章甫，今無購子虛。", "極思樊口酒，共煮井頭魚。", "露白蒹葭冷，江清潦水除。", "年華已如此，又可膏吾車。"]'),
('89baf3d3-67d1-482c-bb67-2354b92c56c0','擬寄雪平諸兄弟及叔姪輩  其一','張埴','宋','宋诗','song-poetry','','[]','八字山前一幅巾，可堪垂白向漂淪。',64,'全唐诗/poet.song.228000.json','["八字山前一幅巾，可堪垂白向漂淪。", "平生夢寐在諸老，近者傳聞失某人。", "社日雞豚新雨淚，秋風鴻雁舊天倫。", "所期林下無窮意，護竹培花陸續春。"]'),
('8ecaeed1-ed83-4188-b5c8-9ccb89c1197d','擬寄雪平諸兄弟及叔姪輩  其二','張埴','宋','宋诗','song-poetry','','[]','桑田成海海成田，迂闊重來每自憐。',64,'全唐诗/poet.song.228000.json','["桑田成海海成田，迂闊重來每自憐。", "北道主人今似月，西江回首遠如天。", "青山千里復千里，白髮一年多一年。", "渺渺西風吹薄袂，能於骨肉不淒然。"]'),
('4a6232d3-90fc-4821-8288-387f8c94e8ec','和彭秋宇四月所唐律','張埴','宋','宋诗','song-poetry','','[]','囅聲鐵聚杯湖上，霍地金舂鏡石前。',64,'全唐诗/poet.song.228000.json','["囅聲鐵聚杯湖上，霍地金舂鏡石前。", "鳳至祗知成二老，龍眠不作可千年。", "南樓暫阻詩同賦，東郭還存履未穿。", "一段江湖真活計，阿戎肯教第三聯。"]'),
('ae02c6e2-483f-4613-89fc-dc949ffe5587','和梅溪歲晚所寄','張埴','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','客裏無魚未易禁，春風頗憶洞庭針。',32,'全唐诗/poet.song.228000.json','["客裏無魚未易禁，春風頗憶洞庭針。", "可能更問詼諧肉，髮已如今不及心。"]'),
('0a550a91-ffd8-4f79-8d8f-b061020d9e72','和舒波社日清明','張埴','宋','宋诗','song-poetry','','[]','小試麻鞋路半乾，歸來連得好詩看。',32,'全唐诗/poet.song.228000.json','["小試麻鞋路半乾，歸來連得好詩看。", "去年曾被梅花惱，今過林邊輒齒寒。"]'),
('d024dfa6-6a49-454e-9b95-06f55f4ceba5','酬劉和叔','張埴','宋','宋诗','song-poetry','','[]','兒時說伯亦吾羞，章甫何知不世謀。',64,'全唐诗/poet.song.228000.json','["兒時說伯亦吾羞，章甫何知不世謀。", "延佇群龍開日月，可堪兩鳥聒春秋。", "十年謾說江湖爾，末路唯求飽暖休。", "心事黄花同□皦，何當籬下話從頭。"]'),
('3748b7ed-f9a8-49eb-849f-f24edb94345f','酬長沙鄧壽甫','張埴','宋','宋诗','song-poetry','','[]','泉翁上下數千年，精力平生涑水然。',64,'全唐诗/poet.song.228000.json','["泉翁上下數千年，精力平生涑水然。", "白髮滿頭猶未了，青燈與影每相憐。", "書成不與無金谷，寶秘惟知有木天。", "兩夜秋窗風雨暗，老人也有可炊烟。"]'),
('8b870818-6dba-4d06-b113-3008ee581c7e','酬黄帝錫見和','張埴','宋','宋诗','song-poetry','','[]','龍髯初一振，人盡息其機。',48,'全唐诗/poet.song.228000.json','["龍髯初一振，人盡息其機。", "池靜朱華出，山凉白鳥歸。", "酒能無已已，詩豈去非非。", "仰面楚天遠，浮雲似白衣。"]'),
('b1e741e9-650f-4169-842b-bd454ea979e6','湖山館中酬謝士宜  其一','張埴','宋','宋诗','song-poetry','','[]','吾道不可東，老雁踏長雲。',48,'全唐诗/poet.song.228000.json','["吾道不可東，老雁踏長雲。", "太息復太息，青海枯成塵。", "喙短莫叫空，此物弗貸人。", "顧影正念群，一唳生湖濱。"]'),
('2650dff8-bc82-4199-a9b9-1a9869071e2c','湖山館中酬謝士宜  其二','張埴','宋','宋诗','song-poetry','','[]','春風采蘋花，悠悠萬里道。',48,'全唐诗/poet.song.228000.json','["春風采蘋花，悠悠萬里道。", "及聽負囊歌，又見騎馿好。", "羲和不停策，天地日已老。", "大笑奉美人，誰言頭白早。"]'),
('9252edaf-d653-4818-b83e-400d4c319e68','此心過酬韻','張埴','宋','宋诗','song-poetry','','[]','雨餘玉带已浮杯，未辦龐眉一笑陪。',64,'全唐诗/poet.song.228000.json','["雨餘玉带已浮杯，未辦龐眉一笑陪。", "春向五更拋我去，君從何處看花來。", "商丘大夏三十魄，白水青松大小回。", "此去政須籠短帽，瑶階領鶴恣徘徊。"]'),
('98e4f68a-cd0d-47df-adc8-b13043c2a886','答彭以直','張埴','宋','宋诗','song-poetry','','[]','南山歲云莫，此日別玄同。',96,'全唐诗/poet.song.228000.json','["南山歲云莫，此日別玄同。", "至今梅花句，華耀白髮翁。", "三見秋江月，何事苦縈係。", "兩夜金風生，吹清幾山桂。", "所思酹尊酒，叱鬼上車柳。", "長笑鏡石邊，更作推敲手。", "炯然此心期，相照應萬時。", "黄千不用多，拜手藏君詩。"]'),
('204dcd60-2084-4099-b746-5fdf3785a4f2','答曾清甫  其一','張埴','宋','宋诗','song-poetry','','[]','看花都是夢，聽雨甚於秋。',48,'全唐诗/poet.song.228000.json','["看花都是夢，聽雨甚於秋。", "白石年年爛，黄金日日愁。", "有餘芻一束，不足橘千頭。", "我醉如眠爾，何須百尺樓。"]'),
('b6cb5f35-26c5-4123-a677-1cfb5c17ed66','答曾清甫  其二','張埴','宋','宋诗','song-poetry','','[]','曲不聞中散，枰猶對弈愁。',48,'全唐诗/poet.song.228000.json','["曲不聞中散，枰猶對弈愁。", "相忘君象小，忍記婦眉愁。", "周版新編齒，秦箕舊會頭。", "白雲知識遠，跨海結成樓。"]'),
('4f8b2032-c377-49f0-9ab5-7cd973d8e663','答吳子登','張埴','宋','宋诗','song-poetry','','[]','閑隨川上弄晴漪，歸飲無何政謂宜。',64,'全唐诗/poet.song.228000.json','["閑隨川上弄晴漪，歸飲無何政謂宜。", "雲去但驚山朵朵，月明空想珮離離。", "高樓長笛無人聽，一日三秋有我詩。", "此意悠悠浮劍外，綠陰深處祇鶑知。"]'),
('2f5e1b9b-71d5-444a-9549-cde7c5181e31','答士宜  其一','張埴','宋','宋诗','song-poetry','','[]','老來凡事不須知，只著沖襟向聖涯。',32,'全唐诗/poet.song.228000.json','["老來凡事不須知，只著沖襟向聖涯。", "怊悵無人思禍水，一窗夜雨客談詩。"]'),
('0aabe6d1-562a-483a-b42a-fdcf59e521bb','答士宜  其二','張埴','宋','宋诗','song-poetry','','[]','書生何飾結天知，忽放晴光渺四涯。',32,'全唐诗/poet.song.228000.json','["書生何飾結天知，忽放晴光渺四涯。", "一片歸心湖草外，輕風摇艇自吟詩。"]'),
('6b3e5a7f-34b3-4bf0-92c8-880291785621','答彭秉山','張埴','宋','宋诗','song-poetry','','[]','萬里夷夏範我驅，如鴟百發一無虛。',64,'全唐诗/poet.song.228000.json','["萬里夷夏範我驅，如鴟百發一無虛。", "却呼赤手烹雙鯉，便計長竿上六魚。", "此去重看黄鶴賦，所慚未識古蒙書。", "吟身只倚春風健，道不能頗盍不蜍。"]'),
('559b3dfd-0ea3-4d5c-8dee-d901b0ea0b11','答愛吾','張埴','宋','宋诗','song-poetry','','[]','無何母子靡不足，偏提進退問爲谷。',32,'全唐诗/poet.song.228000.json','["無何母子靡不足，偏提進退問爲谷。", "閑心青山雙屬玉，江南野水連天綠。"]'),
('722ef29a-5bb1-4717-818e-08413ecf333d','再用還答得淳','張埴','宋','宋诗','song-poetry','','[]','白頭復何事，又是歲寒來。',48,'全唐诗/poet.song.228000.json','["白頭復何事，又是歲寒來。", "方爲狙謀芧，俄欣雀應梅。", "晨光搽戶牖，春意釀盆罍。", "次第湖山境，烟雲大劃開。"]'),
('64fc1271-0004-4a63-a0f5-981ae5eb7728','謝朱郎中','張埴','宋','宋诗','song-poetry','','[]','春風六轡絲，光華塞樊川。',120,'全唐诗/poet.song.228000.json','["春風六轡絲，光華塞樊川。", "川上此何日，所向生奇妍。", "金山萬丈高，但見兀在前。", "白頭分墮落，剨叫鬼擘然。", "青黄奪衆目，不認溝中捐。", "冥冥亦奚能，幅之使無遷。", "由來造化手，一種雨露偏。", "賦形大塊間，受氣小物先。", "誰意王粲孫，主人亦如天。", "買茸繡爲圖，香火長結緣。"]'),
('9613989b-c984-4522-b9b5-3fe45c969046','奉韻酬謝','張埴','宋','宋诗','song-poetry','','[]','得失無常所未論，相輝輩行幾人存。',64,'全唐诗/poet.song.228000.json','["得失無常所未論，相輝輩行幾人存。", "小山政自慚爲弟，老瓦何期飲到孫。", "橘盎且還諸老樂，梅花尤是丈人尊。", "向誰謂我翻公案，持向風流覓一樽。"]'),
('f9fd16fb-5d52-4833-b60f-4ec42e30e214','三用韻謝士安','張埴','宋','宋诗','song-poetry','','[]','清言一掬解千紛，又向名家見大君。',64,'全唐诗/poet.song.228000.json','["清言一掬解千紛，又向名家見大君。", "北海無風鵬不運，南山有雨豹能文。", "更令此手曾扶日，未必吾冠不切雲。", "鼻已辛酸復何事，天寒梅氣只心聞。"]'),
('0abfb1a2-077f-4bca-bf09-e82d62f81211','酬謝謙山所寄','張埴','宋','宋诗','song-poetry','','[]','老逐群兒去聚沙，不知桃子結西華。',64,'全唐诗/poet.song.228000.json','["老逐群兒去聚沙，不知桃子結西華。", "歸來鄉井半鬼錄，依舊湖山一會家。", "白蓋年深蝸浼浼，綠陰人靜鵲槎槎。", "江流依舊皆明德，解見南涯媒北涯。"]'),
('84a0cb3f-524f-4aab-9323-4820d33f2909','菊後','張埴','宋','宋诗','song-poetry','','[]','重來風已落，寒葉集荒階。',48,'全唐诗/poet.song.228000.json','["重來風已落，寒葉集荒階。", "豎子欺人老，先生笑道乖。", "便尋梅寄隴，無救橘逾淮。", "明日過法去，窊尊倒入懷。"]'),
('6e1be5b1-01de-4a14-bfea-fa53ed0f1773','菊花盛開','張埴','宋','宋诗','song-poetry','','[]','玉池吹醒芙蓉醉，回頭紅粉都無味。',96,'全唐诗/poet.song.228000.json','["玉池吹醒芙蓉醉，回頭紅粉都無味。", "秋宮人去金錢飛，過我茅茨若相慰。", "起來采采爲三嗅，猶是上天風露氣。", "餐英端可拔濁俗，南山在眼令人喟。", "幽人所知晚節好，歷歷青蕊開猶未。", "竹葉且與時一中，梅花後生來可畏。"]'),
('7a5dcde6-784a-4b94-b25d-36ba12901c7a','夜枕','張埴','宋','宋诗','song-poetry','','[]','春風陳榻下，夜月庾樓前。',48,'全唐诗/poet.song.228000.json','["春風陳榻下，夜月庾樓前。", "疊疊鳴檛落，翻翻警枕眠。", "祗能欹待旦，何有夢飛天。", "此意誰能解，如流二十年。"]'),
('10aa5980-975d-4ef5-9e41-3aab01788b4b','有遺搔癢之具曰不求人又曰婆指甲約相賦','張埴','宋','宋诗','song-poetry','','[]','阿婆此指甲，昆吾國生長。',180,'全唐诗/poet.song.228000.json','["阿婆此指甲，昆吾國生長。", "當年三五時，搯花記月上。", "纖纖成老大，却作爬沙狀。", "故人遠持贈，慈意有著放。", "想翁乍得之，未悟爲何貺。", "把玩至一再，醜婦能俱喪。", "信手彈三聲，錚然送妍響。", "卯醺未全快，午偃到半餉。", "溽縐垢能寸，美曝背如盎。", "是時可柄用，於人無俯仰。", "名之必可言，翁亦費亭當。", "長吟出肺肝，聞者重惆悵。", "人生七尺外，凡物皆是長。", "維此金石交，百年相倚仗。", "癡兒麻姑爪，忍痛不忍癢。"]'),
('031705bd-e9e6-41e8-810b-aa5878586567','紫霞宮聽南風操','張埴','宋','宋诗','song-poetry','','[]','促絲歷歷行泛聲，紫霞仙翁之爲琴。',66,'全唐诗/poet.song.228000.json','["促絲歷歷行泛聲，紫霞仙翁之爲琴。", "新聲不合天地意，要寫虞氏吾民心。", "嗟乎二十六字中真趣，久矣南風吹散去。", "却令紫霞宮裏翁，彈到今人未彈處。"]'),
('362f23d3-e711-4550-add2-d3205df430f2','歲晚樊口解舟','張埴','宋','宋诗','song-poetry','','[]','武昌夏口之山川，天寒不見吹簫船。',120,'全唐诗/poet.song.228000.json','["武昌夏口之山川，天寒不見吹簫船。", "短蓬推枕酒半醒，斑斑雨裏茸茸烟。", "沙頭白鳥閉目立，上下掠火交烏鳶。", "修蛇赴壑了弗顧，苟且一白春風前。", "我亦長吟上漢水，夜來參到梅花禪。", "一枝似鐵忍寒冷，一枝如玉生溫妍。", "老人無以餞歲事，只掉此舌爲辰筵。", "江湖落魄又五年。"]'),
('dd78caa8-6ef8-4d44-ad1e-77e9f238858f','解舟下石柜','張埴','宋','宋诗','song-poetry','','[]','楓蘭行楚水，標柱壓蠻烟。',48,'全唐诗/poet.song.228000.json','["楓蘭行楚水，標柱壓蠻烟。", "香火崇雙廟，茅茨入半川。", "故人及涯返，去路與天連。", "鹿鹿皆前分，悠悠又一年。"]'),
('4e01025e-8c86-475b-86e3-c885012a11d4','惠白團扇','張埴','宋','宋诗','song-poetry','','[]','藤經剡雪通姿晢，筠度湘秋刮骨清。',64,'全唐诗/poet.song.228000.json','["藤經剡雪通姿晢，筠度湘秋刮骨清。", "兩潔不容塵有污，一圓還與世無爭。", "生來肖貌難爲遁，老去揮毫豈足名。", "林下好風差自快，忍歌桃葉若爲情。"]'),
('25598516-f801-4427-92f7-12254f0a6e7a','遊桃川宮','張埴','宋','宋诗','song-poetry','','[]','瞿老亭存樹插天，靖風扶醉坐雲顛。',64,'全唐诗/poet.song.228000.json','["瞿老亭存樹插天，靖風扶醉坐雲顛。", "黔中歷歷何千狀，晉後紛紛又幾年。", "扣木不知渠是聖，入桃亦認我爲仙。", "山林摇落秋聲起，兩袂清寒一囅然。"]'),
('ce44a8e3-1060-4d80-a111-f9dead8de970','太白祠','張埴','宋','宋诗','song-poetry','','[]','翰林昭代世之雄，何止將軍走下風。',64,'全唐诗/poet.song.228000.json','["翰林昭代世之雄，何止將軍走下風。", "吟墨淋漓三極浹，酒杯傾倒五湖空。", "可憐墓草離離碧，不似袍花嫋嫋紅。", "端的騎鯨何許去，娥眉亭上問漁翁。"]'),
('3613ce46-e5d0-404f-a60c-d62d9d533728','辛未寇萊公祠','張埴','宋','宋诗','song-poetry','','[]','脫去朝衣出禁天，武陵山色識瓢仙。',64,'全唐诗/poet.song.228000.json','["脫去朝衣出禁天，武陵山色識瓢仙。", "匆匆歲月十數字，黯黯風烟二百年。", "自古難全唯晚節，至今猶洌是寒泉。", "幾人拭目宣公筆，惆悵春秋法凜然。"]'),
('05d0b261-a1c4-4264-abc3-a3ff3649a686','南康','張埴','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','彭澤鱗鱗水，匡廬漠漠烟。',48,'全唐诗/poet.song.228000.json','["彭澤鱗鱗水，匡廬漠漠烟。", "朝昏魚作市，伏臘蚌爲田。", "不共劉伶酒，惟同范蠡船。", "膊山千八百，恨未脫珉鎸。"]'),
('d2f88887-176c-463e-a2cc-093d2f3de50f','道間語  其一','張埴','宋','宋诗','song-poetry','','[]','往往騎馿走一遭，江南何處識田毛。',32,'全唐诗/poet.song.228000.json','["往往騎馿走一遭，江南何處識田毛。", "幾人歎息秋風裏，要到天河手不高。"]'),
('fac0bfa6-22ed-4938-8f09-ac88642b71f7','道間語  其二','張埴','宋','宋诗','song-poetry','','[]','蹋破雞頭要作家，豚蹄不直謂汙邪。',32,'全唐诗/poet.song.228000.json','["蹋破雞頭要作家，豚蹄不直謂汙邪。", "火輪殺盡人間物，輸乞淮南觳𧥆車。"]'),
('adb3925d-1243-430d-833d-c1b6f323a132','吳城山用東坡韻','張埴','宋','宋诗','song-poetry','','[]','半篙水映四垂山，不見年時白雨船。',32,'全唐诗/poet.song.228000.json','["半篙水映四垂山，不見年時白雨船。", "自恨闌干搔短髮，斜飛一鳥遠粘天。"]'),
('59c1b755-eb93-443b-9afd-685662afc1f2','山中','張埴','宋','宋诗','song-poetry','','[]','一笑歸來百事疏，溪山隨意葺吾廬。',64,'全唐诗/poet.song.228000.json','["一笑歸來百事疏，溪山隨意葺吾廬。", "有時臨水亦清矣，無事聽禽皆起予。", "但喜達人謀熟醉，不知論者謂因餘。", "馬蹄未踏門前路，也怕先生廢看書。"]'),
('24d80e8a-d95b-408c-a0e5-a4578183ba22','下青峰','張埴','宋','宋诗','song-poetry','','[]','僕僕淮頭路，一年西復東。',48,'全唐诗/poet.song.228000.json','["僕僕淮頭路，一年西復東。", "春風前赤壁，冬日下青峯。", "括揭叫天曙，蒹葭行夢中。", "君無矜矍鑠，我政媿龍鍾。"]'),
('36a7cccc-84b9-4dc8-b03f-3920c8bc1563','赤壁磯','張埴','宋','宋诗','song-poetry','','[]','秋清亦足發，弄水俯晴川。',48,'全唐诗/poet.song.228000.json','["秋清亦足發，弄水俯晴川。", "顧影非坡月，昂首是梵天。", "人才三國後，邊信十年前。", "吹笛歸樊口，蘆花落滿船。"]'),
('830c905f-3f1b-4f9d-862e-dc3f1283cff4','江漲和韻','張埴','宋','宋诗','song-poetry','','[]','浦溆蛟龍穴，波瀾風雨聲。',48,'全唐诗/poet.song.228000.json','["浦溆蛟龍穴，波瀾風雨聲。", "天如粘夢澤，江似覆湓城。", "此地居三孝，何人汩五行。", "囊中無白璧，不得用吾情。"]'),
('90b08bfc-0b75-42bd-95fe-89f24b7aa668','江漢','張埴','宋','宋诗','song-poetry','','[]','桃花門外三月頭，有美人兮眇中洲。',128,'全唐诗/poet.song.228000.json','["桃花門外三月頭，有美人兮眇中洲。", "泛呼木蘭寂無語，舉手相招老白鷗。", "白鷗見人頭上笠，灑灑西江雨痕濕。", "足知心事兩相忘，翻然飛出青蘋立。", "日斜何許一笛愁，西州回首望東州。", "春風吹水柳花落，不見鶴歸江上樓。", "樓前青青草尺許，中有能言兩鸚鵡。", "聲聲渾不說他人，祗謂禰衡駡黄祖。"]'),
('7a03b39d-6ade-4c70-b43b-527578418f8a','八月初四夜池上','張埴','宋','宋诗','song-poetry','','[]','池南夜觀天，斗柄長離離。',100,'全唐诗/poet.song.228000.json','["池南夜觀天，斗柄長離離。", "其間第四星，此點光猶癡。", "流空萬螢火，照我雙鬢絲。", "相待滄海月，坐到三更時。", "須臾衆色盡，造化一事奇。", "手中公瑾扇，皎然相發揮。", "風翻頭上巾，舞過池影西。", "惟有雞冠兩樹花，一笑如受纏頭歸。"]'),
('1210789b-8b51-4071-a894-98465df2168f','初夏湖山  其一','張埴','宋','宋诗','song-poetry','','[]','重臺梔子玉攢花，初夏湖山一供嘉。',32,'全唐诗/poet.song.228000.json','["重臺梔子玉攢花，初夏湖山一供嘉。", "三嗅馨香幾欲泣，年時曾食故侯瓜。"]'),
('d0bae5eb-9e2b-4f30-8f77-c44842243e07','初夏湖山  其二','張埴','宋','宋诗','song-poetry','','[]','今朝二供亦相宜，眼底忘憂粲是詩。',32,'全唐诗/poet.song.228000.json','["今朝二供亦相宜，眼底忘憂粲是詩。", "有恨春風不相待，山林著在日長時。"]'),
('a2bc7d51-556b-4d2e-993f-8568c8f0f455','初夏湖山  其三','張埴','宋','宋诗','song-poetry','','[]','三供飛來箇白鷗，炯然點破一池幽。',32,'全唐诗/poet.song.228000.json','["三供飛來箇白鷗，炯然點破一池幽。", "午陰小扇人回首，何許白蘋江上愁。"]'),
('c1868cef-da2a-4356-be5a-fa8226a72e5a','初夏湖山  其四','張埴','宋','宋诗','song-poetry','','[]','山靈渾不倦差排，四供相隨好雨來。',32,'全唐诗/poet.song.228000.json','["山靈渾不倦差排，四供相隨好雨來。", "花木成行新膏沐，麻鞋更上一層臺。"]'),
('78a1421c-d17e-4a62-93d1-0d4f0e448b8e','初夏湖山  其五','張埴','宋','宋诗','song-poetry','','[]','五供翛然可是鮮，一生只抱石頭眠。',32,'全唐诗/poet.song.228000.json','["五供翛然可是鮮，一生只抱石頭眠。", "死應不恨爲馮劍，夏日攸山二十年。"]'),
('b1d06634-42a6-4436-9a06-5aaddf670307','初夏湖山  其六','張埴','宋','宋诗','song-poetry','','[]','六供菖陽氣味真，還教繩墨百年身。',32,'全唐诗/poet.song.228000.json','["六供菖陽氣味真，還教繩墨百年身。", "幅巾清脫山風外，都等離騷說衆人。"]'),
('6254eef8-34fc-42c9-a6f7-583d2bd801f4','夏日鵠山','張埴','宋','宋诗','song-poetry','','[]','合昏枝上數花白，領略山中每日看。',32,'全唐诗/poet.song.228000.json','["合昏枝上數花白，領略山中每日看。", "閲歷春風人眼恕，相傳此法度荒寒。"]'),
('f446b8c0-7edf-467b-8e87-c07887b37522','小園桃熟','張埴','宋','宋诗','song-poetry','','[]','老子廬東信手栽，今經亂後實纍纍。',64,'全唐诗/poet.song.228000.json','["老子廬東信手栽，今經亂後實纍纍。", "天風暗拽雲裳褪，曉日濃潮酒臉回。", "向上可憐無佞處，從旁只恐有偷來。", "清晨笑摘枝頭熟，且獻千年王母杯。"]'),
('afc2e08e-c231-461b-a12e-d8901a459fdc','雞冠花  其一','張埴','宋','宋诗','song-poetry','','[]','牆東雞冠樹，傾艷爲高紅。',48,'全唐诗/poet.song.228000.json','["牆東雞冠樹，傾艷爲高紅。", "旁出數十枝，猶欲助其雄。", "赬容奪朝日，桀氣矜晚風。", "儼如鬭勝歸，歡昂出筠籠。"]'),
('c0fa02f0-2c82-4da4-9bea-c9c5ebf03730','雞冠花  其二','張埴','宋','宋诗','song-poetry','','[]','衆卉在籬下，惆悵秋光同。',36,'全唐诗/poet.song.228000.json','["衆卉在籬下，惆悵秋光同。", "老農面寸垢，滿口封培功。", "吾亦事吾事，買菊澆寒筒。"]'),
('c82b8a9d-76cd-4b11-8b48-287c70d16711','對木犀','張埴','宋','宋诗','song-poetry','','[]','楚山秋色半凄凉，誰與炊成萬粟黄。',64,'全唐诗/poet.song.228000.json','["楚山秋色半凄凉，誰與炊成萬粟黄。", "明月尚在天上本，西風未了世間香。", "猝然甚有慚羊脾，老矣何曾識蟹腸。", "若得一株紅照几，白頭今夕醉柴桑。"]'),
('6fda0bd7-ab46-4647-956c-37d47a84be87','雨後見酴醾','張埴','宋','宋诗','song-poetry','','[]','夜來一過雨，萬紅不留跡。',132,'全唐诗/poet.song.228000.json','["夜來一過雨，萬紅不留跡。", "草木是尋常，奈何春失色。", "園林肯忍耻，人眼看不得。", "向來傾艷時，天女幾奪織。", "今朝有差事，泥土蒙文飾。", "素花最後出，到骨是一白。", "東官賞其韻，居然班十客。", "著處合摇臺，殘垣不三尺。", "故家美風味，可憐六月息。", "相逢各默然，笑口不得擘。", "造化則劇耳，風簷重嗟惜。"]'),
('3b69a2ef-3206-4d29-9e5b-1518294261c7','朝陽前對紅蓼','張埴','宋','宋诗','song-poetry','','[]','不更江上伴漁翁，獨特移根一畝宮。',64,'全唐诗/poet.song.228000.json','["不更江上伴漁翁，獨特移根一畝宮。", "人見空空當北面，誰知節節受西風。", "雲衣不使通身綠，露慘能令滿意紅。", "却笑曾看齊物論，夜來燈火事匆匆。"]'),
('801145fe-6e97-4fe9-a3a7-d6b4f02e4b89','正月旦小齋觀梅','張埴','宋','宋诗','song-poetry','','[]','粗桃俗李要風光，番雨危君白玉堂。',32,'全唐诗/poet.song.228000.json','["粗桃俗李要風光，番雨危君白玉堂。", "迴首南枝春夢斷，芳心猶憶古含章。"]'),
('7956b596-b563-4879-84b2-6ef684595cd4','苦雨過玄妙池觀蓮','張埴','宋','宋诗','song-poetry','','[]','門外似攻蠹，几間如絕機。',48,'全唐诗/poet.song.228000.json','["門外似攻蠹，几間如絕機。", "飆車何處去，汗馬是誰歸。", "此日炎炎極，吾身往往非。", "有時同白羽，無語立紅衣。"]'),
('34b5fba5-82e0-456c-a582-3d03a4a8ca0c','解蒼然亭','張埴','宋','宋诗','song-poetry','','[]','蒼然亭下櫂歌聲，十里重湖第一程。',64,'全唐诗/poet.song.228000.json','["蒼然亭下櫂歌聲，十里重湖第一程。", "豈要老來遊汗漫，試扶孫去看升平。", "晴空雲退青山朗，晚渚風生白鳥輕。", "歷□舊遊班目睫，日呼穎輩識經行。"]'),
('54d930fb-42a9-4829-8901-8197bd33cc6e','十三日歸天光雲影堂','張埴','宋','宋诗','song-poetry','','[]','因緣十日坐無譁，吹盡蒲香更結跏。',64,'全唐诗/poet.song.228000.json','["因緣十日坐無譁，吹盡蒲香更結跏。", "几上玉鴝猶刮目，階前金鳳已銜花。", "且將柳浪還摩詰，莫去麻丘說子嗟。", "滿袂木陰清似水，時看跳處是蝦蟆。"]'),
('3596c6be-f272-4533-8dbf-b2b6585d87a4','西山九曲亭','張埴','宋','宋诗','song-poetry','','[]','一藜屈折入高秋，惆悵天門萬里頭。',32,'全唐诗/poet.song.228000.json','["一藜屈折入高秋，惆悵天門萬里頭。", "世路轉看無直處，黄州以後有儋州。"]'),
('a93179f1-f039-4432-9c3a-64753c74a57f','合江亭','張埴','宋','宋诗','song-poetry','','[]','踏到城隅路盡頭，烝湘兩水忽交流。',64,'全唐诗/poet.song.228000.json','["踏到城隅路盡頭，烝湘兩水忽交流。", "爐薰不斷征蠻祀，碣墨空遺責楚羞。", "石鼓無聲山落木，朱陵未覺月生洲。", "冷吟綠凈不得句，手攪天風更上樓。"]'),
('9733fbb7-c476-4fc3-897f-54eb87b7bd16','梅溪徙居吾鄉北山下  其一','張埴','宋','宋诗','song-poetry','','[]','乾坤如此我，牢落百深杯。',48,'全唐诗/poet.song.228000.json','["乾坤如此我，牢落百深杯。", "腰有難相折，頭無可以擡。", "南村元亮往，西瀼少陵來。", "書了深衣带，千金末矣哉。"]'),
('a4f269ac-a4a6-44fd-9622-5160c8d3103f','梅溪徙居吾鄉北山下  其二','張埴','宋','宋诗','song-poetry','','[]','故人爲糴罷，薄日杖藜明。',48,'全唐诗/poet.song.228000.json','["故人爲糴罷，薄日杖藜明。", "天外飛鴻影，山中落木聲。", "一枝棲月靜，萬事付雲輕。", "只指梅花畔，留橋略彴行。"]'),
('5d33ada6-8334-4605-903d-3e73fd0f4f76','梅溪徙居吾鄉北山下  其三','張埴','宋','宋诗','song-poetry','','[]','午夜貪泥飲，深村認路歸。',48,'全唐诗/poet.song.228000.json','["午夜貪泥飲，深村認路歸。", "千岐紛莫辨，一隙炯相輝。", "秋日無蓴美，春風有蕨薇。", "人生皆寓爾，惟勿此心違。"]'),
('c758ee17-3e37-4d55-a79a-68b77cb123ee','山閣','張埴','宋','宋诗','song-poetry','','[]','絳甲至今尋四百，東風吹酒楚天涯。',64,'全唐诗/poet.song.228000.json','["絳甲至今尋四百，東風吹酒楚天涯。", "有時咄咄口三唾，無事由由手一叉。", "不怨雨聲聾客耳，只愁春思亂楊花。", "弄烏此日人何往，自倚小樓娛晚霞。"]'),
('6f06de3a-632e-461f-a13c-635135d447fd','歜節南司洲驛','張埴','宋','宋诗','song-poetry','','[]','年年漂泊得康强，美景良辰每不忘。',64,'全唐诗/poet.song.228000.json','["年年漂泊得康强，美景良辰每不忘。", "千丈木蘭從夢見，一瓢菖歜在淮香。", "人生慷慨黄金短，天下升平白髮長。", "回首石橋正惆悵，小兒滿口日凉凉。"]'),
('31dbd5f4-30e7-4bb3-b84e-fb1218b87d13','果泉來館中','張埴','宋','宋诗','song-poetry','','[]','渤海刀將賣，延陵劍又來。',48,'全唐诗/poet.song.228000.json','["渤海刀將賣，延陵劍又來。", "未莎霜後鞠，已蘤臘前梅。", "有客吟今雨，何人愛古罍。", "長裾青剡剡，不但旅顔開。"]'),
('809c0ab2-df8b-4fde-ab2d-2267ac015823','劉元翁爲索賦鞠逸  其一','張埴','宋','宋诗','song-poetry','','[]','回首桃花只俗休，還君本色一籬秋。',32,'全唐诗/poet.song.228000.json','["回首桃花只俗休，還君本色一籬秋。", "小兒德祖渠何見，不認楊梅箇話頭。"]'),
('01ff2d5f-c3a4-4b01-910b-e649e463a7de','劉元翁爲索賦鞠逸  其二','張埴','宋','宋诗','song-poetry','','[]','與花叢薄且媻娑，早晚風霜亦奈何。',32,'全唐诗/poet.song.228000.json','["與花叢薄且媻娑，早晚風霜亦奈何。", "欲待太平求不死，南陽水勝上池多。"]'),
('e63dedb5-5f66-430b-86f2-9044d994e5c6','春日武昌南樓','張埴','宋','宋诗','song-poetry','','[]','客上高樓春已非，山花無語野禽啼。',64,'全唐诗/poet.song.228000.json','["客上高樓春已非，山花無語野禽啼。", "未論老子從前事，且看涪翁以後題。", "汴水悠悠雲盡處，襄州漠漠月明西。", "登臨豈是爲行樂，試倚長風聽鼓鼙。"]'),
('6ac8ab3d-0d3a-4074-8dbc-74fdcd2f80f7','劉元翁索賦雩都孫氏梅軒','張埴','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u897f\u6e56"]','冰天叫鏑交西湖，斷橋鶴去迷烟蕪。',164,'全唐诗/poet.song.228000.json','["冰天叫鏑交西湖，斷橋鶴去迷烟蕪。", "清時水月日入弄，欷歔三十餘年無。", "秋聲一夜生寥廓，晨門喜墮雲中啄。", "江南所少非秀才，誰信泰山今不索。", "庭前皴樹占百弓，相與歲寒爲春風。", "嚼爛楚人二十五，對花一笑千愁空。", "世間佳境本有數，更有玉堂在何處。", "大庾曾長老瞞欺，旁皇不敢窺門戶。", "主人軒上即送申，飛香射影到幅巾。", "雪龍背上暗摸索，何如滿身也带梨花樹下雲。"]'),
('48204660-adda-4abe-a45d-97031520172f','書萍實旅舍','張埴','宋','宋诗','song-poetry','','[]','身謀落落屠羊說，心事冥冥司馬炎。',32,'全唐诗/poet.song.228000.json','["身謀落落屠羊說，心事冥冥司馬炎。", "告訴春風無一語，江南陌上雨廉纖。"]'),
('57578f87-3db4-47ef-b394-f6188ead4de5','寄題西昌嚴後山三教堂','張埴','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高風吹斷溪橋笑，幾箇廬山昏又曉。',192,'全唐诗/poet.song.228000.json','["高風吹斷溪橋笑，幾箇廬山昏又曉。", "新開圖畫白鷗江，螭吻摇鬐到雲表。", "長廊晝永茶烟青，參禪問道談詩聲。", "蒼頭卓午汗交面，烹葵菹韭炊香粳。", "中有軒軒秀眉宇，春日藍田初過雨。", "一幅紗巾三士衣，儼然方外家人主。", "吾聞曾有奇鳶肩，亦聞曾有驚彌天。", "又曾有與花三朵，聊復爾耳能千年。", "誰信沙門頭有髮，誰信道士喉無結。", "飯盂朝貯五山雲，酒壺夕注滄海月。", "此月濯濯乎初明，此雲冉冉乎方生。", "倉之無窮飲無竭，囅聲大笑東風行。"]'),
('d2f1b797-1f9f-40c3-babb-f7be1438f90f','題鍾氏深秀樓','張埴','宋','宋诗','song-poetry','','[]','空同之頂穹雲生，吹著寶石最上層。',160,'全唐诗/poet.song.228000.json','["空同之頂穹雲生，吹著寶石最上層。", "儼驂太白跨坤立，雄雄空半危青撐。", "高人飛樓浮縹紗，滿眼清寒生窈窕。", "蒼煙白鳥出沒間，幾莟芙蓉秋漢曉。", "黄塵如霧交四陲，乃獨脫此一攬奇。", "天風午夜嘯歌歇，教人暗取寒竽吹。", "一吹吹作終南皺，濯濯春陽染曾透。", "再吹吹作琅邪圖，鬰鬰林壑描新就。", "何當祗著大口吞，清晨燕以先生盤。", "次第高舂出海門，坐我茅屋東偏看。"]'),
('d6445d13-4a89-4e77-b277-14e5866b3b23','庚午蛾眉亭  其一','張埴','宋','宋诗','song-poetry','','[]','漠漠西淮雲散，滔滔東海潮歸。',28,'全唐诗/poet.song.228000.json','["漠漠西淮雲散，滔滔東海潮歸。", "鷗鳥飛來石壁，柳花撲上人衣。"]'),
('d732f786-08b6-4260-aa7c-3a51e29b503f','庚午蛾眉亭  其二','張埴','宋','宋诗','song-poetry','','[]','月明宮袍窅窅，新沙釣艇浟浟。',28,'全唐诗/poet.song.228000.json','["月明宮袍窅窅，新沙釣艇浟浟。", "犀口不能一語，蛾眉只管千愁。"]'),
('4ab9781b-0702-4cea-96ee-71c05f18795e','由新田歸故家','張埴','宋','宋诗','song-poetry','','[]','七月景炎炎，金神令初馳。',276,'全唐诗/poet.song.228000.json','["七月景炎炎，金神令初馳。", "辰哨掩村墟，挈家向山薇。", "左手掖慈母，右手招妻兒。", "小人俱世役，誰能抱朝饑。", "舉頭赤日高，繭足荒山垂。", "慰老忽喘息，撫嬰母啼悲。", "吞聲各偷生，莫問厲階誰。", "紛紛事輕逞，梟獍忍若爲。", "性命不直土，殺戮以當戲。", "鬼妾充所歡，皇顔色戚怡。", "恢恢不罩渠，何辜及林池。", "今經用戲地，滿目腥風吹。", "少陵歸草堂，曾叱群小非。", "嗟哉夫何言，收拾聊此歸。", "此歸實天幸，團欒如去時。", "牆西老桂色，屋南佳鞠姿。", "一笑渾未忘，主人舊須眉。", "東巷去問安，茗椀重酒巵。", "北鄰了殘穫，戒婦中宵炊。", "穹昊由此正，禮樂儻可期。", "悠悠風塵中，寧不剩四支。", "未識衣裳化，何年及茅茨。", "昕昏有爲命，啜水當如飴。"]'),
('e45b5db4-f9ea-4d2b-9c62-a727e90972f7','小齋睡起','張埴','宋','宋诗','song-poetry','','[]','受用本分內，三間老茅齋。',60,'全唐诗/poet.song.228000.json','["受用本分內，三間老茅齋。", "豈無日如火，但有書能埋。", "開門烏桕影，盎水潑入懷。", "所期健拄杖，而相軟麻鞋。", "舊雨來人處，青苔生土階。"]'),
('0dcbfec8-7335-42c8-ba80-d3c6bfcb4079','過玉山莊居','張埴','宋','宋诗','song-poetry','','[]','樵路交行石，人家半住雲。',48,'全唐诗/poet.song.228000.json','["樵路交行石，人家半住雲。", "向來披野服，曾到醉山樽。", "虎跡沿坡見，雞啼隔樹聞。", "白頭離亂日，只認是桃源。"]'),
('55aeca0d-6282-477c-ad80-b6ecd9e1eb0b','登岳陽樓  其一','張埴','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','臨風把酒此何時，白首登臨亦暮遲。',32,'全唐诗/poet.song.228000.json','["臨風把酒此何時，白首登臨亦暮遲。", "一片湖光寒日裏，品題都是北來詩。"]'),
('0be4fe98-ecfe-4bea-9dce-74546aa109ff','登岳陽樓  其二','張埴','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','凍雲吹盡楚天寬，鴻去冥冥叫不還。',32,'全唐诗/poet.song.228000.json','["凍雲吹盡楚天寬，鴻去冥冥叫不還。", "饒得兩翁文墨在，至今樓上伴君山。"]'),
('98999cec-92a9-4d28-a51b-3fb975cc4fdf','登岳陽樓  其三','張埴','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','坐擁湖山把一麾，當年吏部只吟詩。',32,'全唐诗/poet.song.228000.json','["坐擁湖山把一麾，當年吏部只吟詩。", "平章功業如今許，棄了吟詩選得碑。"]'),
('8a77c4f9-bfa4-40b0-b4dd-3e9bcd41cebd','登白帝城樓','張埴','宋','宋诗','song-poetry','','[]','春取花歸去，紛紛擘柳綿。',48,'全唐诗/poet.song.228000.json','["春取花歸去，紛紛擘柳綿。", "千年漢城郭，萬里禹山川。", "西雨生新浸，東暉隔薄烟。", "客愁如峽草，生下楚臺前。"]'),
('0fde3824-a018-44ac-ad5c-d41b11ac89cb','洞庭登陸池樓','張埴','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','成陸成池噓吸間，是誰夢裏得其端。',64,'全唐诗/poet.song.228000.json','["成陸成池噓吸間，是誰夢裏得其端。", "茫乎世界虛空立，到此人生束縛寬。", "潮色龍邊塗月濕，卿心雁外抱雲寒。", "明朝又踏桃源去，所可憂兮行路難。"]'),
('dd418f28-be90-4886-9c41-749a8dac0e0f','遊青原飲息庵','張埴','宋','宋诗','song-poetry','','[]','𨸒群揭秋淺，吹醉行山阿。',72,'全唐诗/poet.song.228000.json','["𨸒群揭秋淺，吹醉行山阿。", "不放菊花開，無奈秋風何。", "三甃函冽髓，與山爲清凉。", "路人汗如雨，秋壟方驕陽。", "天雷夜劈山，暍死意猶在。", "平原如可作，世事松聲外。"]'),
('80f0fc49-ac23-4dbc-85ef-94b4744f5e66','重過楚峰驛','張埴','宋','宋诗','song-poetry','','[]','二月風光暖正妍，楚鄉醉夢忽醒然。',64,'全唐诗/poet.song.228000.json','["二月風光暖正妍，楚鄉醉夢忽醒然。", "閑隨白鳥行江上，偶爲青山立檻前。", "花影去年曾接樹，櫓聲何處未歸船。", "行湘老子喚不應，愁絕一抹村南烟。"]'),
('c09d69fa-dfde-402f-acfa-1c67e28d1b32','尚方崖赴劉次山館見過','張埴','宋','宋诗','song-poetry','','[]','梅陰踏雨拾落花，鴉鴉溪上來筍車。',160,'全唐诗/poet.song.228000.json','["梅陰踏雨拾落花，鴉鴉溪上來筍車。", "插頭林隙不敢問，怕是天落山人家。", "入門滿衣花雨濕，執手無言惟作泣。", "十年塵土不可詩，頂破飯顆山頭笠。", "呼兒剪韭爲杯盤，脫套一段春宵歡。", "連州政自厭百舌，幾語換詩春風寒。", "如今尚父何須釣，遇是青山且吟嘯。", "溪翁說到白髮今，前度桃花也陪笑。", "故人不解贈馬鞭，長吟相送吾廬前。", "丁寧傳語東道主，記得石鼎新詩聯。"]'),
('445807f7-cb26-488c-b0d3-adce6f3d9eef','遊洪山館','張埴','宋','宋诗','song-poetry','','[]','山行成興盡，泥飲得情親。',48,'全唐诗/poet.song.228000.json','["山行成興盡，泥飲得情親。", "五月瓜盤美，殊鄉雨話真。", "青雲生此屋，白髮長吾人。", "闌外浮圖立，堂堂似上賓。"]'),
('a3383169-ae16-475a-adb4-cc3d401a1c33','館中寫懷寄樂山琴庵','張埴','宋','宋诗','song-poetry','','[]','動盪六合間，是誰行春風。',120,'全唐诗/poet.song.228000.json','["動盪六合間，是誰行春風。", "萬有本天分，此氣何沖融。", "一噓著舊樹，幾朵班新紅。", "居然受巧摘，持以當晴穹。", "相期到爛熳，一笑成舂容。", "政不滿金谷，何復言錦宮。", "未嘗五日雨，人事乃爾窮。", "亦思發幽抱，求勿孤天工。", "跛履去洛陽，打拐不謂同。", "旦莫造化手，倘俠辟可衷。"]'),
('e16860c0-d89d-4465-95d1-4cb13c12e491','冬夜李仲玉寓所','張埴','宋','宋诗','song-poetry','','[]','門關晡半掩，鳥雀遠相呼。',48,'全唐诗/poet.song.228000.json','["門關晡半掩，鳥雀遠相呼。", "星宿生圭竇，春風在石爐。", "不勝親友念，有恨歲年徂。", "坐久四鄰靜，寒燈勢頗孤。"]'),
('b520297e-f911-456d-a9d8-666aa6f7dd75','寄題月潭方丈','張埴','宋','宋诗','song-poetry','','[]','嵩山古禪林，俯有潭一鏡。',108,'全唐诗/poet.song.228000.json','["嵩山古禪林，俯有潭一鏡。", "中涵片月朗，了了能見性。", "月即是圓覺，潭即是清浄。", "清浄而圓覺，何以得究竟。", "鼻端一點白，而具法眼正。", "指亡輪滅沒，千江烟相映。", "寒山叫不應，誰與足幽詠。", "衆生在黑劫，轉脚成踏暝。", "脫落衆濁源，舞影秋夜靜。"]'),
('75f85c30-f5d5-4026-8eca-54161fc8a991','小絕句  其一','張埴','宋','宋诗','song-poetry','','[]','解貂換美酒，半與美人醉。',24,'全唐诗/poet.song.228000.json','["解貂換美酒，半與美人醉。", "留半伴山翁，夜深談世事。"]'),
('c26f5ad8-8aa3-4fd1-afb5-48b3dfe9aa9d','小絕句  其二','張埴','宋','宋诗','song-poetry','','[]','人言頭上白，皆自愁中得。',24,'全唐诗/poet.song.228000.json','["人言頭上白，皆自愁中得。", "拍手笑沙鷗，滿身都是愁。"]'),
('5824eda0-ac28-4a69-bf1d-c5fb366ec2e6','讀陳公孟等伏闕書','張埴','宋','宋诗','song-poetry','','[]','世故相驅入市藍，無情公用亦難堪。',64,'全唐诗/poet.song.228000.json','["世故相驅入市藍，無情公用亦難堪。", "溫乎此豈神人肯，群也其如祖父慚。", "午夜天狐摇北斗，東風雨射滿江南。", "青山白疊仙吟處，豈不酣酣戰阿三。"]'),
('ee731bfc-fd1f-4100-ab02-efa67ba9de3e','祈雨愛蔣常請求詩','張埴','宋','宋诗','song-poetry','','[]','武夷老子黄弊衣，不能一煦誅虹霓。',242,'全唐诗/poet.song.228000.json','["武夷老子黄弊衣，不能一煦誅虹霓。", "在家顛倒來說奇，出門有請持此歸。", "龍川川上摇短藜，攔街拍手而笑之。", "六月掃空炎歊飛，厚地裂透毛可吹。", "人惟未分舂黄糜，天不下濟難息機。", "忽忽三尺在睫目，川上萬竈濃烟炊。", "我穀螺矣隨頭低，壟首日上露向晞。", "襦不及脛腰鎌誰，杜陵一飽又可期。", "只管飯顆山吟詩，不然市井含哺嬉。", "逢人手提黑羽麾，長裾短帽禿禿髭。", "嘅言人命縣一絲，造化如此人不知。", "東風排雲一致詞，呼來雷公只嬰兒。", "不妨昆明數斗泥，變化斛水爲三時。", "少爲枯槁生春熙，常清真人能爾爲。", "武夷老子黄弊衣，不能一煦誅虹霓，噫。"]'),
('565a0eb9-bb8c-498f-af41-bd940f9ccc02','書後村詩卷','張埴','宋','宋诗','song-poetry','','[]','我看後村詩，未許後生到。',228,'全唐诗/poet.song.228000.json','["我看後村詩，未許後生到。", "油然真意興，流出好懷抱。", "蜂蝶林中花，牛羊原上草。", "孤村來午饁，小澗生新潦。", "扶孫行更健，阻雨歸不早。", "買魚船迸灘，畏虎樵爭道。", "客多待荷花，田少種粳稻。", "木龍有造化，野鶴無煩惱。", "中秋月到笛，九日鞠上帽。", "東舍簾酥胸，西鄰績鬼貌。", "剖開床頭甕，澆沃腹中稿。", "對燈舞僛僛，撫几歌浩浩。", "明朝復何事，隨意足幽討。", "牆下負暄宜，臘前得白好。", "金穰心願遂，木刻足跡掃。", "此樂政無價，吾詩尤是寶。", "清風百世下，持以見郊島。", "持以見郊島，豈不一絕倒。", "豈不一絕倒，來迎玉山老。"]'),
('c3d194a5-c4f8-4e3a-aab9-626a16c5ebe3','書彭秋卷末','張埴','宋','宋诗','song-poetry','','[]','雨露悽其厚地陰，千秋宰木是衣襟。',64,'全唐诗/poet.song.228000.json','["雨露悽其厚地陰，千秋宰木是衣襟。", "君看江頭寒食日，誰不邙山路上心。", "勿剪世無嘉樹傳，相尋事有後來吟。", "相堂翁仲曾傳語，所謂天光要下臨。"]'),
('857b999c-3eed-455a-b9db-7c59497cc16b','送周叔恭遠遊','張埴','宋','宋诗','song-poetry','','[]','過眼不知騎馬幾，低頭何啻問雞三。',64,'全唐诗/poet.song.228000.json','["過眼不知騎馬幾，低頭何啻問雞三。", "舊遊巷陌春風掃，新插田疇夏雨甘。", "白首學從無季子，青山招隠有淮南。", "人生共落三千界，未去嗔癡且去貪。"]'),
('226b6ada-e01c-4c06-8f34-664755ff6f90','小軒生日  其一','張埴','宋','宋诗','song-poetry','','[]','玉宇風清金莖，露爽五日新秋。',28,'全唐诗/poet.song.228000.json','["玉宇風清金莖，露爽五日新秋。", "正好小軒相逢，初度七十邊頭。"]'),
('b7320e90-2b18-4ea7-a31c-b332b24196d6','小軒生日  其二','張埴','宋','宋诗','song-poetry','','[]','滿前白髮翛翛，抱得曾孫弄否。',28,'全唐诗/poet.song.228000.json','["滿前白髮翛翛，抱得曾孫弄否。", "從此長看星明，南極人醉西樓。"]'),
('3e72ec4b-1553-42b6-8dd8-fd53c97ada05','句','張埴','宋','宋诗','song-poetry','','[]','夜靜莫吟奇險句，恐驚明月墮波寒。',16,'全唐诗/poet.song.228000.json','["夜靜莫吟奇險句，恐驚明月墮波寒。"]'),
('6a65b040-44ab-43cd-863e-02c3efbcd42f','句','張埴客','宋','宋诗','song-poetry','','[]','無雙詩客到江干，願借明珠一顆觀。',16,'全唐诗/poet.song.228000.json','["無雙詩客到江干，願借明珠一顆觀。"]'),
('e7239b39-c041-4773-8667-7de68da0ddd4','頌古十首  其一','釋行鞏','宋','宋诗','song-poetry','','[]','玉殿苔生正不居，四臣無路納嘉謨。',32,'全唐诗/poet.song.228000.json','["玉殿苔生正不居，四臣無路納嘉謨。", "老農知是承誰力，風暖歌聲落野鉏。"]'),
('48f9ee4a-333a-4ada-9ed8-16b4d0637a8d','頌古十首  其二','釋行鞏','宋','宋诗','song-poetry','','[]','高燒榾柮暖通身，快活難禁一屋春。',32,'全唐诗/poet.song.228000.json','["高燒榾柮暖通身，快活難禁一屋春。", "不是謝郎來合火，誰知門外有寒人。"]'),
('b375d809-638c-4560-a999-a898d68dc1c5','頌古十首  其三','釋行鞏','宋','宋诗','song-poetry','','[]','領得溈山笑裏刀，方知不枉到明招。',32,'全唐诗/poet.song.228000.json','["領得溈山笑裏刀，方知不枉到明招。", "元來樹倒藤枯後，了得三年五載燒。"]'),
('ae15e046-96bf-4920-8330-539ab4cef096','頌古十首  其四','釋行鞏','宋','宋诗','song-poetry','','[]','百尺竿頭五兩垂，窮沙絕漠任風吹。',32,'全唐诗/poet.song.228000.json','["百尺竿頭五兩垂，窮沙絕漠任風吹。", "可憐無限滄浪客，猶把南針定所歸。"]'),
('c4732748-137e-4f7b-8767-6e586eb03fc8','頌古十首  其五','釋行鞏','宋','宋诗','song-poetry','','[]','柴火煎熬擔在身，相逢狹路不堪論。',32,'全唐诗/poet.song.228000.json','["柴火煎熬擔在身，相逢狹路不堪論。", "淡烟落日青山外，滿地難收刀斧痕。"]'),
('ed44659b-2701-45d9-878e-6a9d1e8cffa9','頌古十首  其六','釋行鞏','宋','宋诗','song-poetry','','[]','錯錯，戲海獰龍，沖霄遼鶴。',45,'全唐诗/poet.song.228000.json','["錯錯，戲海獰龍，沖霄遼鶴。", "老慈明，無著莫，笑裏重重露拴索。", "佛手一展日月昏，大江從此風濤惡。"]'),
('7fceee59-f086-4cd3-9133-a41df0db30e1','頌古十首  其七','釋行鞏','宋','宋诗','song-poetry','','[]','學海波瀾捲未乾，幾煩仙屐上林巒。',32,'全唐诗/poet.song.228000.json','["學海波瀾捲未乾，幾煩仙屐上林巒。", "天香吹落秋風老，不覺相携到廣寒。"]'),
('83cc7239-0a2b-4f4e-ad4e-05295e258706','頌古十首  其八','釋行鞏','宋','宋诗','song-poetry','','[]','萬德不自有，十身何處藏。',24,'全唐诗/poet.song.228000.json','["萬德不自有，十身何處藏。", "薰風生殿閣，化日正舒長。"]'),
('9d24b1ff-129c-4e51-8762-ff8679c63be3','頌古十首  其九','釋行鞏','宋','宋诗','song-poetry','','[]','白浪堆中下一鈎，錦鱗紅尾尚悠悠。',32,'全唐诗/poet.song.228000.json','["白浪堆中下一鈎，錦鱗紅尾尚悠悠。", "漁翁不計竿頭事，笑入蘆花萬頃秋。"]'),
('a1c5f435-c521-49ad-9af1-d946f96bb501','頌古十首  其一○','釋行鞏','宋','宋诗','song-poetry','','[]','恰好被人借去了，莫言鄰舍不通容。',32,'全唐诗/poet.song.228000.json','["恰好被人借去了，莫言鄰舍不通容。", "團圞無縫難安筆，只抹烟雲一兩重。"]'),
('e7d775d3-6e3f-4886-9f4f-7f33b2b47595','偈頌三首  其一','釋行鞏','宋','宋诗','song-poetry','','[]','橫眸碧漢，萬國風清。',20,'全唐诗/poet.song.228000.json','["橫眸碧漢，萬國風清。", "垂手紅塵，千峰日出。"]'),
('41228546-63c0-4359-8f7c-5b3bacec80ac','偈頌三首  其二','釋行鞏','宋','宋诗','song-poetry','','[]','山靜課花蜂股重，林空含籜筍肌明。',32,'全唐诗/poet.song.228000.json','["山靜課花蜂股重，林空含籜筍肌明。", "倚闌不覺成癡兀，又得黄鸝喚一聲。"]'),
('3bab7ed9-a592-4fb6-8e1d-4ece6cd75f44','偈頌三首  其三','釋行鞏','宋','宋诗','song-poetry','','[]','雪峰輥毬，禾山打鼓。',20,'全唐诗/poet.song.228000.json','["雪峰輥毬，禾山打鼓。", "祕魔擎叉，道吾作舞。"]'),
('01bac5f6-f059-44f7-8b80-9fc288272cd2','送空維那','釋行鞏','宋','宋诗','song-poetry','','[]','十載中原一棹還，碧琉璃外更無山。',32,'全唐诗/poet.song.228000.json','["十載中原一棹還，碧琉璃外更無山。", "扣舷三下知誰會，自作吳音唱月彎。"]'),
('8191e686-d611-4f0f-8b02-8bf23d90c9cd','句','黄申','宋','宋诗','song-poetry','','[]','一身留許國，諸子用傳家。',12,'全唐诗/poet.song.228000.json','["一身留許國，諸子用傳家。"]'),
('108461b5-ab4f-4e41-a3a2-a98c717d28be','句  其一','羅太亨','宋','宋诗','song-poetry','','[]','且追白社爲耆會，縱買黄金肯少年。',16,'全唐诗/poet.song.228000.json','["且追白社爲耆會，縱買黄金肯少年。"]'),
('7a40a1fd-8dd6-490e-b436-9fe4415e3bfc','句  其二','羅太亨','宋','宋诗','song-poetry','','[]','勢利朋儔隨處有，詩章行輩逐年無。',16,'全唐诗/poet.song.228000.json','["勢利朋儔隨處有，詩章行輩逐年無。"]'),
('64a04562-e2bd-463a-be79-854187140b3e','登瀟灑亭','錢可則','宋','宋诗','song-poetry','','[]','有緣結得南山境，瀟灑亭高最可人。',32,'全唐诗/poet.song.228000.json','["有緣結得南山境，瀟灑亭高最可人。", "此景古今吟不盡，熙熙客裏且行春。"]'),
('bb6261b0-ee97-478d-ae16-cd789adfaa63','招賢里','錢可則','宋','宋诗','song-poetry','','[]','學行文章徹九重，故旌閭里振頹風。',32,'全唐诗/poet.song.228000.json','["學行文章徹九重，故旌閭里振頹風。", "傍人莫作尋常看，幾百年中有此翁。"]'),
('b19c4154-cf75-4066-b8fe-fbfee2742a54','謝王仲儀元日書字','史吉卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','好事東君不憚勞，點妝梅柳見才高。',64,'全唐诗/poet.song.228000.json','["好事東君不憚勞，點妝梅柳見才高。", "盡輸好景資元日，故遣清齋入我曹。", "錦繡忽貽新筆墨，瓊瑶無以報瓜桃。", "春風遍染西湖綠，且滌金盃共漱醪。"]'),
('7b05e298-b1a8-48a9-91e8-0cecb7bb21d0','嚴子陵釣臺','史吉卿','宋','宋诗','song-poetry','','[]','功名束縛幾英豪，無怪先生抵死逃。',32,'全唐诗/poet.song.228000.json','["功名束縛幾英豪，無怪先生抵死逃。", "坐釣桐江一派水，清風千古與臺高。"]'),
('dfdaf40f-cc69-4365-97c7-0e7025cdd4ec','溪橋晚興','鄭協','宋','宋诗','song-poetry','','[]','寂寞亭基野渡邊，春流平岸草芊芊。',32,'全唐诗/poet.song.228000.json','["寂寞亭基野渡邊，春流平岸草芊芊。", "一川晚照人閒立，滿袖楊花聽杜鵑。"]'),
('7fc4f3ed-4eea-4ce9-9a21-15a6064a4549','錢塘晚望  其一','鄭協','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江上夜潮過，秋靜寒烟白露多。',32,'全唐诗/poet.song.228000.json','["錢塘江上夜潮過，秋靜寒烟白露多。", "吳越青山明月裏，舟人齊唱異鄉歌。"]'),
('07984671-7983-4795-95fc-83d121c117b0','錢塘晚望  其二','鄭協','宋','宋诗','song-poetry','','[]','年年如燕一還家，又訪幽居過水涯。',32,'全唐诗/poet.song.228000.json','["年年如燕一還家，又訪幽居過水涯。", "風雨滿城春欲暮，山中猶有碧桃花。"]'),
('0b520cec-5452-4738-bdce-6c9567d2106e','千頃山  其一','吳珩','宋','宋诗','song-poetry','','[]','松檜陰中六月清，異花靈草不知名。',64,'全唐诗/poet.song.228000.json','["松檜陰中六月清，異花靈草不知名。", "路從瓊液山前過，人在水晶宮上行。", "千尺翠嵐分月色，一軒寒籟動潮聲。", "登臨不厭躋攀峻，貪看雲從舄下生。"]'),
('3f72371d-87b4-4ec3-a104-00eb8a477cd9','千頃山  其二','吳珩','宋','宋诗','song-poetry','','[]','千頃山中月，三黄頂上雲。',24,'全唐诗/poet.song.228000.json','["千頃山中月，三黄頂上雲。", "相看無一語，今日喜逢君。"]'),
('052c7d86-1867-4d7a-b789-b55dc82f4617','梵安院','吳珩','宋','宋诗','song-poetry','','[]','山腰小徑細於繩，山鳥關關喜弄晴。',64,'全唐诗/poet.song.228000.json','["山腰小徑細於繩，山鳥關關喜弄晴。", "黄菊有情留客醉，白雲無事伴人行。", "野流合處堪分字，草藥拈來欲問名。", "回首渡頭詩思逸，漁舟一笛晚風清。"]'),
('64626b9c-6c66-45b6-84c9-16fb7160d6fd','法會院','吳珩','宋','宋诗','song-poetry','','[]','地占金山勝，泉分銀漢流。',48,'全唐诗/poet.song.228000.json','["地占金山勝，泉分銀漢流。", "杉篁能護翠，猿鶴似驚秋。", "祗恨登臨晚，寧辭取次游。", "列峯饒遠秀，不惜上層樓。"]'),
('c7479852-1466-4d59-bb2a-377a942aae2c','祈雨有感','史俊卿','宋','宋诗','song-poetry','','[]','亢旱田禾槁，心香禱列仙。',48,'全唐诗/poet.song.228000.json','["亢旱田禾槁，心香禱列仙。", "沛來三寸雨，感動九重天。", "却扇清無暑，揮鋤慶有年。", "神功歸大造，志喜在吟篇。"]'),
('67c1b0fc-ddb5-4430-9aaa-6dcb3b078b14','思歸寄余玠','蔣凱','宋','宋诗','song-poetry','','[]','病覺腰金重，君恩報已辜。',48,'全唐诗/poet.song.228000.json','["病覺腰金重，君恩報已辜。", "髮從秋後落，花向雨中疎。", "詩禮堪誰倚，山川頼有圖。", "百年心裏事，漁釣老江湖。"]'),
('45d3b0d8-1bcc-4544-9ab6-05fd1ed80e64','秦淮','劉元高','宋','宋诗','song-poetry','','[]','橫鑿南山貫北津，安知豐沛有真人。',32,'全唐诗/poet.song.228000.json','["橫鑿南山貫北津，安知豐沛有真人。", "六朝不得中原土，猶使英雄欲過秦。"]'),
('fd7ee29a-dd34-4b86-8567-fd323e0b167d','冶城樓','劉元高','宋','宋诗','song-poetry','','[]','俯仰明知盡可悲，西風還此立多時。',32,'全唐诗/poet.song.228000.json','["俯仰明知盡可悲，西風還此立多時。", "偶然喚醒東山客，便有淮淝一局棋。"]'),
('49fc31cf-b3af-49cd-8aa0-a56caee362f7','岳王墓','林泳','宋','宋诗','song-poetry','','[]','天意只如此，將軍足可傷。',48,'全唐诗/poet.song.228000.json','["天意只如此，將軍足可傷。", "忠無身報主，冤有骨封王。", "苔雨樓牆暗，花風廟路香。", "沉思百年事，揮淚灑斜陽。"]'),
('3aa891cc-2f88-4b32-98b0-a183f5a8c7f2','寒食','蔣夢炎','宋','宋诗','song-poetry','','[]','不暖不寒寒食天，小橋楊柳未飛綿。',64,'全唐诗/poet.song.228000.json','["不暖不寒寒食天，小橋楊柳未飛綿。", "三分春色一分在，十日晴無兩日全。", "桐角喚回前嶂曉，子規啼破隔江烟。", "麻裙素髻誰家女，哭向墦間送紙錢。"]'),
('48891d2d-bc47-4332-9e15-cd3f9699412c','鄴都','陳昌言','宋','宋诗','song-poetry','','[]','山勢崔嵬望太行，星軺迢遞過臨漳。',64,'全唐诗/poet.song.228000.json','["山勢崔嵬望太行，星軺迢遞過臨漳。", "華林園廢花爭發，銅雀臺空草自芳。", "何必三分誇霸業，獨憐千古擅文章。", "生逢亂世終非幸，疑冢纍纍挂夕陽。"]'),
('42e17021-a1cc-44d2-8d13-c671aeeaf552','狀元峰','歐陽麟','宋','宋诗','song-poetry','','[]','一峰高聳上參天，地勢鍾靈出狀元。',64,'全唐诗/poet.song.228000.json','["一峰高聳上參天，地勢鍾靈出狀元。", "雪霽乍疑抽紫笋，雲開忽見吐青蓮。", "平明遠捧金烏小，薄暮高擎玉兔圓。", "獨羨唐家賢父子，芳名留得後人傳。"]'),
('8aed2eb5-79a1-42a9-a7d9-69e00f65ff7e','疏山','曾淵子','宋','宋诗','song-poetry','','[]','草徑蜿蜒十里間，雲間若在畫圖看。',32,'全唐诗/poet.song.228000.json','["草徑蜿蜒十里間，雲間若在畫圖看。", "萬松密翠地無影，一水長清空自寒。"]'),
('4f69c98e-6bc6-4693-8cec-5892af9960b7','九日登翰苑臺','曾淵子','宋','宋诗','song-poetry','','[]','翰苑臺邊拂舊題，歲華荏苒壯心違。',64,'全唐诗/poet.song.228000.json','["翰苑臺邊拂舊題，歲華荏苒壯心違。", "看萸喜得親長健，對菊猶慚令未歸。", "秋水一江鷗共瘦，雲山千里雁初飛。", "宦情有暇無風雨，把酒相酬此會稀。"]'),
('a7630996-077f-440f-a1cb-44930ad72af2','漳南示義軍寄邑人譚野臣','曾淵子','宋','宋诗','song-poetry','','[]','漳州城南烟霧深，漳州城北氛氣侵。',224,'全唐诗/poet.song.228000.json','["漳州城南烟霧深，漳州城北氛氣侵。", "憶從奸邪賣和議，漢廷君臣愁至今。", "乘輿播遷天地怒，殘軍掩泣眠星霧。", "黄金無收白骨多，指點枯骸擬親故。", "昨夜羽書如電飛，報道三城又被圍。", "皇家恩深重如山，英雄奮起披鐵衣。", "萬人同心猛如虎，關山震動撾鼙鼓。", "百戰須當百勝歸，凱歌唱滿中原土。", "論功賞爵將憲章，汾陽異姓封侯王。", "鞠躬盡瘁固常事，願教一湧殲豺狼。", "莫上高樓偶長望，壯懷忽忽思鄉丈。", "琴臺落日私語時，丹心耿耿今能忘。", "惜君忠義老無官，山河破裂泪欲乾。", "衰容未畫麒麟閣，目盡故園心轉酸。"]'),
('faec0a4f-0139-40c5-8654-360bac3dcbd0','客安南見進奉使回口占','曾淵子','宋','宋诗','song-poetry','','[]','安南莫道是天涯，歲歲人從薊北回。',32,'全唐诗/poet.song.228000.json','["安南莫道是天涯，歲歲人從薊北回。", "江北江南親故滿，三年不寄一書來。"]'),
('466f174e-4d78-449b-9486-1434c1f324ee','咸淳戊辰餘月下澣去郡歸里因訪菊巖龔先生用平舟楊公韻題蓬山堂泉石','洪濤','宋','宋诗','song-poetry','','[]','人生囂塵中，幾若駒過隙。',24,'全唐诗/poet.song.228000.json','["人生囂塵中，幾若駒過隙。", "安得坐此山，枕流復漱石。"]'),
('471c6f20-6508-488e-b77b-1a8f14c0e08a','賦將軍木','王執禮','宋','宋诗','song-poetry','','[]','脫急曾聞匿異人，論功僅得號將軍。',32,'全唐诗/poet.song.228000.json','["脫急曾聞匿異人，論功僅得號將軍。", "長身已逐雲烟去，頼有孫枝記舊勳。"]'),
('6dde6c13-d889-4364-895a-9bb49adb267e','遊玉仙諸洞戲題碧雲石崖','王執禮','宋','宋诗','song-poetry','','[]','已從鹿巖遊，更入龍洞去。',132,'全唐诗/poet.song.228000.json','["已從鹿巖遊，更入龍洞去。", "橫足螃蟹行，連臂猿猱度。", "滑徑鏗蠟屐，陰崖然樺炬。", "振策扶顛隮，捫蘿猛攀附。", "塗險幾欲窮，境勝忽有遇。", "谽谺通石竇，參差流玉乳。", "形開趣彌深，興集理自裕。", "便將遺世紛，且復恣幽步。", "紆餘窮冥搜，淹留迫頹暮。", "題詩識蒼壁，聊寫心迹素。", "重遊豈無期，恐忘來時路。"]'),
('3c843eae-9e0e-4d8b-bffd-ede35fd8011f','湖山紀遊','王執禮','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳山東南秀，葱鬰盤帝城。',288,'全唐诗/poet.song.228000.json','["吳山東南秀，葱鬰盤帝城。", "西湖據其趾，御氣通波心。", "餘膏被草木，蔚眼皆欣榮。", "□晨天宇穆，惠風汎初晴。", "春色正妍妙，放懷共揚舲。", "中流入汗漫，曠闊無埃氛。", "湖光挾山淥，倒射玻璃青。", "絲管響空翠，樓觀森崢嶸。", "獻酬雜歌嘯，爛漫紛醉醒。", "取樂固莫並，興懷一何深。", "緬惟昔三賢，精爽日以沈。", "但餘畫像在，尚想鳴佩襟。", "希古秉微尚，崇雅攄恬情。", "羌予翳蓬藋，無復企組纓。", "淡泊自有得，榮華非所欣。", "舍舟縱散策，逸興生崚嶒。", "白雲引遐眺，碧岫延深登。", "幽期浩無涯，忽到靜者門。", "長松有令姿，流水無俗聲。", "絕磴猿可呼，出谷鶑始鳴。", "乃知物外境，茲象本不驚。", "逝耶初無將，至耶亦無迎。", "便將謝塵鞅，茲焉支頹齡。", "山鴉接晚翅，落日催行縢。"]'),
('1b0e4745-8087-46dd-92bf-74020381863d','錦溪次趙令韻二首  其一','王執禮','宋','宋诗','song-poetry','','[]','微雲淡日半昏明，初換春衫步屧輕。',32,'全唐诗/poet.song.228000.json','["微雲淡日半昏明，初換春衫步屧輕。", "行到小橋幽絕處，朗吟詩句答溪聲。"]'),
('8ffd5ba9-489d-4fc8-8f3c-1dddf388070f','錦溪次趙令韻二首  其二','王執禮','宋','宋诗','song-poetry','','[]','困人天氣近清明，花信風來拂面輕。',32,'全唐诗/poet.song.228000.json','["困人天氣近清明，花信風來拂面輕。", "屏却鳴騶成獨往，綠楊陰裏聽鶑聲。"]'),
('b74a42a9-b1fe-44d6-a410-b86d77b69bed','遊錢王太廟','王執禮','宋','宋诗','song-poetry','','[]','數間老屋半欹頹，宗祏雖存沒草萊。',64,'全唐诗/poet.song.228000.json','["數間老屋半欹頹，宗祏雖存沒草萊。", "尚有遺民呼太廟，可堪游鹿上荒臺。", "花開陌路空餘恨，麥被陵陂不盡哀。", "三節還鄉平日志，化爲杜宇定歸來。"]'),
('a7f5490a-c7cd-4df2-9e8b-3e29385654d0','觀儺','劉鏜','宋','宋诗','song-poetry','','[]','寒雲岑岑天四陰，畫堂燭影紅簾深。',384,'全唐诗/poet.song.228000.json','["寒雲岑岑天四陰，畫堂燭影紅簾深。", "鼓聲淵淵管聲脆，鬼神變化供劇戲。", "金漥玉注始淙潺，眼前倏已非人間。", "夜叉蓬頭鐵骨朵，赭衣藍面眼迸火。", "魆蜮罔象初偋伶，跪羊立豕相嚘嚶。", "紅裳姹女掩蕉扇，綠綬髯翁握蒲劍。", "翻筋踢斗臂膊寬，張頤吐舌唇吻乾。", "摇頭四顧百距躍，斂身千態萬斝索。", "青衫舞蹈忽屏營，采雲揭帳森麾旌。", "紫衣金章獨據案，馬䰎牛權兩披判。", "能言禍福不由天，躬履率越分愚賢。", "蒺藜奮威小甶服，䰐縿揚聲大髽哭。", "白面使者竹筱鎗，自誇搜捕無遺藏。", "牛冠箝卷試閲檢，虎冒肩戟光睒閃。", "五方點隊亂紛紜，何物老嫗繃獶熏。", "終南進士破鞮絝，嗜酒不悟鬼看覷。", "奮髯瞠目起婆娑，衆邪一正將那何。", "披髮將畢飛一吷，風捲雲收鼓簫歇。", "夜闌四坐慘不怡，主人送客客盡悲。", "歸來桃茢坐深蕳，翠鴞黄狐猶在眼。", "自歌楚些大小招，坐久魂魄游逍遥。", "會稽山中禹非死，鑄鼎息壤乃若此。", "又聞鬼姦多馮人，人姦馮鬼姦入神。", "明日冠裳好妝束，白晝通都人面目。"]'),
('8bd8bbe3-9804-4374-a84b-08afbd2c0976','詠陳後主','劉鏜','宋','宋诗','song-poetry','','[]','晉王前殿賀平陳，從此江南雨露均。',32,'全唐诗/poet.song.228000.json','["晉王前殿賀平陳，從此江南雨露均。", "四百年間重混一，誰知江令是忠臣。"]'),
('0de656fc-f6cc-4af9-82f2-4590c87e4789','句  其一','劉鏜','宋','宋诗','song-poetry','','[]','孔曾有道官天下，韓柳無文世子孫。',16,'全唐诗/poet.song.228000.json','["孔曾有道官天下，韓柳無文世子孫。"]'),
('227b1f68-9e6a-4a10-bfa7-101279815e14','句  其二','劉鏜','宋','宋诗','song-poetry','','[]','村橋日落市聲散，山路月明人語歸。',16,'全唐诗/poet.song.228000.json','["村橋日落市聲散，山路月明人語歸。"]'),
('daffd041-b99d-428a-88b2-16846a9461e9','句  其三','劉鏜','宋','宋诗','song-poetry','','[]','月下有聞思望帝，山中無曲舞胎仙。',16,'全唐诗/poet.song.228000.json','["月下有聞思望帝，山中無曲舞胎仙。"]'),
('dc39287b-4744-4890-bcc9-c6e787eaaefa','句  其四','劉鏜','宋','宋诗','song-poetry','','[]','版橋雨過秋苔滑，村碓寒吹暴稻香。',16,'全唐诗/poet.song.228000.json','["版橋雨過秋苔滑，村碓寒吹暴稻香。"]'),
('8354687a-28bd-4916-855e-529a409e2d88','句  其五','劉鏜','宋','宋诗','song-poetry','','[]','尊前能是幾時客，山下已成千古墳。',16,'全唐诗/poet.song.228000.json','["尊前能是幾時客，山下已成千古墳。"]'),
('0d7911c5-8602-4c45-91cb-aa472afa0266','句  其六','劉鏜','宋','宋诗','song-poetry','','[]','柳條風慢天初暖，花影晴光地亦香。',16,'全唐诗/poet.song.228000.json','["柳條風慢天初暖，花影晴光地亦香。"]'),
('75db87a3-9290-4f39-86a2-ecfd98e9129e','句  其七','劉鏜','宋','宋诗','song-poetry','','[]','故人皆死誰爲佛，老我猶生即是仙。',16,'全唐诗/poet.song.228000.json','["故人皆死誰爲佛，老我猶生即是仙。"]'),
('21cd76e5-e69f-4482-b7bb-3de1097598f1','句  其八','劉鏜','宋','宋诗','song-poetry','','[]','草隥水流襜佩響，松梢月冷露珠圓。',16,'全唐诗/poet.song.228000.json','["草隥水流襜佩響，松梢月冷露珠圓。"]'),
('e67c3c4f-7387-4006-8f1c-f410d2fe1fe1','句  其九','劉鏜','宋','宋诗','song-poetry','','[]','幾番雨過山仍在，獨望人間鶴未歸。',16,'全唐诗/poet.song.228000.json','["幾番雨過山仍在，獨望人間鶴未歸。"]'),
('e8dc127b-b1ec-49ad-a8c5-10b8feebef3b','宿袁州楓林邸','柴隨亨','宋','宋诗','song-poetry','','[]','維舟烟柳外，風健布帆輕。',48,'全唐诗/poet.song.228000.json','["維舟烟柳外，風健布帆輕。", "雁過家千里，鵑啼月五更。", "山川行客夢，風雨故鄉情。", "問宿楓林晚，袁州第一程。"]'),
('c0cfb646-24e3-439e-87fd-d5758cc90d4c','旅舍聽雨','柴隨亨','宋','宋诗','song-poetry','','[]','夜長難得寐，況復雨淋淫。',48,'全唐诗/poet.song.228000.json','["夜長難得寐，況復雨淋淫。", "百事不如意，一時都上心。", "客程歧路遠，歸興海濤深。", "頼有東林社，招摇賦賞音。"]'),
('689745e9-f94b-4cfe-be9a-dca46108611e','題白雲庵','柴隨亨','宋','宋诗','song-poetry','','[]','散策入禪扉，愁城酒解圍。',48,'全唐诗/poet.song.228000.json','["散策入禪扉，愁城酒解圍。", "泥黄肥客屨，雲淡護僧衣。", "心事溪相照，吟情雨带歸。", "未盟泉石隠，林鶴背人飛。"]'),
('32aef092-e13a-4da9-905a-4b2674388285','偶倚','柴隨亨','宋','宋诗','song-poetry','','[]','西風獨憑闌干處，可是愁人鬢易華。',64,'全唐诗/poet.song.228000.json','["西風獨憑闌干處，可是愁人鬢易華。", "老木不生秋後葉，孤燈空結夜來花。", "中原落日無歸雁，故國青山有去鴉。", "欲向清尊消舊恨，路迷行客正思家。"]'),
('ecd784d7-bdc7-4abb-82ea-d27584349521','江行即事','柴隨亨','宋','宋诗','song-poetry','','[]','讀罷騷經手自抄，紉蘭歸計勝誅茅。',64,'全唐诗/poet.song.228000.json','["讀罷騷經手自抄，紉蘭歸計勝誅茅。", "新蠶食葉將成繭，舊燕銜泥旋補巢。", "菜老花隨黄麥落，草長色與綠楊交。", "一春過盡三之二，閒倚東風憶孟郊。"]'),
('7fe94a8a-bbfb-486c-96be-9959d5353b49','過道州謁周濂溪故居','柴隨亨','宋','宋诗','song-poetry','','[]','迢迢豸嶺水縈紆，知是元公此結廬。',64,'全唐诗/poet.song.228000.json','["迢迢豸嶺水縈紆，知是元公此結廬。", "老屋至今圖太極，古碑猶在勒通書。", "落花啼鳥春無恙，窗草池蓮景自如。", "閒立釣游磯上石，光風霽月滿庭除。"]'),
('985c86f6-b31f-4cd5-a206-27332d05e71d','晚春即事','柴隨亨','宋','宋诗','song-poetry','','[]','又見東風吹路塵，傷心紅紫易因循。',64,'全唐诗/poet.song.228000.json','["又見東風吹路塵，傷心紅紫易因循。", "杜鵑啼歇三更雨，燕子銜歸一半春。", "近水夕陽憑遠樹，東家飛絮落西隣。", "小舟撐出前村去，忽聽人聲不見人。"]'),
('db7d7b47-fe41-4c9e-964d-583c388b3937','越鎮山樓','柴隨亨','宋','宋诗','song-poetry','','[]','百尺闌干最上頭，杯中旗影動奎婁。',64,'全唐诗/poet.song.228000.json','["百尺闌干最上頭，杯中旗影動奎婁。", "海通蠻島三千國，山鎮東南數百州。", "草木更含天子氣，衣冠不洗晉人羞。", "舊來越戰吳爭事，一曲漁歌起暮鷗。"]'),
('ce039263-1241-490d-9022-f69391f2ed23','客中春晚','柴隨亨','宋','宋诗','song-poetry','','[]','依依官柳暗關情，況復聽人唱渭城。',64,'全唐诗/poet.song.228000.json','["依依官柳暗關情，況復聽人唱渭城。", "半夜客樓聞杜宇，一年春事又清明。", "帆開別浦潮如雪，花落東風雨又晴。", "光景不留人老去，浮生空自歎雲萍。"]'),
('769ff40e-8d6f-4d71-8332-784c82424e06','金陵懷古','柴隨亨','宋','宋诗','song-poetry','','[]','夢覺鍾山夜半鐘，自憐寒月照山翁。',64,'全唐诗/poet.song.228000.json','["夢覺鍾山夜半鐘，自憐寒月照山翁。", "曲從玉樹歌聲斷，數逐金陵王氣終。", "故老更思王化北，南人惟唱大江東。", "憑闌不見豪華事，只是江豚夜起風。"]'),
('3406857e-91b3-4e67-8af6-2cddf6623c0e','春詞','柴隨亨','宋','宋诗','song-poetry','','[]','采蘩春日詠遲遲，何事于今詠黍離。',64,'全唐诗/poet.song.228000.json','["采蘩春日詠遲遲，何事于今詠黍離。", "夜到子中分旦氣，歲從寅上授人時。", "野花啼鳥般般意，流水孤村岸岸移。", "且向醉中歌一曲，自憐吾及共吾兒。"]'),
('497da139-24aa-4662-bc55-08be911b602d','偶題','柴隨亨','宋','宋诗','song-poetry','','[]','人世陰晴了未知，一僮一鶴自相隨。',64,'全唐诗/poet.song.228000.json','["人世陰晴了未知，一僮一鶴自相隨。", "已無少小尊前夢，惟有老來亂後詩。", "花落鳥啼眠幾覺，水流雲散醒多時。", "蟠桃結實三千歲，知熟黄粱幾度炊。"]'),
('39af67ad-8f35-4990-9346-af2cc2a57fd8','和姜居仁感時韻','柴隨亨','宋','宋诗','song-poetry','','[]','十年泉石痼煙霞，吟看浮榮過眼花。',64,'全唐诗/poet.song.228000.json','["十年泉石痼煙霞，吟看浮榮過眼花。", "歸去五株彭澤柳，困來七椀玉川茶。", "功名得失藏蕉鹿，身世糊塗篆壁蝸。", "我亦厭喧求靜者，故園且種邵平瓜。"]'),
('b76641d8-56fc-4524-afad-5ec168db9208','感題','柴隨亨','宋','宋诗','song-poetry','','[]','伯夷恥周粟，仲連豈帝秦。',24,'全唐诗/poet.song.228000.json','["伯夷恥周粟，仲連豈帝秦。", "清風千載上，林下一閒身。"]'),
('7e8cd8d2-46be-4b91-a838-0c43bc3c07bb','昭君圖','柴隨亨','宋','宋诗','song-poetry','','[]','紅顔雖命薄，猶是漢宮人。',24,'全唐诗/poet.song.228000.json','["紅顔雖命薄，猶是漢宮人。", "一上玉關道，天涯淪落身。"]'),
('06be8064-da56-4486-94b1-f39df049fd2c','九日客金陵','柴隨亨','宋','宋诗','song-poetry','','[]','菊雨凄凄江露凉，客中無酒對重陽。',32,'全唐诗/poet.song.228000.json','["菊雨凄凄江露凉，客中無酒對重陽。", "去年黑髮今年白，不似黄花歲歲黄。"]'),
('0ce41614-0269-42bd-8184-09a8acf76be4','春日','柴隨亨','宋','宋诗','song-poetry','','[]','芳草晴時春日低，櫻桃花發亂鶑啼。',32,'全唐诗/poet.song.228000.json','["芳草晴時春日低，櫻桃花發亂鶑啼。", "也應船上看山色，不似青山送馬蹄。"]'),
('f7fa25ae-60fc-45cf-bf8c-1fbd1bd92855','春詞','柴隨亨','宋','宋诗','song-poetry','','[]','爐烟爇盡冷衣篝，長樂鐘聲半入樓。',32,'全唐诗/poet.song.228000.json','["爐烟爇盡冷衣篝，長樂鐘聲半入樓。", "燕子不歸春夢斷，刺桐花月上簾鉤。"]'),
('4b93411d-c8e8-439b-9cd2-9c2be898be64','錢唐寒食','柴隨亨','宋','宋诗','song-poetry','','[]','絮花如雪草如茵，寒食清明處處春。',32,'全唐诗/poet.song.228000.json','["絮花如雪草如茵，寒食清明處處春。", "惆悵錢塘門外路，今年人哭去年人。"]'),
('13fb9d16-b380-49de-b39a-ee33b9a247b4','題趙葦江雁蕩圖','柴隨亨','宋','宋诗','song-poetry','','[]','家住溫州雁蕩巔，歸帆曾載買山錢。',32,'全唐诗/poet.song.228000.json','["家住溫州雁蕩巔，歸帆曾載買山錢。", "江山寂寂蘆花白，好似今朝紙上船。"]'),
('2d58714f-31ee-4ee7-b963-aadcd6129862','寄疊山謝年丈  其一','柴隨亨','宋','宋诗','song-poetry','','[]','幾人同抱杞天憂，戮力支撐不自由。',32,'全唐诗/poet.song.228000.json','["幾人同抱杞天憂，戮力支撐不自由。", "却恨杜鵑啼血處，楚囚相對泣難收。"]'),
('cf42e30e-a297-44bc-b3e9-71a82c133c0e','寄疊山謝年丈  其二','柴隨亨','宋','宋诗','song-poetry','','[]','短劍悲歌浙水灣，疾風吹夢到西山。',32,'全唐诗/poet.song.228000.json','["短劍悲歌浙水灣，疾風吹夢到西山。", "應知薇蕨同滋味，莫道匡時更轍環。"]'),
('d82331f3-89b3-4178-aace-31382a571653','移松','柴隨亨','宋','宋诗','song-poetry','','[]','移種青松數寸苗，俯看微小識孤標。',32,'全唐诗/poet.song.228000.json','["移種青松數寸苗，俯看微小識孤標。", "他年夭矯擎寒重，莫引閒藤上碧霄。"]'),
('a2383f3b-422e-44c8-9bf6-bbff4848c8c7','雨舂','柴隨亨','宋','宋诗','song-poetry','','[]','稻粱收盡水田空，閭舍翁嫗雨後舂。',32,'全唐诗/poet.song.228000.json','["稻粱收盡水田空，閭舍翁嫗雨後舂。", "顆粒擬輸官府稅，只留糠覈過窮冬。"]'),
('ee14b4d4-0fba-41ff-bdf6-0d4f07d2f839','喚渡','柴隨亨','宋','宋诗','song-poetry','','[]','溽風吹暑透人肌，我僕云痡我馬疲。',32,'全唐诗/poet.song.228000.json','["溽風吹暑透人肌，我僕云痡我馬疲。", "隔岸渡船呼不應，柳陰深處立多時。"]'),
('190e46b8-b27f-478c-97be-83f326e54de4','濯清','柴隨亨','宋','宋诗','song-poetry','','[]','世間何水獨流清，惟有箕山此一泓。',32,'全唐诗/poet.song.228000.json','["世間何水獨流清，惟有箕山此一泓。", "祇恨許由曾洗耳，却憐無處濯吾纓。"]'),
('c6abb139-28ad-4bb7-90fb-6c8dcefa9b47','憶昔','柴隨亨','宋','宋诗','song-poetry','','[]','憶昔長安都會地，草木晴輝鍾王氣。',192,'全唐诗/poet.song.228000.json','["憶昔長安都會地，草木晴輝鍾王氣。", "襟带江湖氣象雄，自是天王興復際。", "春風樓閣五鳳城，玉漏聲催香霧盈。", "戶外昭容鶴禁開，殿前執政鵷班行。", "柳綠桃紅湖水曲，盡日歡娛猶不足。", "畫船簫鼓繞雲深，彩仗旌旗吹月色。", "誰知世道互翻覆，滄海倏變爲桑田。", "胡笳哀怨動朝市，麋鹿來游舊陌阡。", "漢宮明妃空艷麗，苑外銅仙亦灑淚。", "古來社稷有興亡，豈識于今不平事。", "禾黍離離迹可憐，傷心回首古苔邊。", "清明寒食誰家酹，痛哭深山聞杜鵑。"]'),
('b91dea41-9e57-47d7-a717-479ebbf6d45e','和趙元鼎錢塘懷古韻','柴隨亨','宋','宋诗','song-poetry','','[]','向來錢塘歌舞地，繡鞍玉勒鳴金轡，風絡柳絲鶑織翠。',168,'全唐诗/poet.song.228000.json','["向來錢塘歌舞地，繡鞍玉勒鳴金轡，風絡柳絲鶑織翠。", "春風一曲杜韋娘，梨花窈窕歌霓裳，落花緩步弓鞋香。", "千金買笑正踟躕，回首烟浪翻五湖，禾黍傷心周大夫。", "韶聲變作笳聲長，逋梅蘇柳何凄凉，夜半呼天熱中腸。", "但見燕麥摇春風，富貴榮華一夢中，無言咄咄謾書空。", "吳越青山落照裏，銅駝陌上棲荆杞，翻思往事徒血指。", "花兮對人花轉羞，人兮對花人轉愁，花老無香人白頭。"]'),
('a5b5ad24-611f-456f-9832-24fb63da25c2','讀史感興  其一','黄文雷','宋','宋诗','song-poetry','','[]','人爲五行精，二氣相循環。',60,'全唐诗/poet.song.228000.json','["人爲五行精，二氣相循環。", "陽明發天秀，隠約超龍蟠。", "如何椒蘭芳，苦厄蕭艾繁。", "良玉必火浴，利刃因崖刓。", "大鈞雖無垠，嶽降亦甚難。"]'),
('1595e82d-ffae-4caf-812d-3dc2ecbf4430','讀史感興  其二','黄文雷','宋','宋诗','song-poetry','','[]','空山有大木，琅玕葉敷腴。',72,'全唐诗/poet.song.228000.json','["空山有大木，琅玕葉敷腴。", "末至更摧落，豈復潤朽株。", "東西四百載，天明拱黄圖。", "哀哀李杜死，諸賢亦淪胥。", "庸蜀反初燃，大厦終難扶。", "長懷追爽鳩，誰復來此居。"]'),
('e6996e2e-3879-4537-9ab2-d463b476e5a7','讀史感興  其三','黄文雷','宋','宋诗','song-poetry','','[]','典午固薄德，南風扇群污。',72,'全唐诗/poet.song.228000.json','["典午固薄德，南風扇群污。", "癡兒各翻覆，血刃起相屠。", "老羝作人語，海上生羊魚。", "山東二百州，白日棲群胡。", "更擅年代足，文皇受乾符。", "泰少否則長，豈亦天意歟。"]'),
('a15959a4-188d-474a-9a65-4603cd9a0e39','讀史感興  其四','黄文雷','宋','宋诗','song-poetry','','[]','斷鰲幾何年，八極儼不動。',72,'全唐诗/poet.song.228000.json','["斷鰲幾何年，八極儼不動。", "當是有樞紐，鐵網絡纖空。", "偷兒睨斗柄，赤手掣天棟。", "愁殺地上人，覆壓萬古痛。", "書生見事淺，十算九不中。", "豈徒書生罪，要與六籍共。"]'),
('a11372cc-691c-4cdb-bcab-91f6834521cd','讀史感興  其五','黄文雷','宋','宋诗','song-poetry','','[]','子胡譏神仙，仙人輕薄俗。',72,'全唐诗/poet.song.228000.json','["子胡譏神仙，仙人輕薄俗。", "軒冕既非榮，刀鋸况多辱。", "惟能小萬物，是以超五欲。", "棲瓊得輕安，鏤玉記華馥。", "一詠太始音，靈芝悟前夙。", "小謫未可遺，裁書繫鶴足。"]'),
('6d852d65-6981-4d57-885a-2ea2874b766e','讀史感興  其六','黄文雷','宋','宋诗','song-poetry','','[]','仙棲固多名，世但知蓬萊。',72,'全唐诗/poet.song.228000.json','["仙棲固多名，世但知蓬萊。", "九州復九州，廣大莫可該。", "翩翩牧鶴童，巧笑如嬰孩。", "授我紫玄章，歸路玉笛哀。", "蒼寒不可覓，但有清風來。", "偪仄寧久居，浮生多塵埃。"]'),
('ce35815f-0d9a-44d4-a7a6-d1ac54d77232','和陶  其一','黄文雷','宋','宋诗','song-poetry','','[]','志士方進身，恨不以羽飛。',72,'全唐诗/poet.song.228000.json','["志士方進身，恨不以羽飛。", "束縛歸山岡，竟爲人所悲。", "白楊夜蕭蕭，顧此何足依。", "百歲會有盡，智愚同所歸。", "奈此後之人，未老形已衰。", "有酒不暇飲，而恐心事違。"]'),
('e201f3a1-d974-45c3-b3be-a1caecf815f3','和陶  其二','黄文雷','宋','宋诗','song-poetry','','[]','林表有宿靄，谷鳥相啾喧。',60,'全唐诗/poet.song.228000.json','["林表有宿靄，谷鳥相啾喧。", "聽此心煩勞，啟窗西南偏。", "天氣總未佳，白雲生隴山。", "欲訪雲間人，雨至或未還。", "撥灰書且住，首肯心中言。"]'),
('c44eb636-2ef7-43e6-9743-4cd84cd5acfe','和陶  其三','黄文雷','宋','宋诗','song-poetry','','[]','黄河一再清，似是上古時。',72,'全唐诗/poet.song.228000.json','["黄河一再清，似是上古時。", "風雅久已降，後來無文辭。", "清風日淪落，世道皆如茲。", "工華不工實，此話我所疑。", "文章有心印，昔人端不欺。", "但恨智者少，吾亦少卑之。"]'),
('ccbc9696-badb-4762-9323-7677959def38','和陶  其四','黄文雷','宋','宋诗','song-poetry','','[]','上有碧松林，下有白石道。',72,'全唐诗/poet.song.228000.json','["上有碧松林，下有白石道。", "中有學仙人，自號枯松老。", "蛻身千歲餘，坐息如木槁。", "面目劇嚴冷，但道空虛好。", "袖出天甲書，意色輕鴻寶。", "此老誠可人，吾欲從師表。"]'),
('2cf48ef4-599d-4311-b0ff-6e319b142885','和陶  其五','黄文雷','宋','宋诗','song-poetry','','[]','牧牛上陽坡，角掛上下經。',72,'全唐诗/poet.song.228000.json','["牧牛上陽坡，角掛上下經。", "吳童歌且謠，旨趣皆混成。", "東西兩山間，飽見日月更。", "歸來松陰凉，夕陽滿前庭。", "黄葉從風翻，蕭颯草際鳴。", "再拜謝天公，賦此小人情。"]'),
('865cdf99-23d4-44bc-ae90-6e1e0a992165','長歌行','黄文雷','宋','宋诗','song-poetry','','[]','君不見遊塵着空生九州，人其中間懸兩眸。',211,'全唐诗/poet.song.228000.json','["君不見遊塵着空生九州，人其中間懸兩眸。", "楊花化萍無根蒂，風消水長東西流。", "紅南下濕人易老，過盡歲年還草草。", "長留白日照人間，榆柳浮生轉枯槁。", "毬紋带繞千花黄，青娥攢眉眉細長。", "莫言一尊千萬壽，乃翁身命屬渠手。", "長安城中鬼笑人，水底紙錢能不朽。", "今人不見古人心，古人不見今人事。", "天上若無長生人，即是古人都盡死。", "金鳬銀雁滿江湖，神光夜夜開黄壚。", "年經月緯三百卷，平生欲作何人書。", "古人去去留不得，我些古人三太息。", "今人莫詫山石牢，更後十年人不識。"]'),
('ec8ea380-63d3-4048-8f63-5bc1f033eb4c','觀化','黄文雷','宋','宋诗','song-poetry','','[]','屋角有蜘蛛，結網大如箕。',116,'全唐诗/poet.song.228000.json','["屋角有蜘蛛，結網大如箕。", "有來者蜻蜓，飛飛墮其圍。", "嗟汝水之生，爬沙自足嬉。", "忽然凌空遊，蜂蠆避路馳。", "一朝嬰禍羅，羽翼安所施。", "蜘蛛雖未出，狼狽已可期。", "我欲起救汝，正坐手足疲。", "噫吁嚱，悲弗悲，蜘蛛亦有黄雀隨。", "百蟲相殘人不管，人兮食人天豈知。"]'),
('b339883e-4603-4e57-8f2f-506ab1173596','歲晚歸自臨川','黄文雷','宋','宋诗','song-poetry','','[]','半世生群盜，窮年見亂離。',48,'全唐诗/poet.song.228000.json','["半世生群盜，窮年見亂離。", "出門偏念母，挾策欲干誰。", "雪重人蹤絕，山寒火氣低。", "平時來往地，滿目盡憂疑。"]'),
('f8337765-b6d4-4610-815b-ac78d93cab6b','無恙','黄文雷','宋','宋诗','song-poetry','','[]','北去初無恙，傳疑路不通。',48,'全唐诗/poet.song.228000.json','["北去初無恙，傳疑路不通。", "戈鋋亭障密，牓牘訓辭工。", "落日鳥飛急，空山花自紅。", "若爲能詛盜，桑匕斗星中。"]'),
('8b24f6b5-8062-4410-9aea-09033debba8d','題醉僧圖','黄文雷','宋','宋诗','song-poetry','','[]','僧之飲酒，地獄咫尺。',240,'全唐诗/poet.song.228000.json','["僧之飲酒，地獄咫尺。", "此僧飲酒，天龍辟易。", "僧之飲酒，背面扺諱。", "此僧飲酒，口角觱沸。", "披毛带角即不理，倒階卧路而已矣。", "一生般若幾杯湯，箇是逃禪真法子。", "不憂兜率不着渠，只憂兜率無酒酤。", "臨行自謗不羞耻，至今留與人畫圖。", "畫圖得龍眠，畫形兼畫意。", "君看阿堵中，如如元不死。", "是卧是死誰得知，手中尚記携鴟夷。", "翻河倒海不救渴，安得餘瀝流於斯。", "我觀此僧面孔真滑稽，醉中定解草聖并賦詩。", "當其幕天席地時，惜無人以筆墨隨。", "紛紛散聖今何爲，頼有一醉留其奇。", "君不見夜雨閉門難學柳下惠，又不見背水置陣古來惟有韓將軍。"]'),
('373799bc-f39d-4bd9-bdc9-a78b89d6ff5a','南紀','黄文雷','宋','宋诗','song-poetry','','[]','南紀霑王澤，涵濡已百年。',48,'全唐诗/poet.song.228000.json','["南紀霑王澤，涵濡已百年。", "故應逢小劫，何得怨蒼天。", "舊觀寧無日，浮生自可憐。", "永懷千古事，感慨淚漣漣。"]'),
('ece818a4-6c76-4daa-8b73-0705fc074666','南豐道中  其一','黄文雷','宋','宋诗','song-poetry','','[]','此縣聞天下，披圖且萬家。',48,'全唐诗/poet.song.228000.json','["此縣聞天下，披圖且萬家。", "螭頭餘佛屋，鹿角卧江沙。", "好與蘇凋瘵，誰令息歎嗟。", "春風多少意，殘竹映疏花。"]'),
('23d32e8a-a014-4f0c-868a-62c13dd00682','南豐道中  其二','黄文雷','宋','宋诗','song-poetry','','[]','此亦勤農者，畬田半入雲。',48,'全唐诗/poet.song.228000.json','["此亦勤農者，畬田半入雲。", "龍蛇因爾雜，玉石故難分。", "天地其如數，江山未返魂。", "茅茨倦行李，何自戒重門。"]'),
('1be19760-ee92-481d-9b1f-c38752076fe8','南豐道中  其三','黄文雷','宋','宋诗','song-poetry','','[]','此路通南國，于今人少行。',48,'全唐诗/poet.song.228000.json','["此路通南國，于今人少行。", "遺民依廟住，曠野用鋤耕。", "古木刀痕熟，空山鬼炎驚。", "猶聞宿師處，倉猝又招兵。"]'),
('e121ac0c-0ee4-405b-8ffe-84c615c039ab','南豐道中  其四','黄文雷','宋','宋诗','song-poetry','','[]','想見承平日，茲爲富庶鄉。',48,'全唐诗/poet.song.228000.json','["想見承平日，茲爲富庶鄉。", "門庭存位置，井臼隔垣牆。", "草市宜區種，空村又夕陽。", "誰歟真致此，盜賊已天亡。"]'),
('5fc598a5-9b33-4226-8fff-fa8ec7b932d0','南豐道中  其五','黄文雷','宋','宋诗','song-poetry','','[]','大村三伯輩，同此就天誅。',48,'全唐诗/poet.song.228000.json','["大村三伯輩，同此就天誅。", "銳欲取禾耳，那知暴骨乎。", "雲疑鵝鸛陣，風想虎狼都。", "掩骼行春令，毋令長媚狐。"]'),
('971658c5-3feb-4679-a86e-2382ccec6e67','曉行','黄文雷','宋','宋诗','song-poetry','','[]','一水來不極，兩山青欲連。',48,'全唐诗/poet.song.228000.json','["一水來不極，兩山青欲連。", "夜雨瀑初漲，曉雲路難緣。", "此寧有人跡，四顧風竹喧。", "渡橋復何歸，倚崖桃初然。"]'),
('3a3d16b7-f3c4-4287-bc43-dac48917b0d7','晚立','黄文雷','宋','宋诗','song-poetry','','[]','獨游得荒蹊，晚意與心會。',48,'全唐诗/poet.song.228000.json','["獨游得荒蹊，晚意與心會。", "水聲遠纔聞，山色靜可對。", "鳥語林塘邊，犬鳴籬落外。", "柴門未須關，月在東峰背。"]'),
('356c365e-ef76-4e6c-9846-b70f4afed8fd','古石','黄文雷','宋','宋诗','song-poetry','','[]','贔屭窗前石，參差類虎螭。',48,'全唐诗/poet.song.228000.json','["贔屭窗前石，參差類虎螭。", "秋晴蘚可剝，歲晏竹相宜。", "要自山川出，那知陵谷移。", "摩挲群玉瘦，風助馬王悲。"]'),
('a905d30f-6f71-4f8e-9f0e-92814113474c','石頭懷古','黄文雷','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江日浩浩，跂予望淮南。',132,'全唐诗/poet.song.228000.json','["長江日浩浩，跂予望淮南。", "禹畫足廣輪，王氣分殽函。", "朝市一以建，蟠踞誠匪慚。", "中躔胡塵悲，六龍此停驂。", "衣冠幸有地，喙息頼未殲。", "豈惟時賢力，要是天險參。", "頗聞京洛墟，不救狐兔饞。", "厭難故有道，往悔寧非貪。", "前登石頭路，得共北客譚。", "新秋带歸鴻，落日隨征帆。", "弔古意未厭，鼓鍾已酣酣。"]'),
('3f9cb8c0-aa6b-4337-92af-acb3b2f8af25','金陵即事  其一','黄文雷','宋','宋诗','song-poetry','','[]','東庵遺像宿塵埃，追想雞聲午夢回。',32,'全唐诗/poet.song.228000.json','["東庵遺像宿塵埃，追想雞聲午夢回。", "只與鍾山增九鼎，當時何似早歸來。"]'),
('6af2c80c-47b4-40b7-a84f-f49929ffd81d','金陵即事  其二','黄文雷','宋','宋诗','song-poetry','','[]','千年陳迹故難尋，向北山根識定林。',32,'全唐诗/poet.song.228000.json','["千年陳迹故難尋，向北山根識定林。", "丘壑獨來差可意，斷無人影古松陰。"]'),
('9c4aa651-9016-4a7a-bd51-1b53eea16d8c','金陵即事  其三','黄文雷','宋','宋诗','song-poetry','','[]','唐晉諸人骨已磨，龍蟠虎踞自山河。',32,'全唐诗/poet.song.228000.json','["唐晉諸人骨已磨，龍蟠虎踞自山河。", "可憐不共羊曇見，奈此秦淮落照何。"]'),
('2945b148-6482-42d9-800f-f816361618ae','金陵即事  其四','黄文雷','宋','宋诗','song-poetry','','[]','王謝風流自一時，長干古巷記烏衣。',32,'全唐诗/poet.song.228000.json','["王謝風流自一時，長干古巷記烏衣。", "尋常百姓幾番換，那有當年燕子飛。"]'),
('ecb56903-5287-45e3-a4f8-e74355457803','西域圖','黄文雷','宋','宋诗','song-poetry','','[]','大哉天地間，品類不可齊。',180,'全唐诗/poet.song.228000.json','["大哉天地間，品類不可齊。", "誰爲好事人，貌此縣度西。", "松花瑣碎沙草肥，是間可牧羊千蹄。", "可憐群鹿正走險，或爾剝割衣其皮。", "啜湩樹樺尚有理，穴𩕳插齒吁何爲。", "吾聞中原全盛時，重譯解辮朝京師。", "懷方象胥飭乃事，幻人詭伎何能奇。", "煌煌烈祖鑒古作，玉斧畫地分華夷。", "羌渾何者宅滎洛，蠕蠕異類方紛披。", "或爲盤瓠孫，或爲天狼妻。", "冠带之國盡狐兔，玉門萬里那得知。", "還君此畫雙涕洟，願賦周官王會詩。"]'),
('eddc8241-9972-475f-b420-7aa234a66f6a','二橋圖','黄文雷','宋','宋诗','song-poetry','','[]','翔龍下卷江東土，孫郎初得橋家女。',128,'全唐诗/poet.song.228000.json','["翔龍下卷江東土，孫郎初得橋家女。", "橋家本自重曹瞞，隻雞斗酒空酸楚。", "衿情正用留阿瑜，尚得人前稱肺腑。", "百年王氣竟銷沉，妙寫丹青嬌欲語。", "香閨搦管記何書，並蔕芙蓉按花譜。", "那知不是未嫁時，本末無從勘彤史。", "詞人多事管閑愁，銅雀紛紛底歌舞。", "儘强被髮向黄壚，只與東阿傳洛浦。"]'),
('3903639b-ab7d-40dc-a357-43411687f5fe','昭君行','黄文雷','宋','宋诗','song-poetry','','[]','君不見未央前殿羅九賓，漢皇南面呼韓臣。',163,'全唐诗/poet.song.228000.json','["君不見未央前殿羅九賓，漢皇南面呼韓臣。", "無人作歌繼大雅，至今遺恨悲昭君。", "丙殿春閑鬭馮傅，掖庭新花隔烟霧。", "票姚枉奪燕支山，玉顔竟上氈車去。", "人生流落那得知，不應畫史嫌蛾眉。", "癡心只共琵琶語，歸夢空隨鴻雁飛。", "穹廬隨分薄梳洗，世間禍福還相倚。", "上流厭人能幾時，後來燕啄皇孫死。", "野狐落中高臺傾，宮人斜邊曲池平。", "千秋萬歲總如此，誰似青冢年年青。"]'),
('7b0a484e-6f91-4365-8ee2-327773d1059b','次黄存之東皋韻  其一','黄文雷','宋','宋诗','song-poetry','','[]','藝木東臯下，新榮冒水涯。',48,'全唐诗/poet.song.228000.json','["藝木東臯下，新榮冒水涯。", "錦機分箔閙，青子亞枝斜。", "犢角初生笋，龍鬚正引瓜。", "汲清雙玉井，留客品嘗茶。"]'),
('99ccbe11-b827-4856-9961-87c08d6c0dae','次黄存之東皋韻  其二','黄文雷','宋','宋诗','song-poetry','','[]','抱膝東臯下，春風又草廬。',48,'全唐诗/poet.song.228000.json','["抱膝東臯下，春風又草廬。", "海仙將可見，溪友未宜疏。", "楷著祈年疏，閑箋種樹書。", "西山頮烟雨，容易長嘉蔬。"]'),
('6a10c1cb-6a93-4ec1-b71c-e4206d93bbd1','次黄存之東皋韻  其三','黄文雷','宋','宋诗','song-poetry','','[]','負耒東臯下，溝塍稻秫分。',48,'全唐诗/poet.song.228000.json','["負耒東臯下，溝塍稻秫分。", "汙邪爭一溉，臺笠事重耘。", "豳雅春稱壽，秦謳歲勞勤。", "無功虛作傳，農績未如君。"]'),
('ad73cb99-c832-448e-9c34-786ccb618ee1','次黄存之東皋韻  其四','黄文雷','宋','宋诗','song-poetry','','[]','挾冊東臯下，從人笑未玄。',48,'全唐诗/poet.song.228000.json','["挾冊東臯下，從人笑未玄。", "傳真秧馬帖，參透牧牛篇。", "列岫窗前月，平湖塢外烟。", "似蒙稽古力，鍾鼎豈其然。"]'),
('74df095b-4a3b-408d-846c-efa13dead655','冬郊','黄文雷','宋','宋诗','song-poetry','','[]','冬郊見初晴，空林夕陽軟。',48,'全唐诗/poet.song.228000.json','["冬郊見初晴，空林夕陽軟。", "歸牛無人驅，欲涉行轉緩。", "新藁明屋山，失喜鵲爭喚。", "絕勝門外人，流冗及歲亂。"]'),
('9de7b42a-6093-400b-95a2-a0dfa8d7b9d2','送故','黄文雷','宋','宋诗','song-poetry','','[]','履霜著餘悲，送故或古風。',48,'全唐诗/poet.song.228000.json','["履霜著餘悲，送故或古風。", "幸會草木長，土脈驗隠隆。", "共惟青鳥仙，倘亦知吾窮。", "落日起秀色，軍峯在雲中。"]'),
('3186d7ad-da14-471c-811e-fc56db538441','上天池寺  其一','黄文雷','宋','宋诗','song-poetry','','[]','蟠際均衡嶽，千峯獨出群。',48,'全唐诗/poet.song.228000.json','["蟠際均衡嶽，千峯獨出群。", "鯤鵬從水擊，翼軫驗天文。", "曠野風行雨，曾霄日貫雲。", "僧言興廢事，因念福王勳。"]'),
('1086e80a-2b9f-4c30-9c50-97c465dc9389','上天池寺  其二','黄文雷','宋','宋诗','song-poetry','','[]','始從平地望，宛在九霄中。',48,'全唐诗/poet.song.228000.json','["始從平地望，宛在九霄中。", "不意身能到，平生心併空。", "江淮通好雨，日月會剛風。", "三伏凉如水，蟠拏想白龍。"]'),
('386fa46e-1924-4163-9c1f-b88e5101f3e7','上天池寺  其三','黄文雷','宋','宋诗','song-poetry','','[]','今古無窮恨，山林只自豪。',48,'全唐诗/poet.song.228000.json','["今古無窮恨，山林只自豪。", "雲行地欲盡，風立天相高。", "靈草如堪餌，浮生計可逃。", "人間何擾擾，萬里一秋毫。"]'),
('c8b1cb54-07e3-4259-8d21-7cdd880733f0','往年因讀岳王傳嘗爲之賦今過東林睹其遺像感而申頌之  其一','黄文雷','宋','宋诗','song-poetry','','[]','將軍英爽冠人豪，眼底山河累寶刀。',64,'全唐诗/poet.song.228000.json','["將軍英爽冠人豪，眼底山河累寶刀。", "青女護香天亦悞，黑龍飲渭數何逃。", "當時僧說松楸犯，今日人推閥閲高。", "珍重王孫方鼎貴，莫將歌舞替征袍。"]'),
('9e285b2b-36eb-418c-9ea2-6c648c5cf61f','往年因讀岳王傳嘗爲之賦今過東林睹其遺像感而申頌之  其二','黄文雷','宋','宋诗','song-poetry','','[]','欲壞長城豈自由，江人重唱白符鳩。',64,'全唐诗/poet.song.228000.json','["欲壞長城豈自由，江人重唱白符鳩。", "熏天富貴還須盡，從古忠良類若仇。", "獄吏但能書牘背，相公終欲割鴻溝。", "書生志念閑無用，長想朱雲地下遊。"]'),
('293b4727-2d61-4f70-a99f-8cdc95806d19','近報  其一','黄文雷','宋','宋诗','song-poetry','','[]','入春風雨惡情懷，談柄誰資近報來。',64,'全唐诗/poet.song.228000.json','["入春風雨惡情懷，談柄誰資近報來。", "比歲時聞通國信，新年又說建行臺。", "難言鐵冶飛灰燼，易見銅駝出草萊。", "羌筦夜吹梅落盡，倚牆繚亂野花開。"]'),
('97f2c8ee-744e-475d-a3ed-5dc03a42cb32','近報  其二','黄文雷','宋','宋诗','song-poetry','','[]','青青塞草始知春，又見平林棗頰頳。',64,'全唐诗/poet.song.228000.json','["青青塞草始知春，又見平林棗頰頳。", "蛇起天津流枉矢，鳥飛淮甸覆行塵。", "漆城按堵寧辭蔭，石馬霑溝會有神。", "千古睢陽無處覓，不知臧質是何人。"]'),
('5dcf78ba-6b58-4241-8a46-e787101db62a','玉壺即事','黄文雷','宋','宋诗','song-poetry','','[]','雨過條風着柳芽，淡黄淺綠嫩如花。',64,'全唐诗/poet.song.228000.json','["雨過條風着柳芽，淡黄淺綠嫩如花。", "陂湖漾漾初侵路，蜂燕紛紛各理家。", "带郭園林仙苑近，送春船舫繡簾遮。", "芸窗倦倚何山翠，暖靄輕籠日脚斜。"]'),
('3ecea5fd-0667-44ea-b3c6-226f1030a9a0','自廣','黄文雷','宋','宋诗','song-poetry','','[]','今古紛紛孰控摶，太平方寸豁憂端。',64,'全唐诗/poet.song.228000.json','["今古紛紛孰控摶，太平方寸豁憂端。", "後千年去人何似，外九州來天更寬。", "風雨南山飛霹靂，江湖北斗掛闌干。", "要知元命真消息，滄海神龍自屈蟠。"]'),
('c4546fbf-fbe8-49a9-a6a8-1cd4f705a53c','次陳剛父見簡韻  其一','黄文雷','宋','宋诗','song-poetry','','[]','我居深山中，細哦求友篇。',48,'全唐诗/poet.song.228000.json','["我居深山中，細哦求友篇。", "解后潮海濱，得此璧一聯。", "山立古先民，期君能拍肩。", "茫茫宇宙心，楚楚東南賢。"]'),
('bc46b3ff-6dc7-4ed4-b9e0-8360ae1238a8','次陳剛父見簡韻  其二','黄文雷','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','讀書知姓名，心死非貌敬。',48,'全唐诗/poet.song.228000.json','["讀書知姓名，心死非貌敬。", "昭回不在小，中天揭西柄。", "空山三木榻，綠滿風雨徑。", "歲寒毋忘我，細意匡山詠。"]'),
('d38ae0c1-f2bf-4e6d-9a84-6f3de71fea8b','次陳剛父見簡韻  其三','黄文雷','宋','宋诗','song-poetry','','[]','呦呦苹野春，我友二三子。',48,'全唐诗/poet.song.228000.json','["呦呦苹野春，我友二三子。", "歸山睡初足，澗壑秋風起。", "一瓣無盡香，黄雲繞書几。", "別吟極雋永，形魂清九耳。"]'),
('8708c54a-43f1-44de-bd96-800a98e9eeed','挽程孺人','黄文雷','宋','宋诗','song-poetry','','[]','有煒遵彤管，無嫌各紫樞。',48,'全唐诗/poet.song.228000.json','["有煒遵彤管，無嫌各紫樞。", "清心能敏悟，雅性謝驕舒。", "奉誥期鸞彩，傳經囑鳳雛。", "妙年仙格迅，琬琰不勝書。"]'),
('f2bd682c-1fe4-4f99-8b14-f806d490be04','絕句  其一','黄文雷','宋','宋诗','song-poetry','','[]','乳燕飛飛簾影遲，不晴不雨晚春時。',32,'全唐诗/poet.song.228000.json','["乳燕飛飛簾影遲，不晴不雨晚春時。", "開窗縱目消書困，風送楊花落硯池。"]'),
('c214725c-9ffe-462f-9018-09217eb783fa','絕句  其二','黄文雷','宋','宋诗','song-poetry','','[]','琴劍平生嘆薄游，雲間春晚思如秋。',32,'全唐诗/poet.song.228000.json','["琴劍平生嘆薄游，雲間春晚思如秋。", "夢回月浸書窗冷，身在吳松江盡頭。"]'),
('640fcf39-e7c6-4c7e-b586-58c4124f5fc8','絕句  其三','黄文雷','宋','宋诗','song-poetry','','[]','一室如窩且屈蟠，稍加糊冪得心寬。',32,'全唐诗/poet.song.228000.json','["一室如窩且屈蟠，稍加糊冪得心寬。", "欲教禁足名安樂，只恐難支大暑寒。"]'),
('15d05e7c-b917-4f03-a2c0-19f7349bb3c7','絕句  其四','黄文雷','宋','宋诗','song-poetry','','[]','莫怪人言濟叔癡，東行西去又思歸。',32,'全唐诗/poet.song.228000.json','["莫怪人言濟叔癡，東行西去又思歸。", "兒童舊讀從溫故，一笑今朝到式微。"]'),
('d90c907e-44e6-4494-b595-53b7bc6769d9','東塘舟中','黄文雷','宋','宋诗','song-poetry','','[]','初識東塘路，言尋槜李船。',48,'全唐诗/poet.song.228000.json','["初識東塘路，言尋槜李船。", "魚鹽千古地，吳越一家天。", "夢覺何爲者，行藏不偶然。", "半溪疏竹影，相送海雲邊。"]'),
('d8aa7dbe-02b8-4559-a935-5da61753795f','偕周伯弜題天申宮蘇文忠公畫像','黄文雷','宋','宋诗','song-poetry','','[]','大澤沾荒裔，靈山識老臣。',48,'全唐诗/poet.song.228000.json','["大澤沾荒裔，靈山識老臣。", "微茫雲外迹，衰病瘴中身。", "濕草寒碑夕，晴花午殿春。", "高檐風雨斷，猶避六丁神。"]'),
('4e8fab28-31dc-4c5b-ad58-781854984b74','登樓有感','黄文雷','宋','宋诗','song-poetry','','[]','顧陸風流幾夕陽，桑疇麥隴自淒凉。',64,'全唐诗/poet.song.228000.json','["顧陸風流幾夕陽，桑疇麥隴自淒凉。", "山從地盡雲垂海，水共天浮日射洋。", "門卒何年隠吳市，嗇夫當日愛桐鄉。", "蟻封未敢誇榮策，芳草無人且自芳。"]'),
('6bd907e2-8e81-4ff3-9e02-5c56b955f1d7','錢氏故園  其一','黄文雷','宋','宋诗','song-poetry','','[]','幾年聞此好名圍，平地黔巫翠掃天。',32,'全唐诗/poet.song.228000.json','["幾年聞此好名圍，平地黔巫翠掃天。", "蕭岸半摧林影暗，亂螢閒自點湖烟。"]'),
('54ab8327-14dd-43c7-b996-dba3e6683875','錢氏故園  其二','黄文雷','宋','宋诗','song-poetry','','[]','中興次輔巧玲瓏，尚带承平艮嶽風。',32,'全唐诗/poet.song.228000.json','["中興次輔巧玲瓏，尚带承平艮嶽風。", "一朵慶雲飛不去，遊人眼冷夕陽中。"]'),
('5ff2c08a-1c36-4307-84ea-d232806201fa','山居','陳必復','宋','宋诗','song-poetry','','[]','接砌斜通徑，緣籬矮結牆。',48,'全唐诗/poet.song.228000.json','["接砌斜通徑，緣籬矮結牆。", "地卑蝸篆壁，山暖蜜分房。", "過雨林亭靜，落花春晝長。", "幽居差省事，猶有課詩忙。"]'),
('22161dfe-65be-49d9-8943-f53b3fdca297','領客游聞人氏省庵園','陳必復','宋','宋诗','song-poetry','','[]','半夜雨方住，一春晴不常。',48,'全唐诗/poet.song.228000.json','["半夜雨方住，一春晴不常。", "倚欄聽鳥語，開戶納花香。", "庭暮竹陰浄，池風水氣凉。", "幾番吟未穩，步月細平章。"]'),
('e4488e99-dbb7-462a-a2ea-d6b8c857f767','搆得','陳必復','宋','宋诗','song-poetry','','[]','搆得數檐椽，閒身與靜便。',48,'全唐诗/poet.song.228000.json','["搆得數檐椽，閒身與靜便。", "半簾花影碎，一樹鳥聲圓。", "吟苦瘦於舊，春寒多似前。", "閉門無客過，心事付琴邊。"]'),
('038bda7e-7c04-4c4c-ba6d-6ef7c7754d3b','百五節','陳必復','宋','宋诗','song-poetry','','[]','獨遊苦無侶，偶步到前川。',48,'全唐诗/poet.song.228000.json','["獨遊苦無侶，偶步到前川。", "春水綠於染，山花紅欲然。", "冷烟寒食月，小雨浴蠶天。", "此去嬉游少，風光又一年。"]'),
('7cbf4e71-4b31-4be9-9097-ab688b907843','贈林尚仁','陳必復','宋','宋诗','song-poetry','','[]','溪邊著吟屋，亦足老生涯。',48,'全唐诗/poet.song.228000.json','["溪邊著吟屋，亦足老生涯。", "洗硯渾池水，敲棋落案花。", "客來多載酒，童去自煎茶。", "愛爾丰標異，逢人滿口誇。"]'),
('15013f11-cd22-47ec-8af5-71227a7d3ac2','舟中得催字','陳必復','宋','宋诗','song-poetry','','[]','山郭少晴日，春陰欲釀梅。',48,'全唐诗/poet.song.228000.json','["山郭少晴日，春陰欲釀梅。", "岸痕新雨過，島色曉雲開。", "數鳥烟中落，一帆天外來。", "溪行正如畫，頻報長年催。"]'),
('5da71293-b01d-4f26-bb72-694cd8f0869f','客枕','陳必復','宋','宋诗','song-poetry','','[]','客枕偏饒睡，春歸尚擁綿。',48,'全唐诗/poet.song.228000.json','["客枕偏饒睡，春歸尚擁綿。", "屋深燈易暈，漏短夢難圓。", "棲鳥警凉夜，閙蛙喧雨天。", "一聲柔櫓過，何處上溪船。"]'),
('f70d4be6-313e-497c-a0ff-9967dedfe169','歸自德清','陳必復','宋','宋诗','song-poetry','','[]','午陰雲弄日，水漲浪侵磯。',48,'全唐诗/poet.song.228000.json','["午陰雲弄日，水漲浪侵磯。", "小港漁舟聚，深村酒戶稀。", "牛閑童自睡，蠶熟客方歸。", "隔岸人家近，繅聲出翠微。"]'),
('e8608b06-f7e2-4a9a-9d26-3e5ed42a104f','游前溪西庵','陳必復','宋','宋诗','song-poetry','','[]','爲愛僧居雅，時來扣野扉。',48,'全唐诗/poet.song.228000.json','["爲愛僧居雅，時來扣野扉。", "沼清魚可數，軒靜客忘歸。", "修竹負牆立，幽禽背水飛。", "道人差不俗，洗耳聽絃徽。"]'),
('3fa51edb-6285-42b6-97fd-15d9d716081a','贈張駉','陳必復','宋','宋诗','song-poetry','','[]','乍見語相合，苦吟心更親。',48,'全唐诗/poet.song.228000.json','["乍見語相合，苦吟心更親。", "老於琴得趣，隠與牧爲鄰。", "一夜檐花雨，十年江樹春。", "所交半湖海，恨晚識斯人。"]'),
('83bd8c14-682e-4fde-9eb0-9c419b2da7fc','東野故居','陳必復','宋','宋诗','song-poetry','','[]','先生高隠地，遺跡尚堪尋。',48,'全唐诗/poet.song.228000.json','["先生高隠地，遺跡尚堪尋。", "出郭祇疑近，入村還覺深。", "秋光淡平野，暝色带遥岑。", "幾度祠邊過，詩成不敢吟。"]'),
('7bad10e4-0c51-4f6f-899d-6b0e181a306c','響應寺','陳必復','宋','宋诗','song-poetry','','[]','步屧窮幽討，扶筇上碧尖。',48,'全唐诗/poet.song.228000.json','["步屧窮幽討，扶筇上碧尖。", "山高秋易瘦，瀑小雨方添。", "寺老僧單少，潭深廟祀嚴。", "平生丘壑志，愛此結茅檐。"]'),
('f9c770a8-3110-4952-95a7-fa1cf6db3a33','宿龍山精舍','陳必復','宋','宋诗','song-poetry','','[]','偶貪禪宇靜，襆被到深林。',48,'全唐诗/poet.song.228000.json','["偶貪禪宇靜，襆被到深林。", "夜榻僧同話，寒檐客自吟。", "窗明疑積雪，樹黑怪常陰。", "猶恨匆匆出，丁寧約重尋。"]'),
('41b9bfe2-d1c4-49fe-ab36-a6c20ec71d2b','僧房','陳必復','宋','宋诗','song-poetry','','[]','結廬修竹裏，身外世緣輕。',48,'全唐诗/poet.song.228000.json','["結廬修竹裏，身外世緣輕。", "滑几浄如拭，小窗低更明。", "夜深留佛火，人靜聽鐘聲。", "共撥爐灰坐，跏趺對短檠。"]'),
('0e0a943e-3efb-4181-99c6-f4368d0ca3f8','山中書事','陳必復','宋','宋诗','song-poetry','','[]','天氣如春盎，連朝未有霜。',48,'全唐诗/poet.song.228000.json','["天氣如春盎，連朝未有霜。", "數蟬嘶老木，一鳥渡寒塘。", "風竹寫晴影，水花臨曉妝。", "靜中觀物化，此意等羲黄。"]'),
('3ea36b23-b719-404a-8b10-4c05065a7cd8','曉步','陳必復','宋','宋诗','song-poetry','','[]','清曉步幽逕，庭蕪带綠莎。',48,'全唐诗/poet.song.228000.json','["清曉步幽逕，庭蕪带綠莎。", "籬根惟有菊，池面已無荷。", "高樹蟬聲急，遠山寒色多。", "小窗風日轉，便覺似春和。"]'),
('7712f875-dede-420a-81d1-46790ee98ae4','吳江道中','陳必復','宋','宋诗','song-poetry','','[]','葉老蠶登箔，泥肥燕葺窠。',48,'全唐诗/poet.song.228000.json','["葉老蠶登箔，泥肥燕葺窠。", "曉風帆腹飽，夜雨柂梢高。", "久客交游少，一春行役多。", "短蓬終日坐，煮茗讀離騷。"]'),
('0f1036cf-13ea-42a0-84ad-44ebb575b9e7','和客用韻','陳必復','宋','宋诗','song-poetry','','[]','麥風翻蝶夢，花露濕蜂窠。',48,'全唐诗/poet.song.228000.json','["麥風翻蝶夢，花露濕蜂窠。", "水闊浪痕帖，雨晴雲氣高。", "酒功書下下，詩料辦多多。", "擬喚三高起，豪吟些楚騷。"]'),
('cf276321-01cb-4445-9802-4691f2c3fe3a','舟行崇德','陳必復','宋','宋诗','song-poetry','','[]','落日掛征帆，西風客袂單。',48,'全唐诗/poet.song.228000.json','["落日掛征帆，西風客袂單。", "燈明村店近，船重水程寬。", "蘆蓼作秋意，汀洲生晚寒。", "鐘聲烟外寺，山色夢中看。"]'),
('4025b7a2-ecb8-4050-9f67-bc4ad14a4de5','嘉禾境上','陳必復','宋','宋诗','song-poetry','','[]','聯疇岡勢斷，缺岸浪痕垂。',48,'全唐诗/poet.song.228000.json','["聯疇岡勢斷，缺岸浪痕垂。", "野店茅柴酒，人家槿樹籬。", "逆風魚上少，連雨稻開遲。", "客路秋偏好，歸程盡是詩。"]'),
('d9880b7d-c758-4fb5-a9f0-1b51c54bc0f0','寄石泉雲間明府叔  其一','陳必復','宋','宋诗','song-poetry','','[]','容易成離索，臨分重忍言。',48,'全唐诗/poet.song.228000.json','["容易成離索，臨分重忍言。", "夜船楊柳岸，曉枕荻花村。", "山雨斷雲脚，溪風生浪痕。", "懸知自公退，懷抱欠同論。"]'),
('fc2c0197-1572-40e9-9369-0c702bcbac17','寄石泉雲間明府叔  其二','陳必復','宋','宋诗','song-poetry','','[]','異政人能說，新吟客爲傳。',48,'全唐诗/poet.song.228000.json','["異政人能說，新吟客爲傳。", "一官清似水，萬事信於天。", "養鶴分厨料，收書出俸錢。", "晝庭少公事，閉閣抱琴眠。"]'),
('9b643212-94f6-41f6-a116-2b6f6b52217f','寄石泉雲間明府叔  其三','陳必復','宋','宋诗','song-poetry','','[]','卧念相從樂，杜門岑寂中。',48,'全唐诗/poet.song.228000.json','["卧念相從樂，杜門岑寂中。", "曙窗報晴色，寒葉語秋風。", "別去詩難穩，愁來酒易空。", "相看才數驛，好爲寄書筒。"]'),
('5ca3d382-5c00-45fd-8ab8-b1fef6eb2dd0','席上和林端隠韻','陳必復','宋','宋诗','song-poetry','','[]','雲壓檐花重，溪禽濕不飛。',48,'全唐诗/poet.song.228000.json','["雲壓檐花重，溪禽濕不飛。", "烟林生暝色，雨砌上苔衣。", "暮鼓深村急，疏鐘遠寺微。", "吟窗得新句，寫向錦囊歸。"]'),
('bfd42202-0e4f-4504-a0fe-901e4e28f8da','梅花','陳必復','宋','宋诗','song-poetry','','[]','瘦得冰肌骨亦清，詩人於爾獨關情。',64,'全唐诗/poet.song.228000.json','["瘦得冰肌骨亦清，詩人於爾獨關情。", "孤高不受塵埃涴，潔白猶嫌縞練輕。", "天下有花皆北面，歲寒惟雪可同盟。", "當時只欠靈均識，不與離騷寫姓名。"]'),
('598a1570-1ef7-4e77-9b6e-44eab488439d','防風氏廟','陳必復','宋','宋诗','song-poetry','','[]','一去歸期不復聞，故鄉目斷會稽雲。',64,'全唐诗/poet.song.228000.json','["一去歸期不復聞，故鄉目斷會稽雲。", "烏江空墮將軍淚，蜀國曾招望帝魂。", "兩壁衣冠存古貌，千年城郭說邦君。", "遺民尚指專車骨，老樹槎牙枕廟門。"]'),
('bf7c3888-c399-4705-8cf3-3a2fa5112b94','偶成','陳必復','宋','宋诗','song-poetry','','[]','繞屋栽梅亦可人，最憐夏月綠陰清。',64,'全唐诗/poet.song.228000.json','["繞屋栽梅亦可人，最憐夏月綠陰清。", "前村雨過山如洗，深徑風來竹自鳴。", "滌硯不嫌池水冷，寫書愛傍午窗明。", "近吟未許人知得，且向梅邊隠姓名。"]'),
('5f609b39-a1d6-4f1c-8d74-5e0e33be7569','舟中效東坡用韻','陳必復','宋','宋诗','song-poetry','','[]','底事京塵踏軟紅，又隨征棹過吳松。',64,'全唐诗/poet.song.228000.json','["底事京塵踏軟紅，又隨征棹過吳松。", "人家半在桑柘住，春水忽迷蘆葦叢。", "赤蟹白魚今稍稍，紅櫻紫笋已匆匆。", "船窗盡日看山色，多少好山供眼中。"]'),
('a2816e04-c6b0-4bc5-92c0-4daedab3e7ba','春日偕遊響應山觀瀑泉飲漱玉亭上分複磴擁危泉賦磴韻十四','陳必復','宋','宋诗','song-poetry','','[]','溪山晴色妍，桃李春意賸。',168,'全唐诗/poet.song.228000.json','["溪山晴色妍，桃李春意賸。", "野服烏角巾，郊游偶乘興。", "同行皆好賓，樂此境物勝。", "古寺臨清潭，鳴泉落危磴。", "孤亭上雲雨，木末渺難認。", "林深行漸迷，谷虛語相應。", "陰壑號悲風，懸蘿礙飛鐙。", "掃花坐寒石，意與幽事稱。", "崖巔記曾遊，蘚濕墨痕凝。", "登高浩懷古，歲月如墮甑。", "百年幾朝昏，今昔一長憑。", "道人苦將迎，頗亦厭車乘。", "他時營菟裘，隙地儻可贈。", "舉杯酌山靈，茲語爲我證。"]'),
('b7f23b65-5287-498d-9f0a-e06813baaab8','題東坡畫像','陳必復','宋','宋诗','song-poetry','','[]','東坡先生謫仙人，騎鯨海宇幾十春。',64,'全唐诗/poet.song.228000.json','["東坡先生謫仙人，騎鯨海宇幾十春。", "麾呵日月斥八極，笑觸豐缺天不嗔。", "萬里歸來故無恙，諸公非復先朝臣。", "空令後世拜公像，洛陽宮闕今成塵。"]'),
('01e7edbb-cb4d-46a4-923e-55018b444cce','村家','陳必復','宋','宋诗','song-poetry','','[]','繞郭一溪斜，溪村八九家。',48,'全唐诗/poet.song.228000.json','["繞郭一溪斜，溪村八九家。", "招邀過鄰里，款曲話桑麻。", "老樹低眠石，寒流淺漱沙。", "吾生尚萍梗，媿爾獨興嗟。"]'),
('cc92f1dc-1954-472f-884a-2ddb17259283','積潦簡友人','陳必復','宋','宋诗','song-poetry','','[]','暝鎖層陰重，霾深失遠巒。',48,'全唐诗/poet.song.228000.json','["暝鎖層陰重，霾深失遠巒。", "積流上籬落，飛影度欄干。", "石髮梳風瘦，垣衣護雨寒。", "深懷裹飯去，終媿往來難。"]'),
('c1ad0bec-d210-4f0d-97c2-9b565c35c23d','葦逕','陳必復','宋','宋诗','song-poetry','','[]','葦逕通支港，舟行倚岸斜。',48,'全唐诗/poet.song.228000.json','["葦逕通支港，舟行倚岸斜。", "曉沙含宿雨，老樹著疏花。", "歲月春城暮，人烟水驛賒。", "仍年爲客恨，飄泊祇堪嗟。"]'),
('5b97091f-a0a1-438a-8df5-3b0182f8e941','東吳逆旅','陳必復','宋','宋诗','song-poetry','','[]','他鄉又寒食，牢落動歸心。',48,'全唐诗/poet.song.228000.json','["他鄉又寒食，牢落動歸心。", "世事少如意，明時無賞音。", "江湖千里客，桑柘一春深。", "昨夜還家夢，西窗見綠陰。"]'),
('6ad2bfdf-4af7-4814-8ee4-22a520cf8b79','遠遊','陳必復','宋','宋诗','song-poetry','','[]','關山勞眺望，宇宙憶經行。',48,'全唐诗/poet.song.228000.json','["關山勞眺望，宇宙憶經行。", "地隔南溟斷，天低北斗橫。", "高譙聞遠柝，孤枕歷寒更。", "隻影惟堪弔，殊鄉鮮弟兄。"]'),
('a020837d-0e51-46e5-8a97-516b5bc49fec','雨晴小步','陳必復','宋','宋诗','song-poetry','','[]','蠶月家家靜，村流處處深。',48,'全唐诗/poet.song.228000.json','["蠶月家家靜，村流處處深。", "草分兩岸色，竹覆半池陰。", "少飲亦微醉，獨行還自吟。", "兒童怪相問，爭識野夫心。"]'),
('d04aa437-b513-4c9e-9c76-52aa854f5832','晨征','陳必復','宋','宋诗','song-poetry','','[]','亂山迎馬首，樹色辨微茫。',48,'全唐诗/poet.song.228000.json','["亂山迎馬首，樹色辨微茫。", "犬吠一村月，鴉啼滿屋霜。", "近郊人語早，遠市漏聲長。", "隔岸誰家圃，疏梅出短牆。"]'),
('f9628c73-1ce7-4b94-b84c-c88b67c41a45','出郭','陳必復','宋','宋诗','song-poetry','','[]','泥深留屐齒，出郭少人行。',48,'全唐诗/poet.song.228000.json','["泥深留屐齒，出郭少人行。", "遠磬含餘韻，疏簾透薄明。", "浮雲時態異，流水世情輕。", "只讀南華了，年來悟養生。"]'),
('104ff3c9-649b-4dfd-b6c9-32baba6e22db','郊行','陳必復','宋','宋诗','song-poetry','','[]','夏半餘寒在，新秧綠未齊。',48,'全唐诗/poet.song.228000.json','["夏半餘寒在，新秧綠未齊。", "僧歸知有寺，水盡覺無溪。", "疏徑風行籜，空庭鳥篆泥。", "東郊有幽致，小暇一扶藜。"]'),
('06b00607-f56e-4c61-9cb7-48ac373ebe63','漏長','陳必復','宋','宋诗','song-poetry','','[]','漏長知夜久，夢薄覺衣輕。',48,'全唐诗/poet.song.228000.json','["漏長知夜久，夢薄覺衣輕。", "曙月侵霜白，寒星度水明。", "遥空一雁過，鄰屋數雞鳴。", "著論吾寧敢，徐徐待老成。"]'),
('0716f5eb-edae-4245-bee3-ab50ab00eac1','意行','陳必復','宋','宋诗','song-poetry','','[]','簡出少過從，前遊仙夢中。',48,'全唐诗/poet.song.228000.json','["簡出少過從，前遊仙夢中。", "寒峰千嶺碧，霜葉半林紅。", "霽表浮餘景，明邊落去鴻。", "意行隨所止，端未哭塗窮。"]'),
('b5369d1f-6e0c-46c8-a9c1-e526fd21ce27','偶出','陳必復','宋','宋诗','song-poetry','','[]','野店荒雞曙，籬荆带暝開。',48,'全唐诗/poet.song.228000.json','["野店荒雞曙，籬荆带暝開。", "漏聲隨雨盡，山色傍船來。", "事業歸書卷，生涯付酒杯。", "溪翁往還慣，不怕白鷗猜。"]'),
('bd955980-1003-41b2-ac9b-383252406e13','書西齋几','陳必復','宋','宋诗','song-poetry','','[]','半枕午窗夢，一聲啼鳥清。',48,'全唐诗/poet.song.228000.json','["半枕午窗夢，一聲啼鳥清。", "雨深花有恨，春老柳無情。", "退覺身名重，閒知世事輕。", "杜門非謝客，懶甚闕將迎。"]'),
('4908fb4a-6b5d-465c-ac44-79e40c336e8d','遲客小軒','陳必復','宋','宋诗','song-poetry','','[]','約客久不至，春明坐小軒。',48,'全唐诗/poet.song.228000.json','["約客久不至，春明坐小軒。", "牆陰侵霽色，簷暈上波痕。", "晴色麥花老，暖風鶑語繁。", "午庭人寂寂，桃李亦無言。"]'),
('57ad253f-ecf3-447c-af95-e23776654af8','賦參政叔祖水亭','陳必復','宋','宋诗','song-poetry','','[]','一段漁歌起夕陽，溪山佳處欠平章。',64,'全唐诗/poet.song.228000.json','["一段漁歌起夕陽，溪山佳處欠平章。", "受風楊柳絲絲弱，臨水軒窗面面凉。", "約客有時同把酒，橫琴無事自燒香。", "沙頭鷗鳥忘機久，却被官船去較忙。"]'),
('cd3fd56f-0250-4d04-9f10-66fb92d7b0fa','夜宿山庵','陳必復','宋','宋诗','song-poetry','','[]','扣宿精廬旋啟扉，佛香未冷坐多時。',64,'全唐诗/poet.song.228000.json','["扣宿精廬旋啟扉，佛香未冷坐多時。", "分僧一半雲歸榻，借竹幾些風入詩。", "隔夢聽鐘疑寺遠，避寒移枕覺宵遲。", "起看猶有殘窗月，春雪滿山啼子規。"]'),
('4ae4b27a-8c60-49c3-877a-e4ddcbdaabb6','書齋戲題','陳必復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','數簷隙地葺幽齋，小作軒窗傍竹開。',64,'全唐诗/poet.song.228000.json','["數簷隙地葺幽齋，小作軒窗傍竹開。", "行蟻上緣風折笋，饑鴉爭啄雨殘梅。", "閉門惟有讀書樂，愛客苦無佳士來。", "最憶西湖柳陰底，扁舟欲去尚徘徊。"]'),
('bf5b7e18-04b4-45dd-9d64-d982718dd80c','江湖','陳必復','宋','宋诗','song-poetry','','[]','江湖路遠總風波，欲向山中製芰荷。',64,'全唐诗/poet.song.228000.json','["江湖路遠總風波，欲向山中製芰荷。", "黄葉落來秋色晚，亂鴉歸處夕陽多。", "慣經世態知時異，拙爲身謀惜歲過。", "有屋一區田二頃，分無清夢到鳴珂。"]'),
('2448bef9-b925-4893-9cb9-90754640a074','過隠者居','陳必復','宋','宋诗','song-poetry','','[]','瘦筇獨與鶴相隨，行盡荒郊入翠微。',64,'全唐诗/poet.song.228000.json','["瘦筇獨與鶴相隨，行盡荒郊入翠微。", "溪鳥喜晴將子浴，山蜂傍暖採花歸。", "空村歲月徵書晚，深徑蒿萊客屨稀。", "久欲依居圖別業，自愁無計泣牛衣。"]'),
('1c142928-e81c-484a-90dd-50a723912be8','奉酬陳介庵明府桐江見寄','陳必復','宋','宋诗','song-poetry','','[]','寒侵征袖客先知，曉角吹霜下客衣。',64,'全唐诗/poet.song.228000.json','["寒侵征袖客先知，曉角吹霜下客衣。", "歸興只緣松菊晚，宦情肯爲稻粱肥。", "山村日落人收市，海浦風生浪打圍。", "怊悵詩成無便寄，夜深暗遣夢魂歸。"]'),
('252e41ad-1851-437b-9dbd-d3803d1372a8','戲折竹葉爲舟示奚奴','陳必復','宋','宋诗','song-poetry','','[]','乃翁兒戲可憐生，折葉浮舟趁岸行。',64,'全唐诗/poet.song.228000.json','["乃翁兒戲可憐生，折葉浮舟趁岸行。", "有便信風翻覆易，無心逐水去留輕。", "觸崖頗似乘時意，藏壑深關遯世情。", "幸喜此身元不繫，底須壁上覓寰瀛。"]'),
('bb1507b3-037e-4d3b-bd1f-90cc1e06cf37','元日酌悠然賦坐客悠字韻','陳必復','宋','宋诗','song-poetry','','[]','東風第一番春游，白袷清樽半日休。',64,'全唐诗/poet.song.228000.json','["東風第一番春游，白袷清樽半日休。", "花氣未醒蜂蝶懶，宿寒猶殢雨雲愁。", "人烟带郭居全少，林沼當軒趣迥幽。", "吟過小橋歸夢晚，亂鐘何處思悠悠。"]'),
('d88bc53e-c00c-4591-b173-fe8905868528','重過東野故居','陳必復','宋','宋诗','song-poetry','','[]','郭外有村名孟堡，舊傳君此卜幽棲。',64,'全唐诗/poet.song.228000.json','["郭外有村名孟堡，舊傳君此卜幽棲。", "草荒東野千年宅，水繞南山一曲溪。", "人物不生詩渺渺，秋風無語恨悽悽。", "可憐如許衣冠士，不爲留祠向竹西。"]'),
('17f12996-6f79-42da-a63a-2c847d0ee10c','歸來','陳必復','宋','宋诗','song-poetry','','[]','小笠輕蓑卧短篷，曉歌楚曲和漁翁。',32,'全唐诗/poet.song.228000.json','["小笠輕蓑卧短篷，曉歌楚曲和漁翁。", "片帆自識歸來路，借得清江一釣風。"]'),
('30962339-bad1-49f2-8510-a58c25adcecf','幽興','陳必復','宋','宋诗','song-poetry','','[]','自折疏花插小瓶，醉眠明月讀騷經。',32,'全唐诗/poet.song.228000.json','["自折疏花插小瓶，醉眠明月讀騷經。", "白雲也識幽人意，分與秋山一半青。"]'),
('2b0987e5-211f-4ff3-97c2-d25691e56f9d','山中冬至','陳必復','宋','宋诗','song-poetry','','[]','讀易燒香自閉門，懶於世故苦紛紛。',32,'全唐诗/poet.song.228000.json','["讀易燒香自閉門，懶於世故苦紛紛。", "曉來靜處參生意，春到梅花有幾分。"]'),
('6ab7f4a2-5de3-4391-a57c-1841709d47e6','夜軒納凉','陳必復','宋','宋诗','song-poetry','','[]','銀牀破睡霧籠紗，翠簟湘紋捲浪斜。',32,'全唐诗/poet.song.228000.json','["銀牀破睡霧籠紗，翠簟湘紋捲浪斜。", "小院夜深凉似水，一池明月浸荷花。"]'),
('2d5f4d4e-2380-47cf-9a53-539f0adf3e7b','五月十三日偶成','陳必復','宋','宋诗','song-poetry','','[]','富貴真同一蟻丘，寵榮多處獨多憂。',64,'全唐诗/poet.song.228000.json','["富貴真同一蟻丘，寵榮多處獨多憂。", "靜觀草木自生意，晚愛溪山多勝游。", "竹豈有情那得醉，雞寧解語亦能愁。", "紛紛數子成何事，只合求田問舍休。"]'),
('e7bc39fc-c2c0-49f5-ba29-6857d73ae9dc','漫賦','陳必復','宋','宋诗','song-poetry','','[]','篝燈讀易聽更殘，微雨蕭蕭獨閉關。',64,'全唐诗/poet.song.228000.json','["篝燈讀易聽更殘，微雨蕭蕭獨閉關。", "治世豈無謀可獻，書生從古命多寒。", "數莖鬚爲憂時白，一點心猶報國丹。", "未肯軒裳便塵土，此身翻恐誤儒冠。"]'),
('deb4e488-02fc-43a2-a180-811d6f6985fd','讀後山詩','陳必復','宋','宋诗','song-poetry','','[]','百世人參杜陵句，一燈晚得後山傳。',64,'全唐诗/poet.song.228000.json','["百世人參杜陵句，一燈晚得後山傳。", "天寒霜重隼孤擊，木落江空花自妍。", "絕代文章驚此老，半生心力盡他年。", "後來不作嗟誰繼，古意淒涼付斷編。"]'),
('0e4988f1-2375-4829-a926-0476ef17b388','夜發江城','陳必復','宋','宋诗','song-poetry','','[]','移舟別浦待潮生，客子怱怱又夜行。',64,'全唐诗/poet.song.228000.json','["移舟別浦待潮生，客子怱怱又夜行。", "雲趁遠帆離島岸，風傳疏角過江城。", "憂時諫草嗟無用，愛客燈花喜有情。", "愁甚不堪親友別，小窗張酒到天明。"]'),
('5c36bc9d-fd60-41e2-b727-10ca50711c6c','遠遊','陳必復','宋','宋诗','song-poetry','','[]','關山勞眺望，宇宙憶經行。',48,'全唐诗/poet.song.228000.json','["關山勞眺望，宇宙憶經行。", "地隔南溟斷，天低北斗橫。", "高譙聞遠柝，孤枕歷寒更。", "隻影惟堪弔，殊鄉鮮弟兄。"]'),
('8cc90d39-1eaf-43d8-a4e4-63adf9627ffa','聞虜退後作','陳必復','宋','宋诗','song-poetry','','[]','小臣憂國志，所願見時平。',48,'全唐诗/poet.song.228000.json','["小臣憂國志，所願見時平。", "刁斗春防塞，囊書夜入京。", "邊風吹冷骨，淮月浸重城。", "失喜天驕死，傳聞已息兵。"]'),
('70099e29-07ae-40e2-858a-2bd52f133f74','詠狂虜','陳必復','宋','宋诗','song-poetry','','[]','狂虜何時靜，干戈卒未休。',48,'全唐诗/poet.song.228000.json','["狂虜何時靜，干戈卒未休。", "乾坤猶半拆，汴泗自東流。", "腥日鼪鼯野，悲風鴻雁秋。", "諸賢江左計，長爲晉人羞。"]'),
('a0bd6853-362f-4cbb-838a-c7b9027ab1b0','松江','陳必復','宋','宋诗','song-poetry','','[]','嗟我賦歸役，憐君尚滯留。',48,'全唐诗/poet.song.228000.json','["嗟我賦歸役，憐君尚滯留。", "江風借行色，山月伴離愁。", "天地日以肅，星辰夜欲浮。", "東籬菊花約，莫易負清秋。"]'),
('3c3688b5-f44a-4cc0-9888-56a4d51df56e','還西里所居','陳必復','宋','宋诗','song-poetry','','[]','長恐山林計未成，可能俯仰羨公卿。',64,'全唐诗/poet.song.228000.json','["長恐山林計未成，可能俯仰羨公卿。", "鶴閑不受雲拘束，梅冷惟須雪主盟。", "北闕無書休悔出，東皋有秫可歸耕。", "鏡容漸改驚非昔，猶喜旁人喚後生。"]'),
('69198dc4-6a01-45ee-8076-e4238677b9a5','春日  其一','陳杰','宋','宋诗','song-poetry','','[]','春日悠悠，春風載條，春酒思柔。',25,'全唐诗/poet.song.228000.json','["春日悠悠，春風載條，春酒思柔。", "念我農人，種秫在疇。"]'),
('17c2d495-17c9-4868-be88-17582e2a3f06','春日  其二','陳杰','宋','宋诗','song-poetry','','[]','春日遲遲，春風載時，春服有暉。',25,'全唐诗/poet.song.228000.json','["春日遲遲，春風載時，春服有暉。", "念我蠶女，勩于桑疇。"]'),
('091b5d80-add9-48bf-865b-3fc36bbd6ba3','春日  其三','陳杰','宋','宋诗','song-poetry','','[]','翩翩黄鳥，載好其羽。',30,'全唐诗/poet.song.228000.json','["翩翩黄鳥，載好其羽。", "鮮鮮遊子，式歌且舞。", "曾孫萬年，敬我有土。"]'),
('8c5f136c-827b-4ade-974e-c3c926eaef91','江永  其一','陳杰','宋','宋诗','song-poetry','','[]','江之永兮，朝宗于海。',31,'全唐诗/poet.song.228000.json','["江之永兮，朝宗于海。", "匪江永兮，洛水攸會。", "洛書其系兮，曷敢不愛。"]'),
('b999708f-cb21-4a54-83ef-4a069b1b4b3c','江永  其二','陳杰','宋','宋诗','song-poetry','','[]','江之永兮，于海朝宗。',31,'全唐诗/poet.song.228000.json','["江之永兮，于海朝宗。", "匪江永兮，河水攸同。", "河圖其系兮，曷敢不恭。"]'),
('c328e82d-457f-4135-a113-9026e0693762','江永  其三','陳杰','宋','宋诗','song-poetry','','[]','江之永兮，我瞻禹迹。',32,'全唐诗/poet.song.228000.json','["江之永兮，我瞻禹迹。", "微江之永兮，三正幾息。", "三極其系兮，曷敢不惕。"]'),
('fff98cc1-5ede-4d36-9296-b77b69c60153','明月  其一','陳杰','宋','宋诗','song-poetry','','[]','悠悠明月，載盈載缺，我酒在室。',15,'全唐诗/poet.song.228000.json','["悠悠明月，載盈載缺，我酒在室。"]'),
('b35629bf-52b2-4e37-bf6f-68638432ccfe','明月  其二','陳杰','宋','宋诗','song-poetry','','[]','皎皎明月，載缺載盈，我酒在庭。',15,'全唐诗/poet.song.228000.json','["皎皎明月，載缺載盈，我酒在庭。"]'),
('41dcd90a-41b1-4862-8f2d-89ec70c71340','明月  其三','陳杰','宋','宋诗','song-poetry','','[]','白日苦短，而夜苦長。',20,'全唐诗/poet.song.228000.json','["白日苦短，而夜苦長。", "遲爾不來，明月靡常。"]'),
('4690477b-c9bf-438d-a650-ee0fe54011d3','明月  其四','陳杰','宋','宋诗','song-poetry','','[]','載脂我車，載秣我馬。',20,'全唐诗/poet.song.228000.json','["載脂我車，載秣我馬。", "煌煌于征，明月在下。"]'),
('d9d37736-c71d-4a38-8f4c-b0e8cb6fddbe','元和','陳杰','宋','宋诗','song-poetry','','[]','元和天子聖，玉燭萬方同。',48,'全唐诗/poet.song.228000.json','["元和天子聖，玉燭萬方同。", "乾坤一澄霽，草木皆春融。", "臣度再稽首，臣愬三鞠躬。", "一雪洗蔡州，敢有貪天功。"]'),
('6c2d3af1-37b4-4c26-889f-6a2bbed15b05','清坐','陳杰','宋','宋诗','song-poetry','','[]','晨興絕無思，清坐還復佳。',48,'全唐诗/poet.song.228000.json','["晨興絕無思，清坐還復佳。", "夜氣不啻存，俗氛殊未來。", "居然類禪定，正爾悟心齋。", "明發謝西爽，故山先夢回。"]'),
('5802a06d-571c-4cc2-896a-c440e029f1ac','送別','陳杰','宋','宋诗','song-poetry','','[]','曉色澹長路，微霜乍霑巾。',84,'全唐诗/poet.song.228000.json','["曉色澹長路，微霜乍霑巾。", "彗妖如撒沙，下覆秋江濆。", "送君萬里船，黯然及茲晨。", "豈無陽關疊，亦有酒盈樽。", "憂端塞宇宙，壯懷浩風雲。", "丈夫矚千載，薄細安足陳。", "欲語重回首，天高水無津。"]'),
('722903d4-ef9a-451d-ac0d-8588ba3dd066','書徐經坂先誌','陳杰','宋','宋诗','song-poetry','','[]','青霞餘絢皆成章，虎變龍匿超故常。',160,'全唐诗/poet.song.228000.json','["青霞餘絢皆成章，虎變龍匿超故常。", "異時欣然讀奇崛，觸眼慘淡令人傷。", "矢心爲詞血爲筆，沈恨欲訴天茫茫。", "波瀾收卷見至性，星斗隠翳回幽光。", "題將片石寄冥漠，意與萬古生凄凉。", "山靈護持夜半泣，悲風著木春無芳。", "伯庸罔極白日短，龍舒歸夢青山長。", "萬鍾不解羊棗痛，一死儻補南陔亡。", "載之實錄非虛譽，斯文知心地下郎。", "檀弓孝經不浪許，椽筆足徵老玉堂。"]'),
('2371f305-3f4b-435f-bf0f-535d1588f543','曩從玉泉道人見壽亭侯印大可方二寸併解池龍骨一枚云侯所下討者今從玄潭道人見旌陽令劍長不過五六寸云令留以鎮水妖者皆微物遠不可考道人請予賦劍因併及印以起興焉','陳杰','宋','宋诗','song-poetry','','[]','玉泉寺中三鈕銅，十年解池討業龍。',134,'全唐诗/poet.song.228000.json','["玉泉寺中三鈕銅，十年解池討業龍。", "當時何不佐取流馬出，火德重開兩都日。", "玄潭觀中半圭鐵，千年龍沙擬蛟孽。", "當時何不喚取泉阿歸，汛灑河洛風雷飛。", "白衣摇艣天難料，鷄犬雲中帝親召。", "漢陵無樹兮晉國成丘，待侯不來兮仙又竟去而莫留，徒使我百世而下生閒愁。", "荆州看印心尚烈，洪州看劍頭如雪。"]'),
('d9bf7848-7395-47aa-a8c3-d5a06b79bbbc','和山長胡端逸辭歸','陳杰','宋','宋诗','song-poetry','','[]','漢濱人物誰耆舊，湖上古松吾老友。',64,'全唐诗/poet.song.228000.json','["漢濱人物誰耆舊，湖上古松吾老友。", "入郭人民半是非，升堂絲竹真烏有。", "煩君楚舞吾楚歌，街頭小兒笑阿婆。", "明年湖水還綠波，携詩來看田田荷。"]'),
('2bf6a950-172d-4ad4-9dae-eecf59f35430','讀史','陳杰','宋','宋诗','song-poetry','','[]','口體乃累人，寒餓事亦細。',56,'全唐诗/poet.song.228000.json','["口體乃累人，寒餓事亦細。", "擁篲何爲者，妨我雪中睡。", "先生死非令尹辱，彼四百家無罪哭。", "粟三鍾，薪十束，天留先生雪楚獄。"]'),
('70285966-0819-4e54-a155-4399ac81fcbc','望廬山','陳杰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','去年山中行，未了廬山意。',112,'全唐诗/poet.song.228000.json','["去年山中行，未了廬山意。", "今年江上望，始盡廬山勢。", "只道山中行，未識廬山面。", "那知江上望，已失廬山願。", "人生出處前料難，向來窗下有此山。", "一行作吏事便廢，十年讀書早已悔。", "五老招人笑舉頭，三老催船不自由。", "柔艣一聲天似水，無情飛起兩沙鷗。"]'),
('e03386af-8c1e-4ea8-a775-cdeb5a422301','贈蔡俊民挾雷法兼眼科北行','陳杰','宋','宋诗','song-poetry','','[]','乖龍捲雨焦土山，妖蟆蝕晴長夜漫。',64,'全唐诗/poet.song.228000.json','["乖龍捲雨焦土山，妖蟆蝕晴長夜漫。", "安得霹靂鞭龍起，取光還天磔蟆死。", "寥落風霆道術空，坐看短世入盲聾。", "南人巫醫尚方滿，一試兩長君恨晚。"]'),
('0ff485e4-d0fc-4cd2-9736-699217a3f9ab','陳梅境恩科晚遇由廣而江帥幕留司索賦','陳杰','宋','宋诗','song-poetry','','[]','昔年鋤梅嶺頭月，今年看梅江路雪。',80,'全唐诗/poet.song.228000.json','["昔年鋤梅嶺頭月，今年看梅江路雪。", "月還在江雪在嶺，兩處開花一般境。", "道人兩眼冰霜寒，道人一襟湖海寬。", "夢回紙帳北窗曉，眼前肯作南枝看。", "月夜雪天花一色，未怕孤山分破得。"]'),
('c2e596e0-74b6-4484-bf2a-59edcf139b1e','蘇東坡西山詩前後和者五十餘篇暇日登覽愴然有感於元祐紹聖之事僭亦用韻','陳杰','宋','宋诗','song-poetry','','[]','檻外春江如醱醅，檻前松株逐番栽。',224,'全唐诗/poet.song.228000.json','["檻外春江如醱醅，檻前松株逐番栽。", "西門安得陶氏柳，西嶺併無坡老梅。", "惟餘荒磎入煙霧，曾載轍迹行崔嵬。", "漥樽其多一卷石，清風千丈嚴瀨臺。", "人間此事固不朽，山高唐業澌成埃。", "干戈五季亂離瘼，帝命封之白雲堆。", "餘三百年付遷客，眼底盆盎得古罍。", "每登勝絕不忍去，往往拂枕眠其隈。", "毀書滅迹坐再閏，枝筇雙屐印蘚苔。", "無端玉堂牽清夢，九虎乍放天門開。", "武昌舊令偶同直，得句一粲金蓮摧。", "那知白頭不同趨，首倡紹述蚊成雷。", "憑高爲弔千古恨，魂兮可招儻一來。", "併持公案徵漫叟，立盡落日山靈哀。"]'),
('ffdfb9d3-05b8-4577-8a5d-00c2ea9730a0','淮南看雪歌','陳杰','宋','宋诗','song-poetry','','[]','出門看雪一萬里，閉門讀書一萬年。',144,'全唐诗/poet.song.228000.json','["出門看雪一萬里，閉門讀書一萬年。", "讀書只讀三皇後，看雪還看太始前。", "洪濛以還初紀異，鍊石補天灰滲地，人蟲森然盜元氣。", "介鱗日深蹄跡多，閫抉垠開奈若何。", "千山忽絕萬逕滅，宇宙鶻崙無璺裂。", "夜燈太極强披圖，清曉長淮初見雪。", "丁寧莫遣風日分，暫時大地皆瑶琨，我爾一醉瓊花樽。", "明朝山河各異色，獨在書生頭上白。"]'),
('e6fc5b66-6b06-4946-99f4-feb2bc782843','武岡向權叔家有陳魏祠堂合祀簡齋鶴山惟兩公世異事殊實難牽合諸公既極推引復徵予言','陳杰','宋','宋诗','song-poetry','','[]','簡齋以詩冠兩都，鶴山以文擅江東。',256,'全唐诗/poet.song.228000.json','["簡齋以詩冠兩都，鶴山以文擅江東。", "茲溪僻在萬山底，遼絕安能來兩公。", "或撞天關忤九虎，或走窮海隨六龍。", "畏途迂車一笑粲，遠謫信杖雙音跫。", "誰其主者林下叟，又誰嗣之大雅翁。", "詩題田家足渾朴，帖送石刻何舂容。", "百年向氏兩奇遇，千載江山真發矇。", "到今窗戶有佳色，尚想林壑生清風。", "恭惟人物一代幾，伊洛既竭岷峨空。", "艱虞各行天下半，名數况復參樞崇。", "高吟大冊照寰宇，如此過化良亦匆。", "泥上指爪東西鴻，精神如水行地中。", "偶然流落亦安計，牽合推引驚盲聾。", "二公德業吾豈敢，淺陋最識詩文工。", "平生此兩大家數，秤較力量能無同。", "創聞合祀適有契，一瓣聊借歌詞通。"]'),
('30e8f7c5-0a3f-4307-bde0-a5edc7ef9f79','重過西湖感事','陳杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','衣如飛鶉馬如狗，二尺錦囊香宇宙。',144,'全唐诗/poet.song.228000.json','["衣如飛鶉馬如狗，二尺錦囊香宇宙。", "車如流水馬如龍，濯龍橋邊吹斷蓬。", "諸公南渡亦不惡，百年西湖最行樂。", "師王園地號山莊，戚畹洞天標水樂。", "銅鋪珠箔錦爲茵，玉簫金管歌遏雲。", "曲江三月勢絕倫，此占四時長作春。", "歲月無情留不住，園上送官洞更主。", "當時一聚冶遊塵，雨打風飄去安所。", "三間古屋餘老梅，千年放鶴歸來暮。"]'),
('a35996cd-341f-41f9-b2b4-a7009b92dc33','壽康堂爲吳氏題','陳杰','宋','宋诗','song-poetry','','[]','人莫不欲壽，文子之祈省非矯。',68,'全唐诗/poet.song.228000.json','["人莫不欲壽，文子之祈省非矯。", "人莫不欲康，文公之步省非狂。", "震風不貸蝸牛廬，堂中老人方晏如，笑我閉門生白鬚。", "安得八荒開壽域，却隨童子詠康衢。"]'),
('67fc21a9-51b5-4300-8fa1-e8071fd0ca73','維揚之役浩堂撥賜鉅舟願易小者','陳杰','宋','宋诗','song-poetry','','[]','美哉不濟如此水，巨川有楫春萬里。',32,'全唐诗/poet.song.228000.json','["美哉不濟如此水，巨川有楫春萬里。", "空貽魏瓠拙用大，誰謂河廣航一葦。"]'),
('b4ee91ff-76b2-42db-b78c-97c970dc8755','御風行送武夷道人謝疊山','陳杰','宋','宋诗','song-poetry','','[]','武夷山中有伏龍，鬣捲雲雨深重重，化爲白鬚一老翁。',120,'全唐诗/poet.song.228000.json','["武夷山中有伏龍，鬣捲雲雨深重重，化爲白鬚一老翁。", "疾雷破山六丁取，置衛銅鐶森守虎，云是健將雨下土。", "老翁一笑百不能，山中所讀皆僊經，吾亦泠然御風行。", "洪崖道上逢老友，手舉無何指翁口，翁已辟穀安事酒。", "青牛紫氣關河咫，大鵬風斯九萬里，回首蓬萊淺清水。"]'),
('fa546f52-ee73-47d0-ab39-da5a569b719d','權貴人','陳杰','宋','宋诗','song-poetry','','[]','權貴人，多怒嗔，頤指所向四海奔。',72,'全唐诗/poet.song.228000.json','["權貴人，多怒嗔，頤指所向四海奔。", "小忤其意中如焚，髮上指冠兩目瞋，投袂而起劍及門。", "當時使氣廉將軍，君視孰與秦王尊。", "氣力到頭同一盡，牧兒持炬上丘墳。"]'),
('2169c371-0afc-4d2e-b06f-16b01a8fe562','書孫州判澹翁再擒寇事蹟','陳杰','宋','宋诗','song-poetry','','[]','古豐怪事未前聞，誰遣盜起紛如雲。',128,'全唐诗/poet.song.228000.json','["古豐怪事未前聞，誰遣盜起紛如雲。", "民無掩骭盜乘馬，民無寸鐵盜鑄冶。", "英英別乘紫髯風，萬甲兵藏學古胸。", "前年借才從柏府，今年駕車就熟路。", "直指賊巢冞入阻，談笑雙收卞莊虎。", "十年養癰破一朝，溪山深處復漁樵。", "由來禁暴非智力，廉爲先聲義爲的。", "蒼生何時蘇息在，安得邦伯皆結輩。"]'),
('df40c86f-b9fa-4c1b-b74e-88c28a1c4d17','和張岳州雪夜彈琴','陳杰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','凍雲留雪消較遲，乾風颼颼時一吹。',184,'全唐诗/poet.song.228000.json','["凍雲留雪消較遲，乾風颼颼時一吹。", "原野慘淡看不宜，饑烏愁絕噤寒鴟。", "飽死帳下羊羔兒，灞橋寂歷久無詩。", "誰歟凝香清夢回，玉山半側瘦藤支。", "意行髣髴鶴氅披，畫堂五丈閒朱旗。", "胡牀冷月浸元規，膝上素弦呵手揮。", "木聲正與絲聲比，避君三舍高漸離。", "忽然曲終雪滿衣，洞庭水湧魚龍知。", "急麾頹魄鞭傾曦，吾聲豈與肅殺期。", "不然持此將安之，折膠無續指無醫。", "我亦從君妄聽奚，雪中作操終何爲，古有履霜思伯奇。"]'),
('c985baa5-2aae-4ecb-8a58-feca28b27490','王儀仲名其讀書之所曰松林願印一言','陳杰','宋','宋诗','song-poetry','','[]','昔人讀書松竹林，今之書林乃無竹。',96,'全唐诗/poet.song.228000.json','["昔人讀書松竹林，今之書林乃無竹。", "有松無竹何不可，松亦元同借鄰燭。", "十年人事桑田變，隔舍丁丁斧斤蹙。", "歸來窗下一燈青，夜半林空山鬼哭。", "乃知藝木印歲寒，不似閉門繙故牘。", "客來若問子孫枝，窗間正有聲吾伊。"]'),
('2b28f377-bb88-479c-8073-1a596739097b','尤物','陳杰','宋','宋诗','song-poetry','','[]','隋珠和璧碎一斧，尤物在鎔堪萬古。',144,'全唐诗/poet.song.228000.json','["隋珠和璧碎一斧，尤物在鎔堪萬古。", "王陽巾㡚捲握多，顧家之穴董家塢。", "天生五材貴民用，饑不可糜寒不縷。", "願天一拔好愛本，與世潛消禍亂祖。", "神奇淮南化爲寶，談笑蕭齊價同土。", "盡收地力作陰産，剩長桑麻富禾黍。", "貨無難得平斗量，行或不齎扣門與。", "遼東獻豕易厭欲，崑山抵鵲誰爭所。", "建德老死不往來，蠻觸長辭血流杵。"]'),
('6f509963-2cb1-4512-8aee-95071a513f76','送彭萊山談星','陳杰','宋','宋诗','song-poetry','','[]','潁川賢人聚無聚，德行何裨理亂數。',104,'全唐诗/poet.song.228000.json','["潁川賢人聚無聚，德行何裨理亂數。", "吳中高士死不死，少微何與興亡事。", "古來觀星觀用星，閒劇災祥一羽輕。", "渾儀圖上無人會，兩曜五行四餘外。", "有福星力關世大，一夕煩君十起看。", "光芒看取十分端，百千萬億蒼生命，由來都在上頭安。"]'),
('c07e9d1a-6fd9-4d30-ba4d-e5d4b41816ea','題點易窗道人蘇門遺嘯','陳杰','宋','宋诗','song-poetry','','[]','書來草木吾臭味，詩有膽氣非黄冠。',64,'全唐诗/poet.song.228000.json','["書來草木吾臭味，詩有膽氣非黄冠。", "清溪研露一雙鶴，蘇門嘯空千仞鸞。", "愁連青燐引觴醉，憤入白虹提劍看。", "誰識道人心最苦，半壇霜月夜漫漫。"]'),
('3506c7da-90e9-454f-abe2-f826796dc523','猛虎行','陳杰','宋','宋诗','song-poetry','','[]','北平山頭羽穿石，將軍醉眼橫夜色。',184,'全唐诗/poet.song.228000.json','["北平山頭羽穿石，將軍醉眼橫夜色。", "高堂白晝坐眈眈，想見負嵎俱辟易。", "銅鐶鎖深雙古槐，霍地嘯舞含風雷。", "三生得非故人積，變化爲我騰空來。", "目光射庭威百步，童奴近前初不怒。", "再三未敢尺箠麾，生綃張羅紅打圍。", "頭如可編鬚可捋，約莫留皮是渾脫。", "世上丹青得許神，向來葉公龍乃真。", "笑渠檻中直摇尾，不動齒牙猶咀爾。", "乾坤意氣空崢嶸，饑鼠倒齧雲母屏，論功有不如狸狌。", "人間猛者何暇像，韓公歌行最知狀。"]'),
('7b38ff84-b7f2-4efe-8c47-275e475f5834','客談矩山大資近事近詩及新相麻云欲浮海以安歸走筆附訊','陳杰','宋','宋诗','song-poetry','','[]','客有云自矩山來，急欲問公起虛左。',80,'全唐诗/poet.song.228000.json','["客有云自矩山來，急欲問公起虛左。", "能言近履殊快活，更誦新篇極精妥。", "奚奴添箇富錦囊，樊子遣餘疏藥裹。", "田租不及胡椒斛，壽數行多念珠顆。", "江濤惱殺浮海翁，野水白鷗閒似我。"]'),
('e9d45bd2-2793-476e-9343-02d851749a40','南山青','陳杰','宋','宋诗','song-poetry','','[]','天公研黛朝染山，天女戲手雙娥彎，挼絲試青墜人間。',72,'全唐诗/poet.song.228000.json','["天公研黛朝染山，天女戲手雙娥彎，挼絲試青墜人間。", "年時春山未著色，十萬野條先弄碧。", "天公一笑不汝爭，白華吹盡秋風生。", "膚寸長含八分雨，南山與天青萬古。"]'),
('7fb8cf9f-c39d-4c47-9a55-32eac1a1863d','羅壽可再如舊都作歸來窗以爲親悅勸之歸者皆是予特下轉語焉','陳杰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','玉門關冷風低草，浪泊水西看飛鳥。',112,'全唐诗/poet.song.228000.json','["玉門關冷風低草，浪泊水西看飛鳥。", "柴桑松菊坐來荒，杜曲桑麻隨分有。", "封侯作夢嗟晚歲，吟詩無功成白首。", "驀波一葉故都懷，短世閒身髮方黝。", "未省匡山幾卷書，能勝平樂千金酒。", "白雲舍下綺疏新，行止隨時總悅親。", "君家所有吾猶贈，已負東洋北海身。"]'),
('f33fd78d-599a-4d46-8be4-2a745f79b783','林告院伯文送菊大如蓋予謂惟黄繖兩字可極形容遂賦','陳杰','宋','宋诗','song-poetry','','[]','碧玉琢幹如拇大，黄金縷花三萬箇。',192,'全唐诗/poet.song.228000.json','["碧玉琢幹如拇大，黄金縷花三萬箇。", "下如弗勝下如幬，疾風過前不少撓。", "園丁結束無餘枝，詩翁打量四十圍。", "放渠疎散得自性，十本奚啻專百畦。", "人間籬落殊短淺，曷不歸來上林苑。", "兩螭侍臣慣在眼，朝旭亭亭照黄繖。", "厥封黑土大斗盛，階南尺五喘兩黥。", "避堂以舍虛左迎，畫梁素壁生晶熒。", "百匝環之三太息，生物何私培植力。", "輪囷正色根極香，桃李爭春笑人寂。", "三葩五蘂好事家，問渠曾識如許花。", "相逢白眼花無恙，千載無人識元亮。"]'),
('eb120263-8391-4051-a111-19a018feef92','題王書史百鴈圖','陳杰','宋','宋诗','song-poetry','','[]','黄蘆落木寒颼飀，平沙占斷江天秋。',88,'全唐诗/poet.song.228000.json','["黄蘆落木寒颼飀，平沙占斷江天秋。", "嗷嗷累百來未休，宛頸相樂飛相求。", "其中各有稻粱謀，落旄海上霜滿裘，不肯爲渠作書郵。", "南去雲峰有盡頭，北歸矰弋正多憂。", "冥鴻高哉獨無儔，祁連將軍生暮愁。"]'),
('cb64177f-48bc-48da-8363-e537ab65d00c','題寄傲軒','陳杰','宋','宋诗','song-poetry','','[]','富貴驕人擁廬兒，寒士不遜原壤夷。',72,'全唐诗/poet.song.228000.json','["富貴驕人擁廬兒，寒士不遜原壤夷。", "傲稱凶德無適宜，長者寄爾渠得知。", "使襪聊爲廷尉重，命履乃有帝師用，苟非其人千仞鳳。", "鸚鵡洲前弔月明，歸來痛飲師劉伶。"]'),
('b2b4c95b-6181-4101-a0ee-a02e8239d3bd','淮南聽雨歌','陳杰','宋','宋诗','song-poetry','','[]','前簷看雨如銀竹，後簷聽雨如瀉瀑。',112,'全唐诗/poet.song.228000.json','["前簷看雨如銀竹，後簷聽雨如瀉瀑。", "九衢對面起波濤，昨日黄埃一丈高。", "書生生無快意事，天公覆手爲辦此。", "邂逅一愜吾已多，千家萬家豐年歌。", "三更不寐凉如水，清愁宛轉秋風起。", "壯士天河更洗兵，皇威海岱一時清。", "幅巾歸去江南好，長卧東皋聽雨聲。"]'),
('293dad56-e334-489c-92ab-1c935e576d5c','金谷客','陳杰','宋','宋诗','song-poetry','','[]','脫舊著新金谷客，力能除蛟并白額。',64,'全唐诗/poet.song.228000.json','["脫舊著新金谷客，力能除蛟并白額。", "家養飛飛角傅翼，天下風塵兒亦得。", "高才疾足長歎息，御卿無權挽無力。", "可人可人與游辟，出門實繁九千跖。"]'),
('2fe88b71-d1a4-4c1c-b19e-97142f17d77d','雪禁體','陳杰','宋','宋诗','song-poetry','','[]','南風導前北風續，仁氣潜隨殺機伏。',160,'全唐诗/poet.song.228000.json','["南風導前北風續，仁氣潜隨殺機伏。", "初疑慘淡八表昏，忽變光明大千足。", "上天之載德如毛，帝力不知封比屋。", "垢汙過眼俱衣被，枯朽何心亦膏沐。", "調治竹君折節下，表顯梅兄受命獨。", "於至嚴凝見溫厚，有大包容分類族。", "是空非空色非色，在坑滿坑谷滿谷。", "鋪張元化有許奇，收斂神功又何速。", "欲搜好句極形容，回首千章成淺俗。", "夜深獸紅妓打圍，雪消雪落何用知。"]'),
('f59df2a8-1cbc-44fd-a30e-755584740b79','讀蘇武傳','陳杰','宋','宋诗','song-poetry','','[]','伸脚踏沙蹟，開口喫漢天。',60,'全唐诗/poet.song.228000.json','["伸脚踏沙蹟，開口喫漢天。", "見天不見雪，况辨雪與氈。", "環觀不敢殺，謂是不死仙。", "漢庭方求不死訣，方士取露和玉屑，何如老臣氈夾雪。"]'),
('82649358-1854-4634-9928-54278de668b7','昭君怨','陳杰','宋','宋诗','song-poetry','','[]','玉筯暈深宮領巾，金槽夜琤出塞新。',96,'全唐诗/poet.song.228000.json','["玉筯暈深宮領巾，金槽夜琤出塞新。", "風沙隴上歲摇碧，一掬猶殘長樂春。", "六奇計醜書來慢，曾是控弦三十萬。", "沼仇無術遣蛾眉，此日天驕更須豢。", "黄鵠傳歌天爲悲，邊笳按拍鵲南飛。", "琵琶遠恨無人省，灼面東家曉粧影。"]'),
('e0530047-dce1-4c96-9716-c75f7efbb1c3','乙丑元日壽昌拜表','陳杰','宋','宋诗','song-poetry','','[]','盛服黎明起，瞻天咫尺東。',48,'全唐诗/poet.song.228000.json','["盛服黎明起，瞻天咫尺東。", "舒遲寅出日，清淑艮來風。", "陰盡恰亭午，景長疑再中。", "初元調玉燭，勉勉聖神功。"]'),
('a4f2643f-0189-4311-a5fb-184c9e24958a','天基節特晴','陳杰','宋','宋诗','song-poetry','','[]','東風特地奇，閣雨放朝曦。',48,'全唐诗/poet.song.228000.json','["東風特地奇，閣雨放朝曦。", "歷數歸仁壽，乾坤表誕彌。", "願敷皇極福，重立太平基。", "忠愛無疎賤，新年第一詩。"]'),
('28028e70-887d-40c7-9b25-e18e0b94430e','壽昌元夕建醮','陳杰','宋','宋诗','song-poetry','','[]','鑪穟無風直，燈蓮有月嬌。',48,'全唐诗/poet.song.228000.json','["鑪穟無風直，燈蓮有月嬌。", "我常占樂歲，人自看元宵。", "印信烽煙息，光輝玉燭調。", "平生笑徼福，今夕爲民徼。"]'),
('d7722d7f-4dec-48b7-9975-e215bb4f28eb','蘇湖道間','陳杰','宋','宋诗','song-poetry','','[]','風物瞻天咫，林塘占地幽。',48,'全唐诗/poet.song.228000.json','["風物瞻天咫，林塘占地幽。", "夾牆樓蔭術，跨岸屋藏舟。", "湖近家皆給，田腴歲再秋。", "幸生無事日，更隸浙西州。"]'),
('11966683-2c7a-4b73-a020-038b0acfce6a','送張教授赴廣闕','陳杰','宋','宋诗','song-poetry','','[]','遠戍不辭難，書生本色官。',48,'全唐诗/poet.song.228000.json','["遠戍不辭難，書生本色官。", "炎埃五嶺熱，夜雨一氈寒。", "鄉信無鴻到，梅花當雪看。", "風雲忽諧偶，擊海起鵬摶。"]'),
('afb0ef09-b68f-437b-9d02-3e6ad29797a0','大享先玄酒','陳杰','宋','宋诗','song-poetry','','[]','大享先玄酒，嘉賓貴食蒿。',48,'全唐诗/poet.song.228000.json','["大享先玄酒，嘉賓貴食蒿。", "不無籩豆實，正有澗溪毛。", "歲未登三鬴，家安取百牢。", "充庭君試數，一一是民膏。"]'),
('b69256d1-f69f-4d9a-a533-253ea5d60af8','寄黄思梅就別祖德','陳杰','宋','宋诗','song-poetry','','[]','間闊長回首，伻來忽嗣音。',48,'全唐诗/poet.song.228000.json','["間闊長回首，伻來忽嗣音。", "故人今有子，吾輩數論心。", "歲晏懷甘旨，年衰毖枕衾。", "殷勤各彊健，春在北枝深。"]'),
('2f61aa2d-07b3-41c1-9968-3e4e25fd18f0','冶城清談','陳杰','宋','宋诗','song-poetry','','[]','西周固羸國，東轍幾孱王。',48,'全唐诗/poet.song.228000.json','["西周固羸國，東轍幾孱王。", "信有親親弱，終無善善亡。", "精詳隋五教，疎略漢三章。", "始悟清談相，嘉言味最長。"]'),
('7be4a4fc-debe-4833-b6c4-6b308b43bebf','題濂溪畫像','陳杰','宋','宋诗','song-poetry','','[]','睟盎真元會，揚休沕穆宣。',48,'全唐诗/poet.song.228000.json','["睟盎真元會，揚休沕穆宣。", "定非三代下，自得六經先。", "翠草紅蓮地，光風霽月天。", "幾神千載悟，紙上更須圈。"]'),
('6ee5463a-93e1-4c04-bd43-9ebd70fcd45f','題思婦','陳杰','宋','宋诗','song-poetry','','[]','碧天無過鴈，芳草靜遊人。',48,'全唐诗/poet.song.228000.json','["碧天無過鴈，芳草靜遊人。", "深院綠雲曉，滿階紅雨春。", "釵鸞慵照影，簫鳳暗棲塵。", "鄰女焉知事，終朝學美矉。"]'),
('3008bf1f-8f73-4371-88bd-451b57706caa','大閫撥醅于園亭坐上文武各半恰西師捷至用同官韻','陳杰','宋','宋诗','song-poetry','','[]','花氣深迷院，湖光曲抱城。',48,'全唐诗/poet.song.228000.json','["花氣深迷院，湖光曲抱城。", "淺春烽火暇，細雨笑談清。", "舁甕看浮蟻，飛書報斬鯨。", "漁陽迴席處，半著魯諸生。"]'),
('1371d8cb-53ba-48af-af2e-7b27c6627e52','請代','陳杰','宋','宋诗','song-poetry','','[]','郡小凋殘最，兵餘旱疫仍。',48,'全唐诗/poet.song.228000.json','["郡小凋殘最，兵餘旱疫仍。", "不能無獄訟，但見可哀矜。", "卿自別利器，吾猶治亂繩。", "新林有孳尾，珍重莫呼鷹。"]'),
('fbf055b4-4bf0-4333-a59d-74b964e8c227','江亭秋思','陳杰','宋','宋诗','song-poetry','','[]','江闊初寒雨，天高欲委秋。',48,'全唐诗/poet.song.228000.json','["江闊初寒雨，天高欲委秋。", "輕陰明遠巘，晚色澹平疇。", "桂樹幽人屋，蘆花釣叟舟。", "人生足清事，長遣意悠悠。"]'),
('8327da3c-3cbf-4302-8a0e-ba4f2a05b137','江亭小憩','陳杰','宋','宋诗','song-poetry','','[]','遠樹依山瘦，空江抱郭斜。',48,'全唐诗/poet.song.228000.json','["遠樹依山瘦，空江抱郭斜。", "水雲涵鴈影，晴雪落梅花。", "經歲長爲客，方春最憶家。", "又持五字律，草草答年華。"]'),
('8f23fd6d-6918-4ed1-aa86-657ed0535a60','荆州雪','陳杰','宋','宋诗','song-poetry','','[]','荆州寒氣盛，一尺雪花圍。',48,'全唐诗/poet.song.228000.json','["荆州寒氣盛，一尺雪花圍。", "賞覺心猶在，餐憐齒寖非。", "蔡功裴度入，剡興子猷歸。", "豈不俱奇事，微醺訊玉妃。"]'),
('bc5d1d3a-dae4-47b4-bac8-94b1d616e237','宣檄隨府初程得風','陳杰','宋','宋诗','song-poetry','','[]','泝楚三千里，離淮第一程。',48,'全唐诗/poet.song.228000.json','["泝楚三千里，離淮第一程。", "海潮隨意送，江月打頭迎。", "西事端無恙，東風故有情。", "篙師渾未解，掛席亦歡聲。"]'),
('9f66dd8f-3fe1-4aaf-9706-b4c1d7a9c04c','重宿城頭驛','陳杰','宋','宋诗','song-poetry','','[]','天地秋聲早，山河夜色深。',48,'全唐诗/poet.song.228000.json','["天地秋聲早，山河夜色深。", "市荒餘冷銼，村迥落孤砧。", "紙帳三生夢，蒲團萬古心。", "漫漫獨無旦，微步數看參。"]'),
('2b68fdf9-71b2-481e-85be-04d161436a00','斗牛山登高','陳杰','宋','宋诗','song-poetry','','[]','佳節一消憂，携壺上斗牛。',48,'全唐诗/poet.song.228000.json','["佳節一消憂，携壺上斗牛。", "乾坤有今日，江漢自東流。", "亂後不多菊，看來無限秋。", "憑高未能已，更爲夕陽留。"]'),
('16141c07-a39f-4d4e-a11a-1176ac901362','山村','陳杰','宋','宋诗','song-poetry','','[]','喬木藏村古，枯藤取逕微。',48,'全唐诗/poet.song.228000.json','["喬木藏村古，枯藤取逕微。", "落紅隨蠟屐，空翠近荷衣。", "抱甕雲間出，吹簫月下歸。", "桃源吾酷慕，何必此間非。"]'),
('e79fb93f-b6fc-4b0c-b1c1-0978c115cb01','景陵湖中宿人村','陳杰','宋','宋诗','song-poetry','','[]','孤撐出叢葦，小泊得疎林。',48,'全唐诗/poet.song.228000.json','["孤撐出叢葦，小泊得疎林。", "兩岸桑麻地，一川楊柳陰。", "鷺拳沙磧遠，人語竹籬深。", "惟有波間月，照予行役心。"]'),
('213d0a5c-71ec-4ce4-955e-5ccf087cff33','冬至攝獻于郊','陳杰','宋','宋诗','song-poetry','','[]','夙駕恭深詔，圓壇儼博臨。',48,'全唐诗/poet.song.228000.json','["夙駕恭深詔，圓壇儼博臨。", "獻班公位亞，冊捧帝書欽。", "星象開明曜，神靈畢顧歆。", "極知祈永命，猶願戒難諶。"]'),
('13a24733-a7d9-4193-8194-db68931e1b08','出郊','陳杰','宋','宋诗','song-poetry','','[]','飛蓋籠晴晝，行厨帳遠林。',48,'全唐诗/poet.song.228000.json','["飛蓋籠晴晝，行厨帳遠林。", "柳塘風度絮，花逕日移陰。", "翠袖穿紅迥，清歌繞綠深。", "獨將衰晚意，危坐數雲岑。"]'),
('ecd0b8a7-3b44-4bd8-be2c-952560d0c4e1','和葉宋英','陳杰','宋','宋诗','song-poetry','','[]','風葉靜千林，歸根深復深。',48,'全唐诗/poet.song.228000.json','["風葉靜千林，歸根深復深。", "江山皆本色，天地見初心。", "苓少和冰斸，梅殘带雪吟。", "人間正彫落，春在二陽臨。"]'),
('36ba49e9-a982-4303-aa24-aee56a2e56e8','東湖夜坐松間','陳杰','宋','宋诗','song-poetry','','[]','夜深仍露坐，湖曲小迷藏。',48,'全唐诗/poet.song.228000.json','["夜深仍露坐，湖曲小迷藏。", "松月半身影，藕花三面香。", "雖忘入城府，終擬卜林塘。", "何日清逋賊，妖星漸不芒。"]'),
('98e2861a-1db9-4723-a7dc-ca03b597b2fa','送朱靖州','陳杰','宋','宋诗','song-poetry','','[]','渠水咨良牧，金臺輟上賓。',48,'全唐诗/poet.song.228000.json','["渠水咨良牧，金臺輟上賓。", "山川今後戶，蠻獠亦吾人。", "保障一方寄，袴襦千里春。", "西師足家問，吉語寄郵頻。"]'),
('9cd7e09f-cdc0-4889-8592-049c205b7f13','餞西北流寓士舟赴南省','陳杰','宋','宋诗','song-poetry','','[]','天馬從西極，雲鵬起北溟。',48,'全唐诗/poet.song.228000.json','["天馬從西極，雲鵬起北溟。", "黍離懷故國，風景過新亭。", "文物衣冠會，山河廟社靈。", "獨無中上策，一聳漢臣聽。"]'),
('71e98c3b-ff0c-4c82-b8e4-956aec910b30','冬晴散步','陳杰','宋','宋诗','song-poetry','','[]','入夜朔風烈，出門黄葉深。',48,'全唐诗/poet.song.228000.json','["入夜朔風烈，出門黄葉深。", "霜曦開暢月，雪蘤動陽林。", "冬暖兒童色，時和父老心。", "百年吾此日，乘健數經尋。"]'),
('6210e7b4-a137-4a91-8460-4c821ab32eab','初出大江移泊別浦','陳杰','宋','宋诗','song-poetry','','[]','水宿乍移浦，客程初望鄉。',48,'全唐诗/poet.song.228000.json','["水宿乍移浦，客程初望鄉。", "江涵鷗夢闊，天入鴈愁長。", "漢月關山白，淮雲草樹蒼。", "東遊何限意，搔首聽鳴榔。"]'),
('c67d4afa-9ed8-403d-9dba-bbeec973d3bc','歸夢','陳杰','宋','宋诗','song-poetry','','[]','人事擾多智，天機行不言。',49,'全唐诗/poet.song.228000.json','["人事擾多智，天機行不言。", "庭榴華就實，梁燕子生孫。", "西嶺千家月，南湖百丈潭。", "晚風吹䆉稏，歸夢繞江村。"]'),
('b4cf67dd-d684-453b-94ec-b3af50bb1d28','孔明','陳杰','宋','宋诗','song-poetry','','[]','千載生諸葛，餘才了十丕。',48,'全唐诗/poet.song.228000.json','["千載生諸葛，餘才了十丕。", "百年巴蜀佐，三代渭濱師。", "禮樂無興日，乾坤有閏時。", "空留文字在，不愧說兼伊。"]'),
('8d5908b6-2b23-4a91-be03-322bcc87748b','仲宣樓','陳杰','宋','宋诗','song-poetry','','[]','地大中原接，天低七澤浮。',48,'全唐诗/poet.song.228000.json','["地大中原接，天低七澤浮。", "山川元用武，離亂一登樓。", "平遠難爲畫，高寒易得秋。", "無言雙野鶩，相對抱清愁。"]'),
('e81cc18e-192f-4a8c-be81-e164187be930','曉登吳山二首  其一','陳杰','宋','宋诗','song-poetry','','[]','海水朝天白，宮雲捧日紅。',48,'全唐诗/poet.song.228000.json','["海水朝天白，宮雲捧日紅。", "衣冠四方極，正朔九夷通。", "矢射狼星北，旗迎太乙東。", "側聞南渡意，暫與去邠同。"]'),
('0c0bd404-ffd3-4409-bbbe-16def4695b05','曉登吳山二首  其二','陳杰','宋','宋诗','song-poetry','','[]','漢鼎猶分二，梁甌未闕全。',48,'全唐诗/poet.song.228000.json','["漢鼎猶分二，梁甌未闕全。", "宸居本無外，王業偶成偏。", "藝祖肇千祀，嫡孫方四傳。", "會將新雨露，遍灑舊山川。"]'),
('4e94a366-b557-4e48-b39f-c5eaca62e376','郊行小憩','陳杰','宋','宋诗','song-poetry','','[]','嵐氣深籠屋，機聲細出林。',48,'全唐诗/poet.song.228000.json','["嵐氣深籠屋，機聲細出林。", "落花流水逕，芳草短牆陰。", "啼鳥招人處，斜陽過客心。", "明朝坐曹去，拄頰盼遥岑。"]'),
('d3260225-bea6-46a8-8b01-880511ac8a33','送安常簿','陳杰','宋','宋诗','song-poetry','','[]','怪來留滯久，世尚識斯人。',48,'全唐诗/poet.song.228000.json','["怪來留滯久，世尚識斯人。", "雨露元深厚，龍蛇互屈伸。", "定無綿蕞習，富有治安陳。", "華要方從始，青雲自立身。"]'),
('f4b8e8f1-e182-492a-b3ad-5c0348a05f71','天人','陳杰','宋','宋诗','song-poetry','','[]','天上分明暗，人間浪喜嗔。',48,'全唐诗/poet.song.228000.json','["天上分明暗，人間浪喜嗔。", "及魚殃本妄，得馬福非真。", "酒薄還圍趙，渠成適利秦。", "聖賢惟任道，兩不繫天人。"]'),
('13ca0ff2-dab6-4c3f-96ed-81d02e50113d','寓舍瓊花一株盛開','陳杰','宋','宋诗','song-poetry','','[]','疑是瑶林種，分從后土家。',48,'全唐诗/poet.song.228000.json','["疑是瑶林種，分從后土家。", "暫來爲地主，相伴住天涯。", "勝日更携酒，明年誰看花。", "此生均一寄，杜曲有桑麻。"]'),
('f90618c2-01d8-4db7-a171-e18bb6fb6a5f','送程楚翁歸歙用其韻','陳杰','宋','宋诗','song-poetry','','[]','木落見江空，星回屬紀窮。',48,'全唐诗/poet.song.228000.json','["木落見江空，星回屬紀窮。", "畏途兵雜盜，急景雪兼風。", "問學嗟遊子，論交愧老翁。", "歸來富千古，此理此心同。"]'),
('818d5b44-c285-4838-ab02-c3518cfa74c4','酬西山龔學諭','陳杰','宋','宋诗','song-poetry','','[]','畏人兼憚暑，息影正逃空。',48,'全唐诗/poet.song.228000.json','["畏人兼憚暑，息影正逃空。", "忽訝衣冠古，還欣臭味同。", "带來西嶺雪，睡起北窗風。", "雙璧無嘉報，懷斤愧郢工。"]'),
('f746d493-9efe-4c85-b372-158fbeae1718','追哭泉谷徐侍郎墓','陳杰','宋','宋诗','song-poetry','','[]','更化公初召，將行我賦詩。',48,'全唐诗/poet.song.228000.json','["更化公初召，將行我賦詩。", "呼兒同肅客，謂子亦憂時。", "不盡相於意，而無再見期。", "些章慙拱木，亦復歎吾衰。"]'),
('8c841865-8090-491a-b867-9eeffb205da9','爲農','陳杰','宋','宋诗','song-poetry','','[]','去國已爲農，憂時但願豐。',48,'全唐诗/poet.song.228000.json','["去國已爲農，憂時但願豐。", "目光牛背上，世事草廬中。", "絕異炰羔惲，聊如藝黍通。", "新來詩亦變，稍稍近豳風。"]'),
('963e809e-f680-4c71-8d34-13fc90612021','和後林寄以夢中不知天盡頭之韻','陳杰','宋','宋诗','song-poetry','','[]','老子卧林丘，憂時雪滿頭。',48,'全唐诗/poet.song.228000.json','["老子卧林丘，憂時雪滿頭。", "詩筒自江社，句律到夔州。", "把菊青山晚，看雲白日流。", "至人安有夢，八極偶神遊。"]'),
('61ba83ee-6645-4908-9007-ed8afa1eefea','出關和雷侍郎送行無魔不成佛觀過始知仁之句','陳杰','宋','宋诗','song-poetry','','[]','事來思爛熟，罪去得深循。',48,'全唐诗/poet.song.228000.json','["事來思爛熟，罪去得深循。", "天壤嗟微義，風霜本至仁。", "十年江社夢，一道雪梅春。", "回首無他囑，當言莫愛身。"]'),
('4224fefa-1b1e-42cc-8aac-7bb5ec5abd62','和陳別魁元吉','陳杰','宋','宋诗','song-poetry','','[]','窮有詩劘壘，愁無酒盪城。',48,'全唐诗/poet.song.228000.json','["窮有詩劘壘，愁無酒盪城。", "艱虞開口笑，邂逅倒衣迎。", "朔雪殘榆柳，東風拂燕鶑。", "一樽何日醁，重論不嫌精。"]'),
('a9c63188-406f-4b6b-8f8a-a4f3bc517958','懋勳挽辭','陳杰','宋','宋诗','song-poetry','','[]','即墨當交困，金城請自行。',48,'全唐诗/poet.song.228000.json','["即墨當交困，金城請自行。", "劍方及蒲外，星遽隕中營。", "遺恨羊碑淚，忠魂晉柩聲。", "成謀授宿將，穩爲了殘枰。"]'),
('8a18d789-94b6-43fb-b6c2-183f431b5397','理考挽詞','陳杰','宋','宋诗','song-poetry','','[]','藝祖的孫傳，仁皇享國年。',48,'全唐诗/poet.song.228000.json','["藝祖的孫傳，仁皇享國年。", "思文重揭日，皇武再中天。", "多難扶三正，彌留痛八埏。", "乾坤理最大，高益帝王前。"]'),
('3fdd617f-6746-41a6-b734-8b95c5be8046','黄茶陵死寇吳荆溪作碑祭文云斥彼懦夫提此英魄爲賦詩以挽之','陳杰','宋','宋诗','song-poetry','','[]','十年三令尹，王事厄還期。',48,'全唐诗/poet.song.228000.json','["十年三令尹，王事厄還期。", "只爲生人重，非貪死節奇。", "冷雲回鴈處，妖雨泣鵑時。", "提得英魂在，邦侯一片碑。"]'),
('c1e118fa-00e2-4f5e-9ed9-94d03036bc7c','太上務德','陳杰','宋','宋诗','song-poetry','','[]','太上務爲德，後來紛立言。',48,'全唐诗/poet.song.228000.json','["太上務爲德，後來紛立言。", "誰非託鄒魯，甯復得羲軒。", "吾愛黄叔度，人稱李仲元。", "典刑如可作，庶用約文煩。"]'),
('eb3e3f7d-b7a0-405e-ba87-7d730e5ad4cb','春晝睡起','陳杰','宋','宋诗','song-poetry','','[]','柳影年華度，鶑聲午夢回。',48,'全唐诗/poet.song.228000.json','["柳影年華度，鶑聲午夢回。", "空牀靜看易，滿席澹凝埃。", "隠几野花落，閉門山雨來。", "無人見愁緒，歡伯一樽開。"]'),
('ef0d2bd4-9e55-482b-a0f4-c5d65200763b','探梅','陳杰','宋','宋诗','song-poetry','','[]','要識梅孤絕，花於未葉時。',48,'全唐诗/poet.song.228000.json','["要識梅孤絕，花於未葉時。", "玲瓏寒玉片，點綴古銅枝。", "初雪落旄節，始刪無傳詩。", "東風一吹綠，萬卉更能奇。"]'),
('689983a0-0cf7-4696-a827-30e9849b55a6','贈孫仙輩','陳杰','宋','宋诗','song-poetry','','[]','株峰紫翠邊，仙已住三年。',48,'全唐诗/poet.song.228000.json','["株峰紫翠邊，仙已住三年。", "手有屠龍技，腰無跨鶴錢。", "地圖藏尚秘，山屐著多穿。", "笑指青囊道，人家要福田。"]'),
('bb63f8b9-ae0d-4adb-b141-5d1ec47a65ac','和蕭太秀中秋月言內事','陳杰','宋','宋诗','song-poetry','','[]','每番昏見甲，茲夕兌中天。',48,'全唐诗/poet.song.228000.json','["每番昏見甲，茲夕兌中天。", "金水光初滿，山河影正全。", "娥曾分大藥，兔敢笑華顛。", "還見乘槎使，重來犯斗年。"]'),
('738e2784-379c-4e82-b208-aff050aab698','客來','陳杰','宋','宋诗','song-poetry','','[]','院靜塵囂隔，閒看砌長苔。',48,'全唐诗/poet.song.228000.json','["院靜塵囂隔，閒看砌長苔。", "新晴農乍急，舊雨客能來。", "適報提壺勸，還驚布穀催。", "窮居有先務，一笑且持杯。"]'),
('c98f5e17-9ffd-4495-a6f4-77128da05f52','送客','陳杰','宋','宋诗','song-poetry','','[]','信屐倦仍還，詩生暮靄間。',48,'全唐诗/poet.song.228000.json','["信屐倦仍還，詩生暮靄間。", "塘蒲身共晚，野鶴意俱閒。", "送客度流水，見雲歸別山。", "一聲長嘯遠，吾亦掩柴關。"]'),
('8cca56ba-050d-4767-8246-7e15f24cd749','挽洛陽李教授喪北歸','陳杰','宋','宋诗','song-poetry','','[]','華閥晁科峻，寒氈洛學開。',48,'全唐诗/poet.song.228000.json','["華閥晁科峻，寒氈洛學開。", "燕山庭五桂，晉國手三槐。", "風幕南烹養，塗車北首哀。", "讀書終不憾，九秩過江來。"]'),
('7c85c069-4d16-4c2a-b63a-b95a952321a2','醉鄉','陳杰','宋','宋诗','song-poetry','','[]','酒亦有何好，離人而趣天。',48,'全唐诗/poet.song.228000.json','["酒亦有何好，離人而趣天。", "乾坤撥醅甕，世界拍浮船。", "魯趙移兵隙，淮澠互霸權。", "醉鄉知許事，蜾蠃過吾前。"]'),
('4bcded65-4d19-4555-8516-036610a02618','挽念齋陳郎中','陳杰','宋','宋诗','song-poetry','','[]','少學真華國，郎潛劣晚逢。',48,'全唐诗/poet.song.228000.json','["少學真華國，郎潛劣晚逢。", "幾看新貴駛，獨抱古文終。", "夢事一丘盡，遺編千載公。", "空餘細論恨，裳錦玉樓東。"]'),
('a085a428-f658-4f52-8045-e01d814dcd28','挽雲屋徐侍郎','陳杰','宋','宋诗','song-poetry','','[]','回首前臺諫，寒心事阽危。',48,'全唐诗/poet.song.228000.json','["回首前臺諫，寒心事阽危。", "著高棋敗後，力盡厦顛時。", "國論家無稿，民庸路有碑。", "絮觴成阻絕，灑淚對傾曦。"]'),
('17977620-87b4-4cba-87de-5618dbd71208','登鍾山憩定林','陳杰','宋','宋诗','song-poetry','','[]','禾黍古離宮，荒畦屈曲通。',48,'全唐诗/poet.song.228000.json','["禾黍古離宮，荒畦屈曲通。", "語音京洛近，王氣海潮東。", "山色餘蕭寺，松聲尚晉風。", "興亡不可詰，太息定林翁。"]'),
('7ee7a5a9-b0cc-4049-97ba-2ea6ddb939a2','夜發吳城渡','陳杰','宋','宋诗','song-poetry','','[]','秋風江上生，秋月渡頭明。',48,'全唐诗/poet.song.228000.json','["秋風江上生，秋月渡頭明。", "人地籟俱寂，水天心共清。", "一雙斜閣艣，二百順流程。", "已泊還佳寐，城頭劣四更。"]'),
('ae8b4006-42dd-4635-9e16-e191e47955e0','熊校尉挾名畫來淮得官辭歸','陳杰','宋','宋诗','song-poetry','','[]','同是飲玻人，均爲騎鶴身。',48,'全唐诗/poet.song.228000.json','["同是飲玻人，均爲騎鶴身。", "我無錢使鬼，君有畫通神。", "客夢黄粱熟，邊愁白髮新。", "歸帆過鷗社，爲拂釣簑塵。"]'),
('3ad19e67-8fc4-4496-b9a1-c3885aa50e09','訊給事徐尚書自除知制誥歸','陳杰','宋','宋诗','song-poetry','','[]','書生稽古力，詞苑久虛名。',48,'全唐诗/poet.song.228000.json','["書生稽古力，詞苑久虛名。", "聊遠三台逼，非貪一佛榮。", "乃身自本末，豈果有虧成。", "不盡明時報，歸來頌太平。"]'),
('e28f8cb0-8168-47ff-8103-65a656312692','宿東林寺','陳杰','宋','宋诗','song-poetry','','[]','遠公招隠處，宿我上方雲。',48,'全唐诗/poet.song.228000.json','["遠公招隠處，宿我上方雲。", "夜永地祇出，谷虛天籟聞。", "挑燈過鴈盡，得句曉窗分。", "不寐關何事，幽棲意自欣。"]'),
('2986d253-53eb-4689-bbc6-4b52164e6de1','江頭閒行送去客','陳杰','宋','宋诗','song-poetry','','[]','正有尋梅約，今朝此見梅。',48,'全唐诗/poet.song.228000.json','["正有尋梅約，今朝此見梅。", "小停剡溪棹，更盡渭城杯。", "人物良堪惜，山川會復來。", "前村風雪夜，歸意莫生埃。"]'),
('40f45d67-fb84-430d-9eab-a992238f9315','揚子橋送客浮湘','陳杰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','客裏還分袂，樽前小繫舟。',48,'全唐诗/poet.song.228000.json','["客裏還分袂，樽前小繫舟。", "笛聲揚子曉，帆色洞庭秋。", "萬里身爲本，中年別作愁。", "乾坤多事在，何日各林丘。"]'),
('0b0b1f6e-e825-4224-bf24-23768f168ba7','挽李司諫','陳杰','宋','宋诗','song-poetry','','[]','論建關時大，幾微犯怨深。',48,'全唐诗/poet.song.228000.json','["論建關時大，幾微犯怨深。", "功名歸厚福，歲月老初心。", "自以無前劍，那知不鼓琴。", "空留忠憤在，斜月暮雲陰。"]'),
('ba45b590-df23-4600-a3af-6622dfe9055e','吳真州屢交詩而不及見告去送別','陳杰','宋','宋诗','song-poetry','','[]','論心曾未面，惜別重相於。',48,'全唐诗/poet.song.228000.json','["論心曾未面，惜別重相於。", "此復失交臂，何當逢下車。", "倚風三弄笛，搔首十年書。", "吟卷歌壺暇，春江足鯉魚。"]'),
('c3ebdbb5-73b2-4e43-8626-ecd15c4118a2','清明日新霽','陳杰','宋','宋诗','song-poetry','','[]','昨夜風雨聲，今朝鳥弄晴。',48,'全唐诗/poet.song.228000.json','["昨夜風雨聲，今朝鳥弄晴。", "光陰殊變態，天地本清明。", "世事觀新火，年華怯冷餳。", "棠梨溪上冢，諸老得無情。"]'),
('8dbba8f7-397e-4c7a-9769-74ed583df0fc','出郭晚回','陳杰','宋','宋诗','song-poetry','','[]','昧谷含凉景，環涂進晚程。',48,'全唐诗/poet.song.228000.json','["昧谷含凉景，環涂進晚程。", "角聲呼月出，鞭影御風行。", "雲樹故多思，暗泉偏有情。", "臨關不得下，回首愧塵纓。"]'),
('d899006c-fc66-4484-9b23-1221fa01cce5','還家父老見迓境上','陳杰','宋','宋诗','song-poetry','','[]','出塞功名薄，還家父老憐。',48,'全唐诗/poet.song.228000.json','["出塞功名薄，還家父老憐。", "尚遲一飯報，又愧五漿先。", "手本平分社，詩堪助種田。", "從今數來往，東陌與西阡。"]'),
('912ec04a-c654-4e86-be6d-93e24331a726','郊行遇鄉人','陳杰','宋','宋诗','song-poetry','','[]','亂後江濱路，跫然客裏聲。',48,'全唐诗/poet.song.228000.json','["亂後江濱路，跫然客裏聲。", "依稀認維梓，邂逅共班荆。", "邑里今安否，親交半死生。", "松楸十年淚，和酒對君傾。"]'),
('fb3abe09-fcb5-4067-9cf6-7638e8bde4da','年華','陳杰','宋','宋诗','song-poetry','','[]','年華機事息，世故妄心空。',48,'全唐诗/poet.song.228000.json','["年華機事息，世故妄心空。", "一笑播糠瞇，多生聞蟻聰。", "體中癡黠半，酒外醉醒同。", "天運端如此，聊師五柳翁。"]'),
('39a299e5-e08d-4b2a-97a2-ce57764f69c4','移居戍將衙','陳杰','宋','宋诗','song-poetry','','[]','細柳連營地，高風昨夜秋。',48,'全唐诗/poet.song.228000.json','["細柳連營地，高風昨夜秋。", "叟兵擐甲歎，中婦寄衣愁。", "白骨閨猶夢，黄丁籍已收。", "江南窮巷士，抵掌說封侯。"]'),
('16142005-0b05-4c71-9e5f-58376c2f39ce','過衢阻潦宿民家','陳杰','宋','宋诗','song-poetry','','[]','暮程聞潦漲，投宿取村斜。',48,'全唐诗/poet.song.228000.json','["暮程聞潦漲，投宿取村斜。", "凉借何方雨，香來隔浦花。", "翁分區種粒，婦進圃抽芽。", "官驛應無此，通宵夢亦佳。"]'),
('43f5fe3c-6f9d-4533-86cc-fc709a7a7dd7','富州花朝用諸老韻','陳杰','宋','宋诗','song-poetry','','[]','鄭重傳河尹，殷勤舍蓋公。',48,'全唐诗/poet.song.228000.json','["鄭重傳河尹，殷勤舍蓋公。", "今安裨議政，昔已坐談空。", "鄉飲干戈後，花朝雨雪中。", "明當移棹去，啼鳥綠怱怱。"]'),
('89e1c1cb-85a2-476b-bdb5-63feb2cd1ea5','送陳知錄赴班改秩','陳杰','宋','宋诗','song-poetry','','[]','相看同味少，又送可人行。',48,'全唐诗/poet.song.228000.json','["相看同味少，又送可人行。", "曉日朝天旆，春江下水程。", "方將有民社，何患不公卿。", "還憶南樓夜，論心霜月明。"]'),
('5538b9f7-e735-4b0d-ba89-8fb8e76446f7','挽劉實齋尚書','陳杰','宋','宋诗','song-poetry','','[]','玉節江湖晚，油幢嶺海春。',48,'全唐诗/poet.song.228000.json','["玉節江湖晚，油幢嶺海春。", "一朝晉遺老，千古漢名臣。", "清白冰壺操，尊光紫府身。", "全歸公不憾，愁絕奠芻人。"]'),
('8e9af1d0-ccff-4965-9d05-ff812f6599c1','贈高眼相士','陳杰','宋','宋诗','song-poetry','','[]','遍閲穹華了，還來寂寞濱。',48,'全唐诗/poet.song.228000.json','["遍閲穹華了，還來寂寞濱。", "山林枉高眼，宇宙著低人。", "關月吟魂冷，吳霜鬢影新。", "相逢欲開說，笑指臘醅醇。"]'),
('3e7c826a-ee34-4ec3-8050-068c6dedeeff','送七姪遊學','陳杰','宋','宋诗','song-poetry','','[]','迅甚風鵬翮，蕭然野鶴深。',48,'全唐诗/poet.song.228000.json','["迅甚風鵬翮，蕭然野鶴深。", "一經教子舊，萬里出門新。", "天下師傳道，方來友輔仁。", "異時吾悔殺，虛負客中春。"]'),
('35518a3c-1e9b-4655-8a6a-17b1ac6e335f','元旦南郊慶成','陳杰','宋','宋诗','song-poetry','','[]','熙朝政化謹三元，有事郊南典禮全。',64,'全唐诗/poet.song.228000.json','["熙朝政化謹三元，有事郊南典禮全。", "嗣聖萬年初見帝，小臣十起夜瞻天。", "想回玉輅紅雲曉，更揭金鷄暖雨前。", "但願慶成天下福，賦詩豈必從甘泉。"]'),
('29d71c1b-f4cf-4c97-ad42-26e41c36be36','天基節特晴','陳杰','宋','宋诗','song-poetry','','[]','王春又數五堯蓂，先自春來半月贏。',64,'全唐诗/poet.song.228000.json','["王春又數五堯蓂，先自春來半月贏。", "天上聖功調玉燭，雲問暖律寫莖英。", "蒼生正頼吾君福，每歲長占此日晴。", "三祝莫嫌言語朴，時和年熟早休兵。"]'),
('66ba53c3-d483-4574-a59e-97e92d061748','人日立春極寒','陳杰','宋','宋诗','song-poetry','','[]','綵鞭點雨斧如雷，頭上頑雲打不開。',64,'全唐诗/poet.song.228000.json','["綵鞭點雨斧如雷，頭上頑雲打不開。", "冬序方隨人日盡，春愁却載土牛來。", "幾多漕運留冰解，何限耕桑要暖回。", "惟有上林花自早，天公羯鼓更頻催。"]'),
('39586f5d-8dae-483a-b31b-0429f414d7dd','臘月中旬立春快雪遄晴','陳杰','宋','宋诗','song-poetry','','[]','夜光吟屋炯無眠，曉色梅簷重粲然。',64,'全唐诗/poet.song.228000.json','["夜光吟屋炯無眠，曉色梅簷重粲然。", "芒端殘臘洗晴雪，花底好春回隔年。", "田疇膏脈占時早，禽鳥和聲得氣先。", "多少趨生寰宇望，紫皇更斡大鈞旋。"]'),
('3253c461-caf5-484c-bfe6-74c0aa086c3f','除日始雪遄霽','陳杰','宋','宋诗','song-poetry','','[]','去年冬孟朔朝雪，今歲臘三十日來。',64,'全唐诗/poet.song.228000.json','["去年冬孟朔朝雪，今歲臘三十日來。", "釀久直疑包地盡，飛狂忽作舞風回。", "盈虛有數天已定，氣候不齊人得猜。", "流轉春光又明發，一樽且送息如雷。"]'),
('2ca74a43-441d-4797-91a5-4cc0d664355d','過小孤順風縱帆瞬息數百里','陳杰','宋','宋诗','song-poetry','','[]','順水風吹順水船，全家水上作飛仙。',64,'全唐诗/poet.song.228000.json','["順水風吹順水船，全家水上作飛仙。", "猶疑五老瞠居後，不覺九華參在前。", "蕭颯自憐雙鬢髮，應酬不暇許山川。", "腐儒易動還多事，三老齁齁倚柁眠。"]'),
('bbf52da9-5cbe-484e-8be8-86e857ac872f','獅子寨小港軃風','陳杰','宋','宋诗','song-poetry','','[]','驚濤拍岸臨無地，遠壑藏舟別有天。',64,'全唐诗/poet.song.228000.json','["驚濤拍岸臨無地，遠壑藏舟別有天。", "風舉酒旗黄帽舞，雨拋魚網綠蓑眠。", "機心起滅浮漚外，世事昏明返照邊。", "安得杖拏相印可，碧蘆深處小延緣。"]'),
('8ce6e2c7-1c0f-4ef9-9d49-70171d7ec30e','閫下忽動歸興','陳杰','宋','宋诗','song-poetry','','[]','無端佩玉更長裾，銜袖人疑表餌疏。',64,'全唐诗/poet.song.228000.json','["無端佩玉更長裾，銜袖人疑表餌疏。", "塞路連雲痡僕馬，轅門似海歎車魚。", "那無定遠封侯相，正有南涯種樹書。", "久客土思吾亦動，明朝滿意聽驪駒。"]'),
('de83301e-a4eb-4472-9973-289a2f5e4774','舊愛靈溪渡風物之美歸途由浙而江即目成詠','陳杰','宋','宋诗','song-poetry','','[]','黄竹弄口雨初晴，靈溪渡頭水漸生。',64,'全唐诗/poet.song.228000.json','["黄竹弄口雨初晴，靈溪渡頭水漸生。", "兩岸桑麻人著本，一川鷗鷺我同盟。", "風環摇日浣紗影，雲杵打波舂稻聲。", "少日經行渾草草，暮年歸路不勝情。"]'),
('5ae0c700-4d4e-49d3-99bb-0087b7154248','歲晏大風','陳杰','宋','宋诗','song-poetry','','[]','羌管橫吹萬點梅，漢葭微透半銖灰。',64,'全唐诗/poet.song.228000.json','["羌管橫吹萬點梅，漢葭微透半銖灰。", "從知急景彫年駛，更著驚飆截道催。", "掠野已空征鳥厲，叫雲欲曙澤鴻哀。", "布衾小作須臾忍，多少無眠待暖回。"]'),
('edd1e599-458a-4a9c-9e46-0e821c0f2ea5','三朝書窗','陳杰','宋','宋诗','song-poetry','','[]','爆聲喚醒鼻中雷，宿溜初停曉色開。',64,'全唐诗/poet.song.228000.json','["爆聲喚醒鼻中雷，宿溜初停曉色開。", "雲落小須新日上，雪消剩放好春回。", "老人自寫題門帖，稚子先嘗得歲杯。", "明暖一窗聊引筆，東風折盡膽瓶梅。"]'),
('09c347b2-5031-4024-bd40-0a1f8bb3451c','得菊花絕黄','陳杰','宋','宋诗','song-poetry','','[]','誰與凜秋料理悲，木樨香冷未梅時。',64,'全唐诗/poet.song.228000.json','["誰與凜秋料理悲，木樨香冷未梅時。", "直疑天上金莖露，全付籬間黄菊枝。", "佳色足陪陶令醉，落英還慰屈原饑。", "東風試問千紅紫，曾有西風此段奇。"]'),
('20492a55-c1be-4366-8a8b-4490b3a057cd','歸舟發南浦','陳杰','宋','宋诗','song-poetry','','[]','舊遊觸景不無情，已辦牽江復小停。',64,'全唐诗/poet.song.228000.json','["舊遊觸景不無情，已辦牽江復小停。", "好在夕陽紅葉樹，依然新月白沙汀。", "舟回剡曲潮空落，笛起山陽酒乍醒。", "當日摻袪談底事，獨揮老淚下旗亭。"]'),
('09f3dedc-dd83-4a5e-807d-3ef1478b3602','送淮漕洪監移節江東暫回天目','陳杰','宋','宋诗','song-poetry','','[]','冷雲初雁水明霞，遥見星躔動漢槎。',64,'全唐诗/poet.song.228000.json','["冷雲初雁水明霞，遥見星躔動漢槎。", "咫尺江淮分表裏，一番禮樂又光華。", "水通建業寧迂道，天近城南且過家。", "忙處得閒應更好，故園秋色上黄花。"]'),
('78bd642c-87c9-49d1-ab0d-942e79905d0e','和鄧中齋至日舟中七言','陳杰','宋','宋诗','song-poetry','','[]','又報微陽九地回，堂堂心在鬢顔摧。',64,'全唐诗/poet.song.228000.json','["又報微陽九地回，堂堂心在鬢顔摧。", "鄉愁雲物有詩寫，驛訊春枝無使來。", "燕谷可能生出黍，漆園但愛死如灰。", "相從導引學仙去，吳市不知人姓梅。"]'),
('15ab43af-5095-4b78-b222-3786fbc70f6a','正月三日甲子題','陳杰','宋','宋诗','song-poetry','','[]','柳邊梅外試陰晴，清曉誰來鵲滿庭。',64,'全唐诗/poet.song.228000.json','["柳邊梅外試陰晴，清曉誰來鵲滿庭。", "春似久痿纔得沾，天如熟醉驟難醒。", "窗含西嶺千秋白，筆轉東皇萬古青。", "又與新年書甲子，階前堯曆第三蓂。"]'),
('462719da-9899-4320-ae45-d2ed49e6f354','寸祿','陳杰','宋','宋诗','song-poetry','','[]','同遊鼎貴佩鳴珂，寸祿中年不啻過。',64,'全唐诗/poet.song.228000.json','["同遊鼎貴佩鳴珂，寸祿中年不啻過。", "方朔猶須設非有，爰絲正可飲無何。", "山前華表書官大，江上郵亭送使多。", "草草百年勳業夢，插天浯石未曾磨。"]'),
('fa1fe814-650c-498a-b652-bb36a3b03378','京口閒行逢李編校謂嘗共蒱戲於長安酒家殊惘然也','陳杰','宋','宋诗','song-poetry','','[]','萬人如海長安市，歌酒相逢底處樓。',64,'全唐诗/poet.song.228000.json','["萬人如海長安市，歌酒相逢底處樓。", "容有門間曾半面，可堪塵際重回頭。", "我非賣藥伯休那，君豈呼盧彥道不。", "歸過舊題梅柳處，寄聲爲謝少年遊。"]'),
('ac1ded10-5a4a-485d-9017-f583dc9b3a2c','贈艾校尉','陳杰','宋','宋诗','song-poetry','','[]','相逢莫說亂離苦，江北江南皆戰場。',64,'全唐诗/poet.song.228000.json','["相逢莫說亂離苦，江北江南皆戰場。", "何限忠肝膏草野，幾多徒手化侯王。", "方當羽檄馳千里，信有纓冠衛一鄉。", "事已論功殊未已，何如相賀返屠羊。"]'),
('eb2572a1-b715-4c12-8d27-c640c498d3bc','憲使魏青崖惠拄杖堅多節而色尚黄惟額用白立秋後十日聲詩','陳杰','宋','宋诗','song-poetry','','[]','三尺青蛇冷劍鋩，百跗委蛻像生黄。',64,'全唐诗/poet.song.228000.json','["三尺青蛇冷劍鋩，百跗委蛻像生黄。", "分來上界金神節，豎起平生鐵脊梁。", "千步已穿蘿逕月，一棱猶带柏臺霜。", "小煩拄到天壇了，歸化爲龍亦未量。"]'),
('6ece3a81-a851-4179-9722-126b4796e5c0','沙頭點視城池','陳杰','宋','宋诗','song-poetry','','[]','酸風射眼舊沙頭，我亦從來兩鬢秋。',64,'全唐诗/poet.song.228000.json','["酸風射眼舊沙頭，我亦從來兩鬢秋。", "萬里客心驚塞雁，五更歸夢化江鷗。", "山川信美坐成晚，風景不殊看總愁。", "征築百年無了日，老天亦自厭兵休。"]'),
('9a78f482-a3c9-4d56-92c2-1e217150cdba','挽陶縣令叔元','陳杰','宋','宋诗','song-poetry','','[]','千載同歸兩陶令，故園相望一青山。',64,'全唐诗/poet.song.228000.json','["千載同歸兩陶令，故園相望一青山。", "怪來强健休官早，贏得艱虞閲世閒。", "差樂輸君已天上，不堪愧我尚人間。", "斯文回首遊從日，淚盡重華叫不還。"]'),
('5910238d-0aaf-4498-b32b-101a0845872b','挽張提點自創玄都觀歸故山羽化','陳杰','宋','宋诗','song-poetry','','[]','年時初峻道官班，紫氣隨師亦度關。',64,'全唐诗/poet.song.228000.json','["年時初峻道官班，紫氣隨師亦度關。", "賜號競驩新宇宙，藏身獨憶舊雲山。", "玄都聊復栽桃去，遼海何當化鶴還。", "見說高人無寵辱，乘除翻手一漚間。"]'),
('41a8d477-aae4-4325-93d2-cc4682f54cee','聞履齋丞相再論貶','陳杰','宋','宋诗','song-poetry','','[]','江濤如此得離難，禍本蕭牆兩巨姦。',64,'全唐诗/poet.song.228000.json','["江濤如此得離難，禍本蕭牆兩巨姦。", "仲舉能無推席起，茂弘正有角巾還。", "救時豈料兔三窟，去國纔知虎九關。", "賣論取官方翕翕，吾詩未敢落人間。"]'),
('4426315e-ae74-41d8-87e3-984f81574198','黄孟博辭往鄂渚贈別','陳杰','宋','宋诗','song-poetry','','[]','與君生共一雌辰，枌社相違整十春。',64,'全唐诗/poet.song.228000.json','["與君生共一雌辰，枌社相違整十春。", "肯爲江山輕萬里，不嫌風雨住兼旬。", "携書又作鸚洲客，有弟能娛鶴髮親。", "豈不勸君歸去好，回頭我自愧鱸蓴。"]'),
('a80057fd-beed-4532-b104-a03ec7392976','滕王閣','陳杰','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','稍覺闌干遠水漪，枉持錢貫去安之。',64,'全唐诗/poet.song.228000.json','["稍覺闌干遠水漪，枉持錢貫去安之。", "湖山千古戶庭內，簾棟幾番鸞玉時。", "記好儘堪邕輟翰，序工且放顥題詩。", "西風何限憑高事，鐵笛吹愁酒一巵。"]'),
('55a221ba-91a1-424d-b73f-0618cfb5459f','冬至前七日青崖分送新曆','陳杰','宋','宋诗','song-poetry','','[]','嫩黄裹冊印如斗，傳教打門驚晝眠。',64,'全唐诗/poet.song.228000.json','["嫩黄裹冊印如斗，傳教打門驚晝眠。", "又見朔平新改歲，獨憐絳老不知年。", "繡衣春立層霄上，黍律陽回七日前。", "更願時和戢豺虎，一犁歸種久荒田。"]'),
('dc3a9a43-16b4-4dc6-b24e-6ca2f030025e','陪蜀士文昌醮','陳杰','宋','宋诗','song-poetry','','[]','葳蕤桑梓翦爲荒，翰墨橫流墜緒茫。',64,'全唐诗/poet.song.228000.json','["葳蕤桑梓翦爲荒，翰墨橫流墜緒茫。", "天北有星明武曲，江南無地託文昌。", "幾時興雨蘇民望，何日乘雲返帝鄉。", "我少乞靈今不夢，倚觀魁宿照詞場。"]'),
('6d93ffb0-fca9-445c-892a-f934958d1bec','仲宣樓','陳杰','宋','宋诗','song-poetry','','[]','一雨真成五月秋，十年重上仲宣樓。',64,'全唐诗/poet.song.228000.json','["一雨真成五月秋，十年重上仲宣樓。", "崢嶸歲月欺人事，浩蕩乾坤入客愁。", "孫劉氣力三分盡，蜀漢山川百戰收。", "可是登臨無限意，閒看西日下城頭。"]'),
('c78be637-7606-4801-b38f-fae55163975f','和諸君野舟之作','陳杰','宋','宋诗','song-poetry','','[]','當年亦自一蓑閒，百丈孤牽夜泝灘。',64,'全唐诗/poet.song.228000.json','["當年亦自一蓑閒，百丈孤牽夜泝灘。", "乘海安歸如此險，臨河不濟美哉瀾。", "五湖月暗收綸卧，七澤雲移倚柁看。", "豈是淪胥惜援手，瞿塘回首上天難。"]'),
('feaa6ccd-3e09-4eb9-a542-5123fa2f04f9','寄題興國倅廳湖山偉觀樓','陳杰','宋','宋诗','song-poetry','','[]','華表歸威可手攀，新亭風景落眉間。',64,'全唐诗/poet.song.228000.json','["華表歸威可手攀，新亭風景落眉間。", "千年宇宙千年事，萬里湖山萬里天。", "庭蠡水來仍水落，衡廬雲起復雲閒。", "古今只在斜陽外，安得憑高一破顔。"]'),
('ee004748-d2db-430f-ad27-367361a5c28f','答龔帥幹楚清','陳杰','宋','宋诗','song-poetry','','[]','一水相望汝與豐，亂來如隔萬山重。',64,'全唐诗/poet.song.228000.json','["一水相望汝與豐，亂來如隔萬山重。", "清名昔已香三楚，晚節今真繼兩龔。", "正自南山深霧豹，何時東野快雲龍。", "唾珠滿紙慳瓊報，聊寫相於磊磈胸。"]'),
('72eeb52b-5e9e-492a-a16d-ca261bf87843','和大閫芍藥讌韻','陳杰','宋','宋诗','song-poetry','','[]','雲霞一片從天墜，誰爲淮南種好春。',64,'全唐诗/poet.song.228000.json','["雲霞一片從天墜，誰爲淮南種好春。", "揮羽本調金鼎手，對花未老玉關人。", "萬紅清洛無前譜，四瑞平山曠後塵。", "坐上魏公甯用讚，倚風商略秩筵賓。"]'),
('5abf33a2-2052-4866-b9e1-22bdf71eda33','端午命童採藥','陳杰','宋','宋诗','song-poetry','','[]','清薰一枕暑初炎，綵索朱符懶重拈。',64,'全唐诗/poet.song.228000.json','["清薰一枕暑初炎，綵索朱符懶重拈。", "天上賜衣無媚骨，山中采藥有長髯。", "扶衰底要三年艾，用拙何嗟六日蟾。", "惟有昌陽堪引壽，一盃泛玉不妨添。"]'),
('1e76cc0e-793d-4d11-a73e-c954c0043df5','詠物','陳杰','宋','宋诗','song-poetry','','[]','天成不挫節根完，底是園工出相端。',64,'全唐诗/poet.song.228000.json','["天成不挫節根完，底是園工出相端。", "花面縈回銀鳳舞，苔身宛轉翠虬蟠。", "由來疎散林壑性，稍就規繩廊廟看。", "至竟風流無改度，霧窗玉立雪籬寒。"]'),
('1e1d6d1e-4426-4e4b-90a5-1047dfd10db0','病起','陳杰','宋','宋诗','song-poetry','','[]','苦炎未了又悲秋，如此相催老即休。',64,'全唐诗/poet.song.228000.json','["苦炎未了又悲秋，如此相催老即休。", "病裏有時烏可帝，夢中奚翅蟻能侯。", "屈平正不爭鷄鶩，老子真堪謂馬牛。", "茲理卧來尤透徹，颯然毛孔散千憂。"]'),
('224c6b50-436e-42c0-ac0f-3080d31c3aff','尋蘇雲卿隠處','陳杰','宋','宋诗','song-poetry','','[]','書幣何因識灌園，等閒夜度北山雲。',64,'全唐诗/poet.song.228000.json','["書幣何因識灌園，等閒夜度北山雲。", "明朝難覓蘇仙鶴，鄰舍空餘孺子墳。", "不世大功關氣數，故人高義足知聞。", "看來只是談恢復，已隠無堪佐萬分。"]'),
('32eed024-e925-4daf-aec5-327926953336','風沙','陳杰','宋','宋诗','song-poetry','','[]','清野風沙覺更長，謫仙此日尚能狂。',64,'全唐诗/poet.song.228000.json','["清野風沙覺更長，謫仙此日尚能狂。", "一株殘柳專春事，兩箔頹籬共夕陽。", "過鷁去空江浪白，歸鴻沒盡塞雲黄。", "酒醒何處吹羌笛，未省吳兒有石腸。"]'),
('f2e08d2d-517a-4c4d-a50e-d035bb5021a2','寄贈','陳杰','宋','宋诗','song-poetry','','[]','客裏蕭蕭兩鬢秋，此身何止二宜休。',64,'全唐诗/poet.song.228000.json','["客裏蕭蕭兩鬢秋，此身何止二宜休。", "禮文疎似嵇中散，疾病多於沈隠侯。", "愧我空餐有懸特，看君迎刃解全牛。", "夜來一炬平安火，賸喜先寬玉食憂。"]'),
('cd8ab91f-b83e-42b5-ae25-8536b31c09d2','詩客有歎不遇者作詩人傲以慰之','陳杰','宋','宋诗','song-poetry','','[]','世間最有詩人傲，龍馬行天不受鞿。',64,'全唐诗/poet.song.228000.json','["世間最有詩人傲，龍馬行天不受鞿。", "鐘鼎何如白木鑱，軒裳得似綠蓑衣。", "舍人錦好宜遭卷，諫議茶清亦取譏。", "近代後翁尤卓絕，客來無語袖金歸。"]'),
('480ce991-e790-4f5a-b67b-7c4d3ce802de','伯文覓雞雛賦送','陳杰','宋','宋诗','song-poetry','','[]','雌雄在殻衆雛分，養手當年紀渻君。',64,'全唐诗/poet.song.228000.json','["雌雄在殻衆雛分，養手當年紀渻君。", "飽履雪霜方出距，淺含風霧未成文。", "徐行肯與鶩爭食，小立還如鶴在羣。", "待放一鳴天下白，秦關下客敢論勳。"]'),
('65ea3042-54e9-4985-93a6-15f45e1b823c','携碧香酒賞紅白桃因觀江漲','陳杰','宋','宋诗','song-poetry','','[]','江光萬頃碧香酒，春事一年紅白桃。',64,'全唐诗/poet.song.228000.json','["江光萬頃碧香酒，春事一年紅白桃。", "不飲其如胸磊磈，欲簪還愧鬢蕭騷。", "言之淺矣乾坤大，逝者如斯晝夜滔。", "多謝江亭好風日，頗哀老子得遊遨。"]'),
('296a528e-a785-4eca-b279-7c610f7c4108','題王氏先壠壽松亭','陳杰','宋','宋诗','song-poetry','','[]','兵前萬事舉頭非，風太無情宰木悲。',64,'全唐诗/poet.song.228000.json','["兵前萬事舉頭非，風太無情宰木悲。", "馬鬣未隨陵谷變，龍髯還長子孫枝。", "會看高表鶴歸日，毋忘新栽鹿觸時。", "雨露百年思不極，深心更有歲寒知。"]'),
('0fa7f4ff-2f11-4948-816b-15360ba048b2','徐子蒼自金陵遣詩來用韻送魚腊','陳杰','宋','宋诗','song-poetry','','[]','寄詩曾自日邊郵，眼底江楓幾換秋。',64,'全唐诗/poet.song.228000.json','["寄詩曾自日邊郵，眼底江楓幾換秋。", "頗憶故人當富貴，又傳新句寫窮愁。", "人生不會長彈鋏，心事何知各倚樓。", "閒把武昌魚送似，試參風味帝王州。"]'),
('b964d698-839f-49a2-af97-026485658418','守歲','陳杰','宋','宋诗','song-poetry','','[]','階前爆竹作驚雷，從俗何妨進酒杯。',64,'全唐诗/poet.song.228000.json','["階前爆竹作驚雷，從俗何妨進酒杯。", "微醉偶便深閣坐，好春先入小瓶梅。", "焚香靜閲年光轉，不寐頻聞夜漏催。", "明日買臣當五十，却思上印故鄉回。"]'),
('d5434d30-0f8d-4bd0-83f1-758dbd7561a7','上元果晴讌南樓詩弈盡歡用韻','陳杰','宋','宋诗','song-poetry','','[]','賞心壓景與晴期，廣讌張山下漏遲。',64,'全唐诗/poet.song.228000.json','["賞心壓景與晴期，廣讌張山下漏遲。", "萬國燈宵臣卜晝，三軍樂舞客歌詩。", "抃鼇東極遥觴壽，飛雹南風活著棋。", "不爲清談恐妨要，胡牀儘到月來時。"]'),
('dbc60c6e-2745-4647-9931-7b85ed8a2927','五日江亭即事','陳杰','宋','宋诗','song-poetry','','[]','五日江城因遠望，畫橈不動美哉洋。',64,'全唐诗/poet.song.228000.json','["五日江城因遠望，畫橈不動美哉洋。", "人間昌歜誰同嗜，地下離騷只自香。", "折得玉蕖冰照坐，飛來鷗鳥雪爲裳。", "一番節物忙收拾，客舍題詩生晚凉。"]'),
('9632a878-e059-41b6-a821-a7187cf53eef','題菊鄉亭','陳杰','宋','宋诗','song-poetry','','[]','晉朝徵士種菊處，滿地蒼雲無古今。',64,'全唐诗/poet.song.228000.json','["晉朝徵士種菊處，滿地蒼雲無古今。", "漫喜孤亭初結構，每懷高節此登臨。", "南山日入輸佳氣，北闕天長馳寸心。", "瞻眺徘徊徒感慨，清風簾底坐鳴琴。"]'),
('69e0df55-3518-4380-8907-98959c4d2e50','把茅','陳杰','宋','宋诗','song-poetry','','[]','廣武醉後呵豎子，稷下談鋒避少年。',64,'全唐诗/poet.song.228000.json','["廣武醉後呵豎子，稷下談鋒避少年。", "未知更蠟阮屐幾，惟恐有著祖鞭先。", "鬻技百金或封地，著書五車無入玄。", "人間事多特未定，把茅去老白雲邊。"]'),
('90fcd0ca-6972-4c8a-b4b4-ac6f8b9a28b8','南樓登高','陳杰','宋','宋诗','song-poetry','','[]','九日陰陰怯遠遨，南樓平壓騎臺豪。',64,'全唐诗/poet.song.228000.json','["九日陰陰怯遠遨，南樓平壓騎臺豪。", "輕颸吹帽何妨落，囂市登山易得高。", "烽火太平州送酒，檄書餘暇客題糕。", "歸來不盡良辰意，更折黄花照鬢毛。"]'),
('2040ff39-d2b1-41dd-9114-2362a9e954e2','江天','陳杰','宋','宋诗','song-poetry','','[]','凉意蕭蕭起白蘋，憑高小扇一障塵。',64,'全唐诗/poet.song.228000.json','["凉意蕭蕭起白蘋，憑高小扇一障塵。", "西風可是生華髮，秋水偏能隔美人。", "巴曲數聲烏散後，楚騷滿目雁來新。", "江天只屬漁翁管，那得閒愁上釣綸。"]'),
('3ce7cde7-c96a-49a0-b944-25467c70732a','出郊','陳杰','宋','宋诗','song-poetry','','[]','殘紅滿地綠平池，趁得晴天一日嬉。',64,'全唐诗/poet.song.228000.json','["殘紅滿地綠平池，趁得晴天一日嬉。", "曲徑間行逃酒處，小樓閒坐品簫時。", "俗間禮節疎來久，客裏光陰去不知。", "一笑主人還指似，牆東忽自有酴醿。"]'),
('457cf0ec-8a74-4a45-989b-fa961f176e0e','予以甲寅冬過弋陽石橋戊辰正月重過','陳杰','宋','宋诗','song-poetry','','[]','周行淮漢萬山川，重此經過十五年。',64,'全唐诗/poet.song.228000.json','["周行淮漢萬山川，重此經過十五年。", "野老眉間新世事，蹇馿背上舊吟鞭。", "幾分春色梅花後，一片歸心杜宇前。", "深谷有人難問信，石橋倚遍晚晴天。"]'),
('ad962a9c-928f-4e21-8104-71eb4ad1517b','和陳郎中時舉清夜不寐','陳杰','宋','宋诗','song-poetry','','[]','四簷殘溜雜風鈴，長夜遥空候啟明。',64,'全唐诗/poet.song.228000.json','["四簷殘溜雜風鈴，長夜遥空候啟明。", "綠鬢望郎猶不寐，白頭遺老得無情。", "幾時畫角吹愁徹，何處黄粱做夢成。", "一笑詩來扶杖起，滿湖煙霽曉寒輕。"]'),
('dfa7ab6b-8c8a-416c-a287-2d7bfc7ee96e','惡講義不遜者','陳杰','宋','宋诗','song-poetry','','[]','全人未可一偏論，盛德真堪百代尊。',64,'全唐诗/poet.song.228000.json','["全人未可一偏論，盛德真堪百代尊。", "房魏其逢猶愧禮，荀陳之道不知文。", "我朝正有二三老，地位向妨八九分。", "近日後生談理學，直將聞百掩前聞。"]'),
('31bc9553-de17-4cdc-af4a-3fb05cd74af8','用同官南樓韻尾聯以慰李倅子發','陳杰','宋','宋诗','song-poetry','','[]','年時歌管縈雲處，閒倚欄干水拍空。',64,'全唐诗/poet.song.228000.json','["年時歌管縈雲處，閒倚欄干水拍空。", "萬古胡牀自明月，幾行官柳又西風。", "鬅鬙那復梳千下，磊磈聊須酒一中。", "更憶翹材人獨自，夜燈寒雁耳偏聰。"]'),
('1e0aaa38-58d2-4b91-880d-f63130521322','又登南樓','陳杰','宋','宋诗','song-poetry','','[]','縹渺層巒出畫闌，半空長鎖白雲閒。',64,'全唐诗/poet.song.228000.json','["縹渺層巒出畫闌，半空長鎖白雲閒。", "一弓斜摺蜀江水，八字平分漢渚山。", "眼入中原鴻去迥，手摩華表鶴飛還。", "好天誰遣成南北，遺限悠悠落照間。"]'),
('7ca30249-e891-4b59-bbe6-7ab2956e29b4','揚州城樓','陳杰','宋','宋诗','song-poetry','','[]','東南賦甲天下處，萬里西風生黍禾。',64,'全唐诗/poet.song.228000.json','["東南賦甲天下處，萬里西風生黍禾。", "禹貢九州今見一，晉軍三役古無多。", "水包楚蜀雖朝海，山引終嵩只隔河。", "安得六飛時此駐，棘間咫尺望銅駝。"]'),
('eb2efa7e-204e-41cf-96e0-528dd73db9bf','索隠張君風鑒兼人未嘗衣帛食肉自謂數短故勉之歸就肆焉','陳杰','宋','宋诗','song-poetry','','[]','布衣蔬食百無營，底用江湖更有聲。',64,'全唐诗/poet.song.228000.json','["布衣蔬食百無營，底用江湖更有聲。", "正爾多才憂管輅，何如一肆老君平。", "逢人足可談忠孝，對鬼無勞語爽精。", "問鵲占珠還動否，親年喜懼室嬛嬛。"]'),
('b09cb799-570b-4175-8a2a-3c8e259e720b','小惠','陳杰','宋','宋诗','song-poetry','','[]','初持小惠釣聲華，祿厚官高譽轉加。',64,'全唐诗/poet.song.228000.json','["初持小惠釣聲華，祿厚官高譽轉加。", "過客厨豐路碑炫，中朝賂重裏言誇。", "黄金何但買身貴，多粟尤堪作傳佳。", "百世倘無公論在，邪人渾指正人邪。"]'),
('11500baf-1a85-429e-b549-fc51c9f8397e','泛西湖','陳杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百年歲月此池臺，十里雲霞鏡面開。',64,'全唐诗/poet.song.228000.json','["百年歲月此池臺，十里雲霞鏡面開。", "青鳥慣含紅旆去，小娃頻採白蓮回。", "玉簫吹拂玻瓈國，繡縠穿交金碧堆。", "好是太平人自樂，宮車咫尺不曾來。"]'),
('13f5558b-bd24-4106-8d09-5f99b3a3f100','和韻歸趙宗聖詩卷','陳杰','宋','宋诗','song-poetry','','[]','宇宙詩愁海未深，有情何必句鏗金。',64,'全唐诗/poet.song.228000.json','["宇宙詩愁海未深，有情何必句鏗金。", "蹇馿橋上長寒眼，短笠山頭獨苦心。", "千載暗中捫沈謝，幾人灰裏撥何陰。", "濯纓自取滄浪去，好在三閭澤畔吟。"]'),
('5af0c89c-78f9-4361-879c-71fdb3c5e74e','和韻歸張通父詩卷','陳杰','宋','宋诗','song-poetry','','[]','當年握手談何事，此日相觀一卷詩。',64,'全唐诗/poet.song.228000.json','["當年握手談何事，此日相觀一卷詩。", "湘竹恨深聽雨夜，洛英夢繼看花時。", "杜陵春好工添淚，宋玉秋清祇益悲。", "猶有堪論千載上，由來不倩俗間知。"]'),
('59ea87f9-a370-40c3-9453-b6399b9c7241','天命','陳杰','宋','宋诗','song-poetry','','[]','至狂而聖至愚神，天命何私與物均。',64,'全唐诗/poet.song.228000.json','["至狂而聖至愚神，天命何私與物均。", "萬水各涵全體月，千花同受十分春。", "一家路透家家路，一性仁通性性仁。", "秦漢以還無講學，幾多輕棄不貲身。"]'),
('de468f45-1210-4349-9e60-5babef71b54d','武甯道間遇故舊於負販中','陳杰','宋','宋诗','song-poetry','','[]','拍天富貴有危機，屠釣逃名未覺非。',64,'全唐诗/poet.song.228000.json','["拍天富貴有危機，屠釣逃名未覺非。", "許靖何嘗羞馬磨，王章安用泣牛衣。", "班荆道舊身俱晚，折柳臨分意重違。", "且復斯須相勞苦，明年我亦荷鋤歸。"]'),
('2af40b24-3f68-4b47-b1c6-8feac89284c0','感興','陳杰','宋','宋诗','song-poetry','','[]','滿目塵沙萬里還，客來相對舊儒酸。',64,'全唐诗/poet.song.228000.json','["滿目塵沙萬里還，客來相對舊儒酸。", "秋風慣識茅茨屋，朝日仍登苜蓿盤。", "雲鶴性情閒去好，山林面目本來看。", "今年少緩梅花約，敝盡貂裘未可寒。"]'),
('5456e6f1-64c7-49f6-8065-e222afc9eda4','和雷侍郎賀雪賜燕','陳杰','宋','宋诗','song-poetry','','[]','萬箇瑶姬擁御筵，千官玉立壽巵前。',64,'全唐诗/poet.song.228000.json','["萬箇瑶姬擁御筵，千官玉立壽巵前。", "豐年三度雪平地，需燕一番雲上天。", "鷺序捲班元老後，龍顔瞻喜侍臣先。", "幾多夜訪籌邊事，更願毋安一枕眠。"]'),
('d891215b-7aae-4959-8ae1-12e810600208','空第','陳杰','宋','宋诗','song-poetry','','[]','潭潭居府美哉輪，歌舞回頭迹已陳。',64,'全唐诗/poet.song.228000.json','["潭潭居府美哉輪，歌舞回頭迹已陳。", "東閣早知爲馬廐，西曹正可認車茵。", "高明易瞰多招鬼，富貴無常忽易人。", "看取田文何意氣，雍門未鼓淚盈巾。"]'),
('e978e219-bc90-452a-8288-b9ac568d0ee5','除夕','陳杰','宋','宋诗','song-poetry','','[]','憶曾守歲荆州夜，多少艱虞共濟人。',64,'全唐诗/poet.song.228000.json','["憶曾守歲荆州夜，多少艱虞共濟人。", "一紀重來仍作客，百年誰是自由身。", "干戈滿地今猶昨，日月行天故復新。", "願及春回再清晏，綠蓑永換黑貂塵。"]'),
('719f9b4c-8491-4bc2-974f-d38be25a43cb','立春久渴雨大閫正月八日禱遄應','陳杰','宋','宋诗','song-poetry','','[]','農祥見正久當雨，元日至人還要晴。',64,'全唐诗/poet.song.228000.json','["農祥見正久當雨，元日至人還要晴。", "長旦始和開歲事，一番既渥起春耕。", "瓣香及物何神速，咫拜瞻天只血誠。", "小待爲霖三日足，燈宵又放十分明。"]'),
('bf99fffd-dee3-412d-b738-8b99080d8ad7','贈張慈寶五行精到奇中','陳杰','宋','宋诗','song-poetry','','[]','大慈寺裏談天寶，蜀産凋零此亦奇。',64,'全唐诗/poet.song.228000.json','["大慈寺裏談天寶，蜀産凋零此亦奇。", "借我干支作正鵠，驗渠禍福似蓍龜。", "李虛中術曾無失，絳老人年漫不知。", "大運茫茫君自扣，故鄉歸去定何時。"]'),
('91387465-3911-4076-b3f8-90dc66efbc4f','即事二首  其一','陳杰','宋','宋诗','song-poetry','','[]','扁舟小繫畫闌西，萬里晴光一拄頤。',64,'全唐诗/poet.song.228000.json','["扁舟小繫畫闌西，萬里晴光一拄頤。", "湖面欲包天外去，嶠鬟疑割海中來。", "高空自瀉軒皇樂，元氣長涵杜老詩。", "慶曆殘碑重回首，此生何限退憂時。"]'),
('e5642570-2216-4cf4-8268-499745a8327a','即事二首  其二','陳杰','宋','宋诗','song-poetry','','[]','慶曆殘碑倦復看，斯文豈是爲游觀。',64,'全唐诗/poet.song.228000.json','["慶曆殘碑倦復看，斯文豈是爲游觀。", "一番棟宇開荒礎，萬古青螺點玉盤。", "鳥度雲移人事換，天高地大客愁寬。", "六絲小駐詢遺俗，尚憶重華舞羽干。"]'),
('3507418d-afea-4024-8aa5-4227731980c5','感懷','陳杰','宋','宋诗','song-poetry','','[]','一箭乾風射眼酸，幾棱遠碧壓眉攢。',64,'全唐诗/poet.song.228000.json','["一箭乾風射眼酸，幾棱遠碧壓眉攢。", "芙蓉開徹徐娘老，楊柳疎來范叔寒。", "何處素商調綠綺，誰家翠袖倚琅玕。", "無情九辯渾拋得，却被天公畫出看。"]'),
('97211660-3cde-4b8e-a0c3-daeaec8b58a9','十二月二十六日蔡叔庸至剪燭聽雨','陳杰','宋','宋诗','song-poetry','','[]','水氣昏昏接海邊，清江狂客繫吳船。',64,'全唐诗/poet.song.228000.json','["水氣昏昏接海邊，清江狂客繫吳船。", "天風十日河冰碎，夜雨三更瀑布懸。", "寂寂春光歸柳上，匆匆離色在花前。", "故人著屐能相過，剪燭西窗話昔年。"]'),
('785064b3-9d77-4df3-854c-d844d38708e4','元宵','陳杰','宋','宋诗','song-poetry','','[]','老去何心說看燈，一年還要此宵晴。',64,'全唐诗/poet.song.228000.json','["老去何心說看燈，一年還要此宵晴。", "暖風忽斷簷間溜，繁吹初過枕上聲。", "誰變慘悽成笑語，定回離亂作清平。", "不應淡薄梅花月，偏照詩人白髮生。"]'),
('35f62aa9-1453-4473-a72c-93b168ef6925','挽雷尚書喪歸二首  其一','陳杰','宋','宋诗','song-poetry','','[]','班朝曾共多艱日，草疏相過太息時。',64,'全唐诗/poet.song.228000.json','["班朝曾共多艱日，草疏相過太息時。", "扶起斁倫千古痛，喚醒忠魄九原悲。", "我逃微責去汶遠，公坐高名出晝遲。", "危急一朝還並命，舉頭顛厦欲安之。"]'),
('7f165f19-af78-4a24-864b-1a29b78c2678','挽雷尚書喪歸二首  其二','陳杰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','初聞難及廬山老，晚見喪歸南海翁。',64,'全唐诗/poet.song.228000.json','["初聞難及廬山老，晚見喪歸南海翁。", "猶被卹章雖弗逮，竟成全節略相同。", "事惟有死仲連子，貌乃如生顔魯公。", "不盡哀榮千載下，爽鳩墟壠幾秋風。"]'),
('b7c39fe2-c2f8-46b6-ad7a-b04a02b122ee','挽龔竹卿','陳杰','宋','宋诗','song-poetry','','[]','同朝尚憶當時事，我去明朝公入臺。',64,'全唐诗/poet.song.228000.json','["同朝尚憶當時事，我去明朝公入臺。", "岳柱摧邊忽英簜，海塵揚處又蓬萊。", "夢闌杞國憂天痛，世換遼東避地回。", "似爾全歸亦安憾，貞元遺曲自生哀。"]'),
('4a947252-94dc-4ecc-93bb-eb98285eaaff','挽黄思梅','陳杰','宋','宋诗','song-poetry','','[]','夢回殘月墮觚棱，歸棹滄浪自濯纓。',64,'全唐诗/poet.song.228000.json','["夢回殘月墮觚棱，歸棹滄浪自濯纓。", "城郭重來嗟隔世，江山如畫憶初盟。", "當年阮瑀誰爭長，千載相如凜若生。", "空復滿襟餘老淚，臨風三叫爲君傾。"]'),
('66650e45-3f1a-44f9-8520-4c4fb33f2397','挽范安仲死寇','陳杰','宋','宋诗','song-poetry','','[]','十載紛紛死亂離，如君清苦獨堪悲。',64,'全唐诗/poet.song.228000.json','["十載紛紛死亂離，如君清苦獨堪悲。", "醫餘書眼猶評史，瘦盡吟肩正琢詩。", "李涉空哦綠林夜，阿先竟厄白波時。", "還勝罹難天涯者，荒冢無人酹一巵。"]'),
('46a98a1c-5fdd-452a-9e99-93042a688c7c','和林一父自溫陵寄詩由信上再忤時貴歸本貫','陳杰','宋','宋诗','song-poetry','','[]','幾度思君欲白頭，人間富貴曲如鈎。',64,'全唐诗/poet.song.228000.json','["幾度思君欲白頭，人間富貴曲如鈎。", "細論誰可一樽酒，高卧惟應百尺樓。", "工力忽從詩句見，鋒鋩漸向筆端收。", "海鷗不駭漁爭席，自此寬閒任釣遊。"]'),
('0105f6e1-83ac-47f2-9ee6-8158972c9878','和伯文送丁校尉往維揚伯文嘗教之避禍不從','陳杰','宋','宋诗','song-poetry','','[]','聞道機心不下鷗，丈夫乃不爲身謀。',64,'全唐诗/poet.song.228000.json','["聞道機心不下鷗，丈夫乃不爲身謀。", "人間信有城門犬，江滸非無夜半舟。", "塞上馬來還反掌，揚州鶴去又從頭。", "茫茫世事誰能料，未蓋棺前卒未休。"]'),
('89607fe4-cfa3-44be-ad19-a2592afca1eb','和欽弟讀予孫吳之作','陳杰','宋','宋诗','song-poetry','','[]','少狂拂劍指天山，中歲驅馳萬險艱。',64,'全唐诗/poet.song.228000.json','["少狂拂劍指天山，中歲驅馳萬險艱。", "射虎將軍頻出塞，墮鳶老子晚征蠻。", "莫誇兵法來圯上，但愛挐音出葦間。", "風后大鴻三引首，一波長乞白鷗閒。"]'),
('2bd0416c-9738-40bf-b63e-fc1be86b296c','和天民寄筆','陳杰','宋','宋诗','song-poetry','','[]','眼光如電氣如虹，少日詞場互長雄。',64,'全唐诗/poet.song.228000.json','["眼光如電氣如虹，少日詞場互長雄。", "幾度憶君風月社，十年坐我簿書叢。", "癡兒了事未易了，老兔中書今不中。", "次第買山歸隠去，不嫌苦淡幸來同。"]'),
('fd388c36-a207-43c4-8b34-6af56052525e','和姚山長一甫','陳杰','宋','宋诗','song-poetry','','[]','潭影悠悠白日閒，千年如畫此江山。',64,'全唐诗/poet.song.228000.json','["潭影悠悠白日閒，千年如畫此江山。", "高人徐孺死已朽，上疏梅仙去不還。", "底是憂堪埋地下，誰能遠不在人間。", "相逢正有論詩樂，且透西江句上關。"]'),
('ba67845e-f567-4b79-80ea-1938229895aa','和王守城山','陳杰','宋','宋诗','song-poetry','','[]','宦遊落拓成前夢，亂瘼摧藏各幸民。',64,'全唐诗/poet.song.228000.json','["宦遊落拓成前夢，亂瘼摧藏各幸民。", "歲晚來門今雨舊，人間傾蓋白頭新。", "斯文不厭重論細，吾味何關數面親。", "海內凄然成二老，玻瓈更共一江濱。"]'),
('2e0029d1-a26d-43f4-b5bc-0aa542edb5d9','和敖教諭','陳杰','宋','宋诗','song-poetry','','[]','又遲江南緝落毛，兒衣折盡海紋濤。',64,'全唐诗/poet.song.228000.json','["又遲江南緝落毛，兒衣折盡海紋濤。", "靜看機事梟羣奕，醉倚西風蠃二豪。", "黄菊籬間三引滿，夕陽樓上一凭高。", "故人經亂渾無恙，贏得新吟可擬騷。"]'),
('5dbff8bc-dd42-44cb-b9f0-40fcabfb4248','和夏南麓繡斧曾驅當道狼及答尹存吾喻仁山携詩相過值出','陳杰','宋','宋诗','song-poetry','','[]','金石論交半化狼，竹桐吾味暫棲凰。',64,'全唐诗/poet.song.228000.json','["金石論交半化狼，竹桐吾味暫棲凰。", "陶籬三畝新荒逕，孔壁千秋未壞堂。", "彩鳳題門人灑落，驪珠照夜筆淋浪。", "惜無北海盈樽酒，與賦東湖五月凉。"]'),
('bfac34c5-31d5-4b92-b9fa-e085e5968ff9','和曾平山見貽蚤自溫榮挹豔香韻','陳杰','宋','宋诗','song-poetry','','[]','夢事曾陳一瓣香，清愁兩地鬢眉蒼。',64,'全唐诗/poet.song.228000.json','["夢事曾陳一瓣香，清愁兩地鬢眉蒼。", "少陵空復詩劘壘，王湛聊須易在牀。", "古有忘言行畏壘，今無書法可柴桑。", "提君四印各安穩，正使同羣不亂行。"]'),
('c4938131-f68c-4979-bfc2-68e517583137','與節東歸和同幕送行之作','陳杰','宋','宋诗','song-poetry','','[]','來參軍事久無功，宜黜而陞愧在中。',64,'全唐诗/poet.song.228000.json','["來參軍事久無功，宜黜而陞愧在中。", "攬轡登車寧有是，過家祭竈略相同。", "送人萬里鷗波白，回首千山騎火紅。", "待得故園高卧日，諸君劍佩一時東。"]'),
('67756061-9f1f-4391-b9e4-c3ab4a9f84b8','胡端逸結庵於清江之草鞋甲歲晏言別始知猶有九袠母在敬和韻','陳杰','宋','宋诗','song-poetry','','[]','千羊濈濈擁初平，不抵封人反哺羹。',64,'全唐诗/poet.song.228000.json','["千羊濈濈擁初平，不抵封人反哺羹。", "自說老來行欲倦，忽聞親在座皆驚。", "白雲飛動能無思，寒雀啁啾故有聲。", "回首送君雙淚落，松楸霜露正關情。"]'),
('f1b3c9f2-1dca-445a-9af2-e74382e0ac68','永穆陵復土隨龍除官甚盛','陳杰','宋','宋诗','song-poetry','','[]','故王沉憤九重泉，先帝焦勞四十年。',64,'全唐诗/poet.song.228000.json','["故王沉憤九重泉，先帝焦勞四十年。", "已有含桃薦新廟，獨無麥飯灑荒阡。", "挽回天怒當初政，扶植人倫在衆賢。", "此邸最關宗社計，加恩莫放代來先。"]'),
('095dd068-7065-4702-828b-5ad0e6902b81','徐祠曾碑久仆前山長胡端逸與士友共豎之邀予賦','陳杰','宋','宋诗','song-poetry','','[]','短世人間厦幾顛，高風湖上榻猶懸。',64,'全唐诗/poet.song.228000.json','["短世人間厦幾顛，高風湖上榻猶懸。", "荒凉士豎殘碑日，遼邈官修廢祀年。", "萬古南州人似玉，千秋曾子筆如椽。", "斯文未喪神猶在，會見冠裳擁壞阡。"]'),
('d9af53fc-e674-4bee-8e10-e0680d8823cc','沙頭送客和伯文','陳杰','宋','宋诗','song-poetry','','[]','報答春光兩鬢華，荆南二月苦無花。',64,'全唐诗/poet.song.228000.json','["報答春光兩鬢華，荆南二月苦無花。", "津亭折柳清江駛，野寺觀棋白日斜。", "賦客不來樓背隰，霸功安在戟沉沙。", "歸途却惜怱怱過，一徑深紅賣酒家。"]'),
('5d2a5301-a489-4ead-9f1c-cb037b835043','食客','陳杰','宋','宋诗','song-poetry','','[]','巾履鮮明意氣洋，高門懸箔走如狂。',64,'全唐诗/poet.song.228000.json','["巾履鮮明意氣洋，高門懸箔走如狂。", "慣曾携筯從崔贍，可但驅車造辟疆。", "合五侯鯖爲一饌，染公鼎指要先嘗。", "寄聲窮巷長饑士，今代何人餉子桑。"]'),
('0ac70ddd-6694-4045-9019-d06f992fc4c2','讀邸報  其一','陳杰','宋','宋诗','song-poetry','','[]','戰骨如山血未乾，補瘡遮眼肉都剜。',64,'全唐诗/poet.song.228000.json','["戰骨如山血未乾，補瘡遮眼肉都剜。", "向來手詔真哀痛，間者人言已治安。", "夜訪宰臣憂卧榻，晝延學士論危竿。", "祖宗全盛猶如此，半壁江風面面寒。"]'),
('b64f5e40-0f57-4398-a6cd-d3a3479091b5','讀邸報  其二','陳杰','宋','宋诗','song-poetry','','[]','鑽刺逢迎狀似奴，是非羞惡一毫無。',64,'全唐诗/poet.song.228000.json','["鑽刺逢迎狀似奴，是非羞惡一毫無。", "蓋間老犬曾共嗾，韝上新鷹正待呼。", "遞趲庸回聯鼎食，長排耆俊在泥途。", "一朝政事渠何算，可惜傾人好國都。"]'),
('95bd824c-19ef-45e3-a349-5019ced86323','見邸報','陳杰','宋','宋诗','song-poetry','','[]','正徯朝陽聽鳳鳴，忽傳鵜鴂作秋聲。',64,'全唐诗/poet.song.228000.json','["正徯朝陽聽鳳鳴，忽傳鵜鴂作秋聲。", "百年事會紛成毀，一日光陰屢晦明。", "張霸安能識時務，翟公久自見交情。", "人間快意真難待，茅屋看山了此生。"]'),
('faac1c3d-54f4-401c-930e-9d0edd80ce46','扶憊效死清事久廢奏院郭公應酉以舊翹館客自杭來談江上師潰及京城非才誤著極爲不平且辱惠書明日又爲嶺海之行勉强用韻','陳杰','宋','宋诗','song-poetry','','[]','决漢排淮二十春，玉班步武乍駸駸。',64,'全唐诗/poet.song.228000.json','["决漢排淮二十春，玉班步武乍駸駸。", "緊官爲餌剛摇手，退處如飴肯動心。", "寶劍夜鳴猶斗近，貂裘晚出已寒深。", "當初若聽苞桑計，未必江濤許浸淫。"]'),
('e39a6387-b4e6-4c8d-9ca6-bae5b50513df','迓古心觀相帥長沙','陳杰','宋','宋诗','song-poetry','','[]','夾道歡呼百吏恭，微垣上相領藩雄。',64,'全唐诗/poet.song.228000.json','["夾道歡呼百吏恭，微垣上相領藩雄。", "一星文采低南斗，十乘先驅走祝融。", "孔子猶須晚封楚，周公只合早歸東。", "林深近亦聞時事，小駐油幢請下風。"]'),
('02f6c9da-5376-40df-bee8-8843c9e156cf','中齋生朝','陳杰','宋','宋诗','song-poetry','','[]','當家勳閥舊巍煌，天女裁雲爲製裳。',64,'全唐诗/poet.song.228000.json','["當家勳閥舊巍煌，天女裁雲爲製裳。", "胸飽治朝周典禮，篋餘內苑漢詞章。", "經行禾黍關河遠，指點蓬萊日月長。", "故國風流一回首，不妨鸞玉小徜徉。"]'),
('2e9cd6ae-c16b-42e4-8edf-b877bf8c35c7','山居','陳杰','宋','宋诗','song-poetry','','[]','深僻山居自在身，似僧有髮俗無塵。',64,'全唐诗/poet.song.228000.json','["深僻山居自在身，似僧有髮俗無塵。", "讀殘貝葉都忘世，看足梅花不要春。", "嘖嘖樹間黄口小，悠悠道上白頭新。", "足非何與先生事，閒倚枯藤一欠伸。"]'),
('9ae7cd2f-ea16-412a-83cb-1399f506898e','窮居','陳杰','宋','宋诗','song-poetry','','[]','窮居省事亦欣然，老屋中間易一篇。',64,'全唐诗/poet.song.228000.json','["窮居省事亦欣然，老屋中間易一篇。", "安步當車蔬當肉，筆耕爲耒紙爲田。", "幸生朱陸相鳴後，猶憶羲文未露前。", "三益不來山月白，卧聽澗水說真詮。"]'),
('1af0334c-ac61-4779-982d-d3a8b7b877e5','春風','陳杰','宋','宋诗','song-poetry','','[]','著柳成新綠，吹花作故紅。',24,'全唐诗/poet.song.228000.json','["著柳成新綠，吹花作故紅。", "衰顔與華髮，不敢怨春風。"]'),
('3af8703c-ebc3-46fc-9865-c766b6315103','浙江潮','陳杰','宋','宋诗','song-poetry','','[]','只道潮聲落，潮來復有聲。',24,'全唐诗/poet.song.228000.json','["只道潮聲落，潮來復有聲。", "何當機事息，暫遣海門平。"]'),
('f2042b2f-7b75-45bd-9db6-8993caa868eb','試問','陳杰','宋','宋诗','song-poetry','','[]','試問屋藏書，何如斛貯珠。',24,'全唐诗/poet.song.228000.json','["試問屋藏書，何如斛貯珠。", "奄奄投閣老，凜凜墜樓姝。"]'),
('a6cc5c79-846a-40b3-9108-09aa6a415e3f','萱徑携筇','陳杰','宋','宋诗','song-poetry','','[]','松下無喝道，言樹聊蠲憂。',24,'全唐诗/poet.song.228000.json','["松下無喝道，言樹聊蠲憂。", "誰知赤籐杖，獨倚萬古愁。"]'),
('8b4f6e9d-d8e5-4726-9121-1cfb64e7c995','菊畹秋香','陳杰','宋','宋诗','song-poetry','','[]','金莖餘孤標，青女滿殺氣。',24,'全唐诗/poet.song.228000.json','["金莖餘孤標，青女滿殺氣。", "隨地堪百畦，流芳亦千歲。"]'),
('8cf7ebec-1f4a-48d8-aca1-1c8aae26db04','昭君','陳杰','宋','宋诗','song-poetry','','[]','千古和戎恨，冢青今尚聞。',24,'全唐诗/poet.song.228000.json','["千古和戎恨，冢青今尚聞。", "漢朝三尺草，埋沒幾昭君。"]'),
('97978635-c078-41c6-b91a-cd725baa3752','琴窗夜雪','陳杰','宋','宋诗','song-poetry','','[]','寒更洞書幌，几上明素絃。',24,'全唐诗/poet.song.228000.json','["寒更洞書幌，几上明素絃。", "滿意宇宙曙，霏霏正漫天。"]'),
('88ad3090-649b-4591-b36e-d0713fe0e242','讀書三首  其一','陳杰','宋','宋诗','song-poetry','','[]','畫前逃弧馬，井法開賦役。',24,'全唐诗/poet.song.228000.json','["畫前逃弧馬，井法開賦役。", "聖人本仁民，何意重利跖。"]'),
('0e9de12e-f91d-4c9f-9d17-46381a699642','讀書三首  其二','陳杰','宋','宋诗','song-poetry','','[]','書初說包貢，禮有獻民虜。',24,'全唐诗/poet.song.228000.json','["書初說包貢，禮有獻民虜。", "末流尚忍聞，作俑叫千古。"]'),
('7d266cf7-4493-4d4a-859d-4b081bf12fd2','讀書三首  其三','陳杰','宋','宋诗','song-poetry','','[]','汝以爲多學，吾猶及闕文。',24,'全唐诗/poet.song.228000.json','["汝以爲多學，吾猶及闕文。", "憂端已秦誓，糟粕尚三墳。"]'),
('18b610db-c41a-489c-aee7-57ac23555818','老米暮景','陳杰','宋','宋诗','song-poetry','','[]','承平米家船，遺我獨悽然。',24,'全唐诗/poet.song.228000.json','["承平米家船，遺我獨悽然。", "此豈有愁地，不能無暝天。"]'),
('f6b64ed2-714a-46ff-a842-46cfcfd1feba','博弈觀人二首  其一','陳杰','宋','宋诗','song-poetry','','[]','西軍嚴駕後，北府捷書前。',24,'全唐诗/poet.song.228000.json','["西軍嚴駕後，北府捷書前。", "勝負豈人與，兩公天已全。"]'),
('a04d75d5-3f1b-4632-a731-fecf3f35bec2','博弈觀人二首  其二','陳杰','宋','宋诗','song-poetry','','[]','等閒移作塞，鄭重喝成盧。',24,'全唐诗/poet.song.228000.json','["等閒移作塞，鄭重喝成盧。", "莫看文懷瘦，胸吞幾寄奴。"]'),
('e012ecb1-de0f-4132-a906-e107b69b4877','題子胥廟','陳杰','宋','宋诗','song-poetry','','[]','吳以讓長國，讓亡吳亦隨。',24,'全唐诗/poet.song.228000.json','["吳以讓長國，讓亡吳亦隨。", "屬鏤天討賊，魚劍禍階誰。"]'),
('cf03b08e-dc25-407b-bf72-5d95d1e18094','題江山煙水圖','陳杰','宋','宋诗','song-poetry','','[]','疊疊雲山過盡，茫茫煙水安歸。',28,'全唐诗/poet.song.228000.json','["疊疊雲山過盡，茫茫煙水安歸。", "還君此畫三歎，閒殺江南釣磯。"]'),
('e7b9b7d4-90b6-455e-826c-7bec3928b596','述往二首  其一','陳杰','宋','宋诗','song-poetry','','[]','阿六生活大可，滕叔經紀自能。',28,'全唐诗/poet.song.228000.json','["阿六生活大可，滕叔經紀自能。", "申生死爲恭子，寧哥墓曰惠陵。"]'),
('7aca0ab8-4bb1-4fe0-973c-4b8ae810f6df','述往二首  其二','陳杰','宋','宋诗','song-poetry','','[]','貞惠文子升士，睿聖武公好賢。',28,'全唐诗/poet.song.228000.json','["貞惠文子升士，睿聖武公好賢。", "晏平仲狐裘一，齊景公駟馬千。"]'),
